import { useState, useEffect, useRef, useCallback } from 'react';
import { db } from '../../firebase';
import { collection, onSnapshot, query, where, limit, doc, getDocs } from 'firebase/firestore';
import { Task, PriorityLevel, Notification } from '../../types/appTypes';
import { PRIORITY_ORDER } from '../../constants/uiConstants';
import { taskService } from '../../services/taskService';

export const useTaskData = (
    isAuthenticated: boolean, 
    checkPermission: (perm: string) => boolean,
    onAddNotification: (n: Partial<Notification>) => void
) => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [draftTasks, setDraftTasks] = useState<Task[]>([]);
  const isFirstLoad = useRef(true);
  const checkPermissionRef = useRef(checkPermission);

  useEffect(() => { checkPermissionRef.current = checkPermission; }, [checkPermission]);

  // 1. LISTENER PRE ŽIVÉ ÚLOHY
  useEffect(() => {
    if (!isAuthenticated) return;
    const threshold = Date.now() - (3 * 24 * 60 * 60 * 1000);
    const q = query(collection(db, 'tasks'), where('createdAt', '>=', threshold), limit(300)); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));

      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added' && checkPermissionRef.current('perm_play_sound')) {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3').play().catch(() => {});
                  }
              }
          });
      }
      isFirstLoad.current = false;

      setTasks(newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) return (b.completedAt || 0) - (a.completedAt || 0);
        if (a.isManualBlocked !== b.isManualBlocked) return (a.isManualBlocked ? 1 : 0) - (b.isManualBlocked ? 1 : 0);
        const pA = PRIORITY_ORDER[a.priority || 'NORMAL'], pB = PRIORITY_ORDER[b.priority || 'NORMAL'];
        return pA !== pB ? pA - pB : (a.createdAt || 0) - (b.createdAt || 0);
      }));
    });
  }, [isAuthenticated]);

  // 2. LISTENER PRE DRAFT
  useEffect(() => {
    return onSnapshot(doc(db, 'settings', 'draft'), (s) => {
      setDraftTasks(s.exists() ? (s.data().data || []) : []);
    });
  }, []);

  // 3. WRAPPERS PRE SERVICE
  const onAddTask = useCallback(async (pn: string, wp: string | null, qty: string, unit: string, prio: PriorityLevel, isLog?: boolean, note?: string, isProd?: boolean, src?: string | null, tgt?: string | null) => {
    const user = localStorage.getItem('app_user') || 'Unknown';

    return taskService.addTask({
        partNumber: pn || '',
        text: pn || '',
        workplace: wp || '',
        quantity: qty || '0',
        quantityUnit: unit || 'pcs',
        priority: prio || 'NORMAL',
        isLogistics: !!isLog,
        isProduction: !!isProd,
        createdBy: user,
        note: note || '',
        plate: isLog ? (note || '') : '',
        sourceSectorId: src || null,
        targetSectorId: tgt || null
    });
  }, []);

  const onUpdateTask = useCallback((id: string, up: Partial<Task>) => taskService.updateTask(id, up), []);
  const onDeleteTask = useCallback((id: string) => taskService.deleteTask(id), []);

  const onToggleTask = useCallback(async (id: string, sectorId?: string) => {
      const task = tasks.find(t => t.id === id);
      if (!task) return;
      const user = localStorage.getItem('app_user') || 'Unknown';
      const updates: any = { isDone: !task.isDone, completedAt: !task.isDone ? Date.now() : null, completedBy: !task.isDone ? user : null, status: !task.isDone ? 'completed' : 'open' };
      if (!task.isDone && sectorId) updates.pickedFromSectorId = sectorId;
      return taskService.updateTask(id, updates);
  }, [tasks]);

  const onToggleMissing = useCallback(async (id: string, reason?: string) => {
      const task = tasks.find(t => t.id === id);
      if (!task) return;
      const user = localStorage.getItem('app_user') || 'Unknown';
      const isMarking = !task.isMissing;
      const updates: any = { isMissing: isMarking, missingReason: isMarking ? (reason || 'Unknown') : null, missingReportedBy: isMarking ? user : null, isInProgress: false, inProgressBy: null };
      if (isMarking && task.createdBy) {
          onAddNotification({ partNumber: task.partNumber, reason: `CHÝBA: ${reason}`, reportedBy: user, targetUser: task.createdBy });
      }
      return taskService.updateTask(id, updates);
  }, [tasks, onAddNotification]);

  const onSetInProgress = useCallback(async (id: string) => {
      const task = tasks.find(t => t.id === id);
      if (!task) return;
      const user = localStorage.getItem('app_user') || 'Unknown';
      return taskService.updateTask(id, task.isInProgress ? { isInProgress: false, inProgressBy: null } : { isInProgress: true, inProgressBy: user, startedAt: Date.now() });
  }, [tasks]);

  const onToggleBlock = useCallback(async (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    const user = localStorage.getItem('app_user') || 'Unknown';
    const isCurrentlyBlocked = !!task.isBlocked;
    return taskService.updateTask(id, {
        isBlocked: !isCurrentlyBlocked,
        blockedBy: !isCurrentlyBlocked ? user : null
    });
  }, [tasks]);

  const onExhaustSearch = useCallback(async (id: string) => {
    const user = localStorage.getItem('app_user') || 'Unknown';
    return taskService.updateTask(id, {
        searchExhausted: true,
        searchedBy: user
    });
  }, []);

  // NOVÁ FUNKCIA: onAddNote
  const onAddNote = useCallback(async (id: string, note: string) => {
    return taskService.updateTask(id, { note });
  }, []);

  const onStartAudit = useCallback((id: string) => taskService.updateTask(id, { isAuditInProgress: true, auditBy: localStorage.getItem('app_user'), isInProgress: false, inProgressBy: null }), []);
  const onFinishAudit = useCallback((id: string, res: 'found' | 'missing', note: string) => {
      const task = tasks.find(t => t.id === id);
      if (task) taskService.finishAudit(task, res, note, localStorage.getItem('app_user') || 'Unknown', onAddNotification);
  }, [tasks, onAddNotification]);

  return {
    tasks, draftTasks, onAddTask, onUpdateTask, onDeleteTask, onToggleTask, onToggleMissing, onSetInProgress, onStartAudit, onFinishAudit, onToggleBlock, onExhaustSearch, onAddNote,
    onToggleManualBlock: (id: string) => { const t = tasks.find(x => x.id === id); if(t) taskService.toggleManualBlock(t); },
    onDailyClosing: taskService.dailyClosing, onWeeklyClosing: taskService.weeklyClosing,
    fetchSanons: async () => (await getDocs(collection(db, 'sanony'))).docs.map(d => d.data())
  };
};

import React, { useMemo } from 'react';
import PartSearchScreen from './components/PartSearchScreen';
import NotificationModal from './components/modals/NotificationModal';
import { useData } from './context/DataContext';
import { SystemConfig } from './types/appTypes';

interface AppAuthenticatedProps {
  currentUser: string;
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  onLogout: () => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  onUpdateAdminKey: (oldK: string, newK: string) => Promise<void>;
  onToggleAdminLock: (val: boolean) => void;
  installPrompt: any;
  onInstallApp: () => void;
}

const AppAuthenticated: React.FC<AppAuthenticatedProps> = (props) => {
  const data = useData();

  // Získanie notifikácií pre aktuálneho používateľa
  const myNotifications = useMemo(() => {
      if (!data || !data.notifications) return [];
      return data.notifications
        .filter(n => n.targetUser === props.currentUser)
        .sort((a, b) => b.timestamp - a.timestamp); // Najnovšie prvé, ale zobrazujeme ich postupne
  }, [data?.notifications, props.currentUser]);

  // Vyberieme prvú notifikáciu v rade na zobrazenie
  const activeNotification = myNotifications.length > 0 ? myNotifications[0] : null;

  const handleConfirmNotification = () => {
      if (activeNotification && data.onClearNotification) {
          data.onClearNotification(activeNotification.id);
      }
  };

  const resolveName = (username?: string | null) => {
      if (!username) return '-';
      const u = data?.users.find(x => x.username === username);
      return (u?.nickname || username).toUpperCase();
  };

  if (!data || !data.tasks || !data.users) {
      return (
          <div className="w-full h-full flex items-center justify-center bg-gray-900">
              <p className="text-white text-xl font-bold animate-pulse">Načítavam systém...</p>
          </div>
      );
  }

  // Bezpečné funkcie (fallbacky) ak by náhodou context zlyhal
  const safeGetDocCount = (data as any).onGetDocCount || (async () => 0);
  const safePurgeOldTasks = (data as any).onPurgeOldTasks || (async () => 0);
  const safeExportTasksJSON = (data as any).onExportTasksJSON || (async () => {});
  const safeFetchArchivedTasks = (data as any).onFetchArchivedTasks || (async () => []);
  const safeVerifyAdminPassword = (data as any).onVerifyAdminPassword || ((p: string) => false);
  const safeRequestPart = (data as any).onRequestPart || (async () => false);
  const safeRequestBOM = (data as any).onRequestBOM || (async () => false);
  const safeOnDailyClosing = (data as any).onDailyClosing || (async () => ({ success: false, count: 0 }));
  const safeOnWeeklyClosing = (data as any).onWeeklyClosing || (async () => ({ success: false, count: 0, sanon: '' }));
  const safeFetchSanons = (data as any).fetchSanons || (async () => []);

  // Admin Notes functions
  const safeAdminNotes = (data as any).adminNotes || [];
  const safeAddAdminNote = (data as any).onAddAdminNote || (() => {});
  const safeDeleteAdminNote = (data as any).onDeleteAdminNote || (() => {});
  const safeClearAdminNotes = (data as any).onClearAdminNotes || (() => {});

  const partsList = data.partsMap 
    ? Object.entries(data.partsMap).map(([p, d]) => ({ id: p, value: p, description: d }))
    : [];

  return (
    <div className="w-full h-full">
        <PartSearchScreen
          {...(data as any)}
          // Action Hooks (priame prepojenie na useTaskData cez Context)
          onAddTask={data.onAddTask}
          onUpdateTask={data.onUpdateTask}
          onDeleteTask={data.onDeleteTask}
          onToggleTask={data.onToggleTask}
          onToggleBlock={data.onToggleBlock}
          onToggleManualBlock={data.onToggleManualBlock}
          onExhaustSearch={data.onExhaustSearch}
          onAddNote={data.onAddNote}
          onMarkAsIncorrect={data.onMarkAsIncorrect}
          onStartAudit={data.onStartAudit}
          onFinishAudit={data.onFinishAudit}
          onToggleMissing={data.onToggleMissing}
          onDeleteMissingItem={(id) => data.onToggleMissing(id)}

          // Maintenance & System
          onGetDocCount={safeGetDocCount}
          onPurgeOldTasks={safePurgeOldTasks}
          onExportTasksJSON={safeExportTasksJSON}
          onFetchArchivedTasks={safeFetchArchivedTasks}
          onVerifyAdminPassword={safeVerifyAdminPassword}
          onRequestPart={safeRequestPart}
          onRequestBOM={safeRequestBOM}
          onDailyClosing={safeOnDailyClosing}
          onWeeklyClosing={safeOnWeeklyClosing}
          fetchSanons={safeFetchSanons}

          // Data
          draftTasks={data.draftTasks || []}
          settings={{ draft: { data: data.draftTasks || [] } }}
          parts={partsList}

          // Props from Parent
          currentUser={props.currentUser}
          currentUserRole={props.currentUserRole}
          onLogout={props.onLogout}
          systemConfig={props.systemConfig}
          onUpdateSystemConfig={props.onUpdateSystemConfig}
          onUpdateAdminKey={props.onUpdateAdminKey}
          onToggleAdminLock={props.onToggleAdminLock}
          installPrompt={props.installPrompt}
          onInstallApp={props.onInstallApp}

          // Admin Notes
          dbLoadWarning={false}
          adminNotes={safeAdminNotes}
          onAddAdminNote={safeAddAdminNote}
          onDeleteAdminNote={safeDeleteAdminNote}
          onClearAdminNotes={safeClearAdminNotes}
        />

        {activeNotification && (
            <NotificationModal 
                notification={activeNotification}
                onConfirm={handleConfirmNotification}
                resolveName={resolveName}
            />
        )}
    </div>
  );
};

