// --- MAIN DASHBOARD COMPONENT ---
interface PartSearchScreenProps {
    tasks: Task[];
    draftTasks: Task[];
    users: any[];
    roles: Role[];
    workplaces: DBItem[];
    parts: { id: string; value: string; description?: string }[];
