    partRequests: PartRequest[];
    bomRequests: BOMRequest[];
    adminNotes: AdminNote[];
    systemConfig: SystemConfig;
    isBreakActive: boolean;

    currentUser: string;
    currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
    onLogout: () => void;

    // Task Actions
    onAddTask: (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, isLogistics?: boolean, noteOrPlate?: string, isProduction?: boolean, sourceSectorId?: string | null, targetSectorId?: string | null) => Promise<void>;
    onUpdateTask: (id: string, updates: Partial<Task>) => Promise<void>;
    onDeleteTask: (id: string) => Promise<void>;
    onToggleTask: (id: string, sectorId?: string) => Promise<void>;
    onSetInProgress: (id: string) => Promise<void>;
    onToggleBlock: (id: string) => Promise<void>;
    onToggleManualBlock: (id: string) => Promise<void>;
    onExhaustSearch: (id: string) => Promise<void>;
    onMarkAsIncorrect: (id: string) => Promise<void>;
    onAddNote: (id: string, note: string) => Promise<void>;
    onReleaseTask: (id: string) => Promise<void>;
    onStartAudit: (id: string) => Promise<void>;
    onFinishAudit: (id: string, result: 'found' | 'missing', note: string) => Promise<void>;
    onToggleMissing: (id: string, reason?: string) => Promise<void>;
    onDeleteMissingItem: (id: string) => Promise<void>;

    // User & Permission Management
    onUpdatePermission: (permissionName: string, roleName: string, hasPermission: boolean) => Promise<void>;
    onUpdateUserRole: (username: string, newRole: string) => Promise<void>;
    onAddRole: (name: string, parentId?: string, rank?: number) => Promise<void>;
    onDeleteRole: (id: string) => Promise<void>;

    // System Settings
    onUpdateSystemConfig: (config: Partial<SystemConfig>) => Promise<void>;
    onUpdateAdminKey: (oldKey: string, newKey: string) => Promise<void>;
    onToggleAdminLock: (val: boolean) => void;

    // Database Management
    onAddPart: (value: string, description?: string) => Promise<void>;
    onBatchAddParts: (vals: string[]) => Promise<void>;
    onDeletePart: (val: string) => Promise<void>;
    onDeleteAllParts: () => Promise<void>;

    onAddWorkplace: (val: string, time?: number, x?: number, y?: number) => Promise<void>;
    onUpdateWorkplace: (id: string, updates: Partial<DBItem>) => Promise<void>;
    onBatchAddWorkplaces: (vals: string[]) => Promise<void>;
    onDeleteWorkplace: (id: string) => Promise<void>;
    onDeleteAllWorkplaces: () => Promise<void>;

    onAddLogisticsOperation: (val: string, time?: number, dist?: number, x?: number, y?: number, defaultSource?: string, defaultTarget?: string) => Promise<void>;
    onUpdateLogisticsOperation: (id: string, updates: Partial<DBItem>) => Promise<void>;
    onDeleteLogisticsOperation: (id: string) => Promise<void>;
    onDeleteAllLogisticsOperations: () => Promise<void>;

    onAddMapSector: (name: string, x: number, y: number, color?: string) => Promise<void>;
    onUpdateMapSector: (id: string, updates: Partial<MapSector>) => Promise<void>;
    onDeleteMapSector: (id: string) => Promise<void>;

    onAddMapObstacle: (obs: Omit<MapObstacle, 'id'>) => Promise<void>;
    onDeleteMapObstacle: (id: string) => Promise<void>;

    onAddBOMItem: (parent: string, child: string, qty: number) => Promise<void>;
    onBatchAddBOMItems: (vals: string[]) => Promise<void>;
    onDeleteBOMItem: (parent: string, child: string) => Promise<void>;
    onDeleteAllBOMItems: () => Promise<void>;

    onAddMissingReason: (val: string) => Promise<void>;
    onDeleteMissingReason: (id: string) => Promise<void>;
    onAddBreakSchedule: (start: string, end: string) => Promise<void>;
    onDeleteBreakSchedule: (id: string) => Promise<void>;

    onAddAdminNote: (text: string, author: string) => Promise<void>;
    onDeleteAdminNote: (id: string) => Promise<void>;
    onClearAdminNotes: () => Promise<void>;

    // Maintenance & Data
    onDailyClosing: () => Promise<{ success: boolean; count: number }>;
    onWeeklyClosing: () => Promise<{ success: boolean; count: number; sanon: string }>;
    onPurgeOldTasks: () => Promise<number>;
    onExportTasksJSON: () => Promise<void>;
    onGetDocCount: () => Promise<number>;
    fetchSanons: () => Promise<any[]>;
    onRequestPart: (part: string) => Promise<boolean>;
    onRequestBOM: (parent: string) => Promise<boolean>;
    onVerifyAdminPassword: (password: string) => boolean;

    installPrompt: any;
    onInstallApp: () => void;
}

const PartSearchScreen: React.FC<PartSearchScreenProps> = (props) => {
    const { t, language, setLanguage } = useLanguage();
    const [activeTab, setActiveTab] = useState('entry');
    const [mode, setMode] = useState<'production' | 'logistics'>('production');
    const [isFullscreen, setIsFullscreen] = useState(false);

    // Form states for adding new tasks
    const [selectedPart, setSelectedPart] = useState<string | null>(null);
    const [selectedWorkplace, setSelectedWorkplace] = useState<string | null>(null);
    const [quantity, setQuantity] = useState('');
    const [quantityUnit, setQuantityUnit] = useState<'pcs' | 'boxes' | 'pallet'>('pcs');
    const [priority, setPriority] = useState<PriorityLevel>('NORMAL');
    const [logisticsRef, setLogisticsRef] = useState('');
    const [logisticsPlate, setLogisticsPlate] = useState('');
    const [logisticsOp, setLogisticsOp] = useState('');
    const [sourceSector, setSourceSector] = useState<string | null>(null);
    const [targetSector, setTargetSector] = useState<string | null>(null);

    // Fullscreen handling
    const toggleFullscreen = () => {
        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen().then(() => setIsFullscreen(true)).catch(err => console.error(err));
        } else {
            if (document.exitFullscreen) {
                document.exitFullscreen().then(() => setIsFullscreen(false)).catch(err => console.error(err));
            }
        }
    };

    // Permission check memoized for children
    const hasPermission = useCallback((permName: string) => {
        if (props.currentUserRole === 'ADMIN') return true;
        const roleObj = props.roles.find(r => r.name === props.currentUserRole);
        if (!roleObj) return false;
        return roleObj.permissions ? roleObj.permissions.includes(permName) : false;
    }, [props.roles, props.currentUserRole]);

    // Name resolution memoized for performance
    const resolveName = useCallback((username?: string | null) => {
        if (!username) return '-';
        const u = props.users.find(x => x.username === username);
        return (u?.nickname || username).toUpperCase();
    }, [props.users]);

    const resetEntry = () => {
        setSelectedPart(null);
        setSelectedWorkplace(null);
        setQuantity('');
        setQuantityUnit('pcs');
        setPriority('NORMAL');
        setLogisticsRef('');
        setLogisticsPlate('');
        setLogisticsOp('');
        setSourceSector(null);
        setTargetSector(null);
    };

    const handleAddTask = async () => {
        if (mode === 'production') {
            if (!selectedPart || !selectedWorkplace || !quantity) {
                alert(t('fill_all_fields'));
                return;
            }
            // OKAMŽITÉ PRIDANIE - Modal sa zobrazí až pri dokončení skladníkom
            await props.onAddTask(
                selectedPart,
                selectedWorkplace,
                quantity,
                quantityUnit,
                priority,
                false,
                '',
                true
            );
            resetEntry();
        } else {
            if (!logisticsRef || !logisticsOp || !quantity) {
                alert(t('fill_all_fields'));
                return;
            }
            await props.onAddTask(
                logisticsRef,
                logisticsOp,
                quantity,
                'pallet',
                priority,
                true,
                logisticsPlate,
                false,
                sourceSector,
                targetSector
            );
            resetEntry();
        }
    };

    const counts = useMemo(() => ({
        tasks: props.tasks.filter(t => !t.isDone).length,
        pendingRequests: props.partRequests.length + props.bomRequests.length
    }), [props.tasks, props.partRequests, props.bomRequests]);

    return (
        <div className="flex flex-col h-screen overflow-hidden bg-gray-900">
            {/* Top UI Bar */}
            <AppHeader 
                currentUser={props.currentUser}
                currentUserRole={props.currentUserRole}
                users={props.users}
                onLogout={props.onLogout}
                language={language as any}
                setLanguage={setLanguage as any}
                t={t}
                isFullscreen={isFullscreen}
                onToggleFullscreen={toggleFullscreen}
                installPrompt={props.installPrompt}
                onInstallApp={props.onInstallApp}
                hasPermission={hasPermission}
                resolveName={resolveName}
                isBreakActive={props.isBreakActive}
            />

            {/* Application Tab Selector */}
            <TabNavigator 
                activeTab={activeTab}
                setActiveTab={setActiveTab}
                hasPermission={hasPermission}
                t={t}
                counts={counts}
                currentUserRole={props.currentUserRole}
            />

            {/* Main Application Container */}
            <main className="flex-grow overflow-y-auto custom-scrollbar p-4 sm:p-6">
                <div className="max-w-7xl mx-auto h-full">
                    {activeTab === 'entry' && hasPermission('perm_tab_entry') && (
                        <ProductionEntry 
                            mode={mode}
                            setMode={setMode}
                            selectedPart={selectedPart}
                            setSelectedPart={setSelectedPart}
                            selectedWorkplace={selectedWorkplace}
                            setSelectedWorkplace={setSelectedWorkplace}
                            logisticsRef={logisticsRef}
                            setLogisticsRef={setLogisticsRef}
                            logisticsPlate={logisticsPlate}
                            setLogisticsPlate={setLogisticsPlate}
                            logisticsOp={logisticsOp}
                            setLogisticsOp={setLogisticsOp}
                            sourceSector={sourceSector}
                            setSourceSector={setSourceSector}
                            targetSector={targetSector}
                            setTargetSector={setTargetSector}
                            quantity={quantity}
                            setQuantity={setQuantity}
                            quantityUnit={quantityUnit}
                            setQuantityUnit={setQuantityUnit}
                            priority={priority}
                            setPriority={setPriority}
                            parts={props.parts.map(p => p.value)}
                            workplaces={props.workplaces}
                            logisticsOperationsList={props.logisticsOperations}
                            mapSectors={props.mapSectors}
                            t={t}
                            language={language}
                            hasPermission={hasPermission}
                            handleAdd={handleAddTask}
                            onRequestPart={props.onRequestPart}
                        />
                    )}

                    {activeTab === 'tasks' && hasPermission('perm_tab_tasks') && (
                        <TaskList 
                            currentUser={props.currentUserRole as any}
                            currentUserName={props.currentUser}
                            tasks={props.tasks}
                            missingReasons={props.missingReasons}
                            mapSectors={props.mapSectors}
                            onToggleTask={props.onToggleTask}
                            onEditTask={props.onUpdateTask}
                            onDeleteTask={props.onDeleteTask}
                            onToggleMissing={props.onToggleMissing}
                            onSetInProgress={props.onSetInProgress}
                            onToggleBlock={props.onToggleBlock}
                            onToggleManualBlock={props.onToggleManualBlock}
                            onExhaustSearch={props.onExhaustSearch}
                            onMarkAsIncorrect={props.onMarkAsIncorrect}
                            onAddNote={props.onAddNote}
                            onReleaseTask={props.onReleaseTask}
                            onAuditPart={props.onStartAudit}
                            onFinishAudit={props.onFinishAudit}
                            hasPermission={hasPermission}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'bom' && hasPermission('perm_tab_bom') && (
                        <BOMScreen 
                            parts={props.parts}
                            workplaces={props.workplaces}
                            bomMap={props.bomMap}
                            onAddTask={props.onAddTask}
                            onRequestBOM={props.onRequestBOM}
                            t={t}
                            language={language}
                        />
                    )}

                    {activeTab === 'catalog' && hasPermission('perm_tab_catalog') && (
                        <PartCatalogTab 
                            parts={props.parts}
                            onSelectPart={(p) => { setSelectedPart(p.value); setActiveTab('entry'); }}
                        />
                    )}

                    {activeTab === 'missing' && hasPermission('perm_tab_missing') && (
                        <MissingItemsTab 
                            tasks={props.tasks}
                            onDeleteMissingItem={props.onDeleteMissingItem}
                            hasPermission={hasPermission}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'inventory' && hasPermission('perm_tab_inventory') && (
                        <InventoryTab 
                            currentUser={props.currentUser}
                            tasks={props.tasks}
                            onAddTask={props.onAddTask}
                            onUpdateTask={props.onUpdateTask}
                            onToggleTask={props.onToggleTask}
                            onDeleteTask={props.onDeleteTask}
                            hasPermission={hasPermission}
                            parts={props.parts.map(p => p.value)}
                            onRequestPart={props.onRequestPart}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'logistics' && hasPermission('perm_tab_logistics_center') && (
                        <LogisticsCenterTab 
                            tasks={props.tasks} 
                            draftTasks={props.draftTasks}
                            users={props.users}
                            fetchSanons={props.fetchSanons}
                            onDeleteTask={props.onDeleteTask} 
                            hasPermission={hasPermission} 
                            resolveName={resolveName} 
                        />
                    )}

                    {activeTab === 'map' && hasPermission('perm_tab_map') && (
                        <MapVisualizationTab 
                            tasks={props.tasks}
                            draftTasks={props.draftTasks}
                            fetchSanons={props.fetchSanons}
                            users={props.users}
                            mapSectors={props.mapSectors}
                            workplaces={props.workplaces}
                            logisticsOperations={props.logisticsOperations}
                            mapObstacles={props.mapObstacles}
                            systemConfig={props.systemConfig}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'logs' && hasPermission('perm_tab_logs') && (
                        <TransactionLogTab 
                            tasks={props.tasks}
                            draftTasks={props.draftTasks}
                            fetchSanons={props.fetchSanons}
                            users={props.users}
                            mapSectors={props.mapSectors}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'erp' && hasPermission('perm_tab_erp') && (
                        <ERPBlockageTab 
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            parts={props.parts}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'analytics' && hasPermission('perm_tab_analytics') && (
                        <AnalyticsTab 
                            systemConfig={props.systemConfig}
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            hasPermission={hasPermission}
                        />
                    )}

                    {activeTab === 'settings' && hasPermission('perm_tab_settings') && (
                        <SettingsTab 
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            installPrompt={props.installPrompt}
                            onInstallApp={props.onInstallApp}
                            systemConfig={props.systemConfig}
                            onUpdateSystemConfig={props.onUpdateSystemConfig}
                            onUpdateAdminKey={props.onUpdateAdminKey}
                            onToggleAdminLock={props.onToggleAdminLock}
                        />
                    )}

                    {activeTab === 'permissions' && hasPermission('perm_tab_permissions') && (
                        <PermissionsTab 
                            roles={props.roles}
                            onAddRole={props.onAddRole}
                            onDeleteRole={props.onDeleteRole}
                            onUpdatePermission={props.onUpdatePermission}
                            onVerifyAdminPassword={props.onVerifyAdminPassword}
                        />
                    )}
                </div>
            </main>
        </div>
    );
};

export default PartSearchScreen;

import React, { useState } from 'react';
import { Role } from '../../App'; 
import { useLanguage } from '../LanguageContext';

interface PermissionsTabProps {
    roles: Role[];
    onAddRole: (name: string, parentId?: string, rank?: number) => void;
    onDeleteRole: (id: string) => void;
    onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
    onVerifyAdminPassword: (password: string) => boolean;
}

const PermissionsTab: React.FC<PermissionsTabProps> = ({ roles, onAddRole, onDeleteRole, onUpdatePermission, onVerifyAdminPassword }) => {
    const { t, language } = useLanguage();
    const [newRoleName, setNewRoleName] = useState('');
    const [selectedParentId, setSelectedParentId] = useState('');

    const permGroups = [
      {
          name: 'perm_group_tabs',
          perms: [
              'perm_tab_entry', 
              'perm_tab_tasks', 
              'perm_tab_bom', 
              'perm_tab_catalog',
              'perm_tab_missing', 
              'perm_tab_inventory', 
              'perm_tab_logistics_center', 
              'perm_tab_map',
              'perm_tab_logs',
              'perm_tab_erp',
              'perm_tab_analytics', 
              'perm_tab_settings', 
              'perm_tab_permissions', 
              'perm_logistics_mode'
          ] 
      },
      {
          name: 'perm_group_actions',
          perms: ['perm_btn_finish', 'perm_btn_edit', 'perm_btn_delete', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_copy', 'perm_btn_return', 'perm_btn_note', 'perm_btn_incorrect', 'perm_btn_lock', 'perm_btn_block_new', 'perm_btn_audit', 'perm_view_fullscreen', 'perm_play_sound', 'perm_push_notification', 'perm_view_passwords']
      },
      {
          name: 'perm_group_settings',
          perms: ['perm_view_setup', 'perm_settings_users', 'perm_settings_parts', 'perm_settings_wp', 'perm_settings_bom', 'perm_settings_system', 'perm_settings_maint']
      },
      {
          name: 'perm_group_mgmt',
          perms: ['perm_manage_users', 'perm_delete_users', 'perm_manage_db', 'perm_manage_logistics_ops', 'perm_manage_bom', 'perm_archive', 'perm_manage_breaks', 'perm_manage_roles'] 
      }
    ];

    const hasPermission = (role: Role, permName: string) => {
        return role.permissions ? role.permissions.includes(permName) : false;
    };

    const handleCreateRole = () => {
        if (!newRoleName.trim()) return;
        const parent = roles.find(r => r.id === selectedParentId);
        const rank = parent ? (parent.rank || 0) + 1 : 5;
        onAddRole(newRoleName, selectedParentId || undefined, rank);
        setNewRoleName('');
        setSelectedParentId('');
    };

    const canDelete = (role: Role) => !role.isSystem && role.name.toUpperCase() !== 'ADMIN';

    const handleDeleteClick = (role: Role) => {
        if (!canDelete(role)) return;
        if (window.confirm(language === 'sk' ? `Naozaj chcete vymazať rolu ${role.name}?` : `Delete role ${role.name}?`)) {
            onDeleteRole(role.id);
        }
    };

    return (
        <div className="max-w-6xl mx-auto space-y-10 pb-12 animate-fade-in relative">
            <h1 className="text-center text-3xl font-extrabold text-orange-400 mb-8 uppercase tracking-widest">{t('sect_roles')}</h1>

            {/* Role Management Header */}
            <div className="bg-gray-800 p-6 rounded-2xl border border-gray-700 shadow-xl mb-10">
                <h3 className="text-xs font-black text-gray-500 uppercase tracking-[0.2em] mb-4">Vytvoriť novú rolu</h3>
                <div className="flex flex-col md:flex-row gap-4">
                    <input 
                        type="text" 
                        value={newRoleName}
                        onChange={(e) => setNewRoleName(e.target.value)}
                        placeholder={t('role_name_place')}
                        className="flex-1 bg-gray-900 border border-gray-700 text-white px-5 py-3 rounded-xl focus:border-orange-500 outline-none font-bold uppercase placeholder-gray-600"
                    />
                    <select 
                        value={selectedParentId}
                        onChange={(e) => setSelectedParentId(e.target.value)}
                        className="md:w-64 bg-gray-900 border border-gray-700 text-white px-5 py-3 rounded-xl focus:border-orange-500 outline-none font-bold uppercase"
                    >
                        <option value="">{language === 'sk' ? 'ŽIADNY NADRIADENÝ' : 'NO PARENT ROLE'}</option>
                        {roles.map(r => (
                            <option key={r.id} value={r.id}>{r.name} (LVL {r.rank || 0})</option>
                        ))}
                    </select>
                    <button 
                        onClick={handleCreateRole}
                        className="bg-orange-600 hover:bg-orange-500 text-white font-black px-10 py-3 rounded-xl transition-all shadow-lg active:scale-95 uppercase tracking-widest text-sm"
                    >
                        {t('role_add_btn')}
                    </button>
                </div>
            </div>

            {permGroups.map(group => (
                 <div key={group.name} className="bg-gray-900 rounded-2xl p-8 border border-gray-700">
                     <h3 className="text-xl font-black text-gray-300 mb-6 border-b border-gray-700 pb-3 uppercase">{t(group.name as any)}</h3>
                     <div className="overflow-x-auto custom-scrollbar"> 
                         <table className="min-w-[700px] w-full text-left text-base">
                             <thead>
                                 <tr>
                                     <th className="py-4 px-5 text-gray-400 font-bold uppercase text-xs tracking-widest">{t('permission_label')}</th> 
                                     {roles.map(role => (
                                         <th key={role.id} className="py-4 px-5 text-white font-black text-center min-w-[120px]">
                                             <div className="flex flex-col items-center gap-1">
                                                 <span className="text-sm leading-tight">{role.name}</span>
                                                 <div className="flex items-center gap-2">
                                                     <span className="text-[9px] text-orange-500/70 uppercase font-black bg-orange-500/10 px-1.5 rounded border border-orange-500/20">LVL {role.rank || 0}</span>
                                                     <button 
                                                        onClick={() => handleDeleteClick(role)}
                                                        disabled={!canDelete(role)}
                                                        className={`transition-colors ${canDelete(role) ? 'text-gray-600 hover:text-red-500' : 'text-gray-800 cursor-not-allowed opacity-30'}`}
                                                     >
                                                        <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                                                     </button>
                                                 </div>
                                             </div>
                                         </th>
                                     ))}
                                 </tr>
                             </thead>
                             <tbody className="divide-y divide-gray-800">
                                 {group.perms.map(perm => (
                                     <tr key={perm} className="hover:bg-gray-800/50 transition-colors">
                                         <td className="py-5 px-5 text-gray-300 font-medium">{t(perm as any)}</td>
                                         {roles.map(role => (
                                             <td key={`${role.id}-${perm}`} className="py-5 px-5 text-center">
                                                 <input 
                                                    type="checkbox" 
                                                    checked={hasPermission(role, perm)} 
                                                    onChange={(e) => onUpdatePermission && onUpdatePermission(perm, role.name, e.target.checked)} 
                                                    className="w-6 h-6 text-orange-500 bg-gray-700 border-gray-600 rounded cursor-pointer transition-transform active:scale-110" 
                                                 />
                                             </td>
                                         ))}
                                     </tr>
                                 ))}
                             </tbody>
                         </table>
                     </div>
                 </div>
             ))}
        </div>
    );
};

export default PermissionsTab;

import React, { useState, useEffect, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { db } from '../../firebase';
import { doc, onSnapshot, updateDoc, setDoc, getDoc } from 'firebase/firestore';
import { ERPBlockage, DBItem } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';
import { useData } from '../../context/DataContext';
import PartNumberInput from '../PartNumberInput';

declare var XLSX: any;

interface ERPBlockageTabProps {
    currentUser: string;
    currentUserRole: string;
    parts: DBItem[];
    resolveName: (username?: string | null) => string;
}

const Icons = {
    Warning: () => <svg className="w-8 h-8 text-orange-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>,
    Check: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" /></svg>,
    Trash: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
    Excel: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
};

const ERPBlockageTab: React.FC<ERPBlockageTabProps> = ({ currentUser, currentUserRole, parts, resolveName }) => {
    const { t, language } = useLanguage();
    const { onAddNotification } = useData();

    // State
    const [blockages, setBlockages] = useState<ERPBlockage[]>([]);
    const [loading, setLoading] = useState(true);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [timer, setTimer] = useState(Date.now());

    // Form State
    const [partNumber, setPartNumber] = useState('');
    const [quantity, setQuantity] = useState('');
    const [userNote, setUserNote] = useState('');

    // Modal State
    const [finishModal, setFinishModal] = useState<{ isOpen: boolean; id: string | null; note: string }>({ isOpen: false, id: null, note: '' });
    const [confirmModal, setConfirmModal] = useState<{ isOpen: boolean; title: string; desc: string; onConfirm: () => void; type: 'danger' | 'warning' }>({ isOpen: false, title: '', desc: '', onConfirm: () => {}, type: 'danger' });

    // REALTIME SYNC (Single Doc pattern)
    useEffect(() => {
        const unsub = onSnapshot(doc(db, 'settings', 'erp_blockages'), (s) => {
            if (s.exists()) setBlockages(s.data().items || []);
            else setBlockages([]);
            setLoading(false);
        });
        const interval = setInterval(() => setTimer(Date.now()), 60000);
        return () => { unsub(); clearInterval(interval); };
    }, []);

    const sortedList = useMemo(() => {
        const score = { waiting: 0, resolving: 1, ready: 2 };
        return [...blockages].sort((a, b) => {
            if (score[a.status] !== score[b.status]) return score[a.status] - score[b.status];
            return b.timestamp - a.timestamp;
        });
    }, [blockages]);

    // HANDLERS
    const handleAdd = async () => {
        if (!partNumber || !quantity || !userNote) {
            alert(t('fill_all_fields'));
            return;
        }
        setIsSubmitting(true);
        try {
            const newItem: ERPBlockage = {
                id: crypto.randomUUID(),
                partNumber,
                quantity,
                userNote,
                status: 'waiting',
                createdBy: currentUser,
                timestamp: Date.now()
            };
            const ref = doc(db, 'settings', 'erp_blockages');
            await setDoc(ref, { items: [newItem, ...blockages] }, { merge: true });

            // Vyčistenie formulára
            setPartNumber(''); setQuantity(''); setUserNote('');
        } catch (e) { console.error(e); }
        finally { setIsSubmitting(false); }
    };

    const updateStatus = async (id: string, updates: Partial<ERPBlockage>) => {
        try {
            const newList = blockages.map(item => item.id === id ? { ...item, ...updates } : item);
            await updateDoc(doc(db, 'settings', 'erp_blockages'), { items: newList });
        } catch (e) { console.error(e); }
    };

    const handleResolve = (id: string) => {
        updateStatus(id, { status: 'resolving', resolvedBy: currentUser });
    };

    const openFinishModal = (id: string) => {
        setFinishModal({ isOpen: true, id, note: '' });
    };

    const handleConfirmFinish = async () => {
        if (!finishModal.id || !finishModal.note.trim()) return;
        const item = blockages.find(b => b.id === finishModal.id);
        if (!item) return;

        const updates: Partial<ERPBlockage> = {
            status: 'ready',
            adminNote: finishModal.note,
            resolvedAt: Date.now(),
            resolvedBy: currentUser
        };

        await updateStatus(finishModal.id, updates);

        // Notifikácia operátorovi
        onAddNotification({
            partNumber: item.partNumber,
            reason: finishModal.note,
            reportedBy: currentUser,
            targetUser: item.createdBy,
            timestamp: Date.now()
        });

        setFinishModal({ isOpen: false, id: null, note: '' });
    };

    const handleDelete = (id: string) => {
        setConfirmModal({
            isOpen: true,
            title: t('erp_delete_confirm'),
            desc: language === 'sk' ? "Táto akcia je nevratná a záznam bude odstránený zo zoznamu." : "This action is irreversible.",
            type: 'danger',
            onConfirm: async () => {
                const newList = blockages.filter(b => b.id !== id);
                await updateDoc(doc(db, 'settings', 'erp_blockages'), { items: newList });
                setConfirmModal(p => ({ ...p, isOpen: false }));
            }
        });
    };

    const handleClearReady = () => {
        setConfirmModal({
            isOpen: true,
            title: t('erp_clear_confirm'),
            desc: language === 'sk' ? "Všetky záznamy v stave OPRAVENÉ budú natrvalo vymazané." : "All fixed records will be deleted.",
            type: 'danger',
            onConfirm: async () => {
                const newList = blockages.filter(b => b.status !== 'ready');
                await updateDoc(doc(db, 'settings', 'erp_blockages'), { items: newList });
                setConfirmModal(p => ({ ...p, isOpen: false }));
            }
        });
    };

    const handleExport = () => {
        if (typeof XLSX === 'undefined') return;
        const data = sortedList.map(b => ({
            "Dátum": new Date(b.timestamp).toLocaleDateString(),
            "Čas": new Date(b.timestamp).toLocaleTimeString(),
            "Diel": b.partNumber,
            "Množstvo": b.quantity,
            "Nahlásil": resolveName(b.createdBy),
            "Dôvod (User)": b.userNote,
            "Stav": b.status.toUpperCase(),
            "Riešiteľ": resolveName(b.resolvedBy),
            "Spätná väzba (Admin)": b.adminNote || ""
        }));
        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Chyby_Odvodu");
        XLSX.writeFile(wb, `Chyby_Odvodu_${new Date().toISOString().split('T')[0]}.xlsx`);
    };

    const getAgeingText = (ts: number) => {
        const diff = Math.floor((timer - ts) / 60000);
        return diff < 1 ? t('erp_ageing_now') : t('erp_ageing_min', { n: diff });
    };

    const isAdmin = currentUserRole === 'ADMIN';

    return (
        <div className="max-w-7xl mx-auto space-y-8 pb-24 animate-fade-in text-slate-200">

            {/* HEADER SECTION */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div className="flex items-center gap-5">
                    <div className="p-4 bg-orange-500/20 rounded-2xl border border-orange-500/30">
                        <Icons.Warning />
                    </div>
                    <div>
                        <h2 className="text-3xl font-black text-white uppercase tracking-tighter leading-none">{t('erp_report_title')}</h2>
                        <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-2">{t('erp_report_subtitle')}</p>
                    </div>
                </div>
                <div className="flex gap-3 w-full md:w-auto">
                    <button onClick={handleExport} className="flex-1 md:flex-none h-12 px-6 bg-teal-600/10 hover:bg-teal-600/20 text-teal-500 border border-teal-500/30 rounded-xl font-black uppercase text-[10px] tracking-widest transition-all flex items-center justify-center gap-2">
                        <Icons.Excel /> {t('erp_btn_excel')}
                    </button>
                    {isAdmin && (
                        <button onClick={handleClearReady} className="flex-1 md:flex-none h-12 px-6 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-500/30 rounded-xl font-black uppercase text-[10px] tracking-widest transition-all flex items-center justify-center gap-2">
                            <Icons.Trash /> {t('erp_btn_clear')}
                        </button>
                    )}
                </div>
            </div>

            {/* INPUT FORM SECTION */}
            <div className="bg-slate-900/60 border-2 border-slate-800 rounded-[2rem] p-8 shadow-2xl backdrop-blur-md relative overflow-hidden group">
                <div className="absolute top-0 right-0 w-64 h-64 bg-orange-500/5 rounded-full -mr-32 -mt-32 blur-[100px] pointer-events-none"></div>
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-end relative z-10">
                    <div className="space-y-4">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] ml-1">{t('part_number')}</label>
                            <PartNumberInput 
                                parts={parts.map(p => p.value)} 
                                value={partNumber} 
                                onPartSelect={(v) => setPartNumber(v || '')}
                                onInputChange={(v) => setPartNumber(v.toUpperCase())}
                                placeholder="33..."
                            />
                        </div>
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] ml-1">{t('quantity')}</label>
                            <input 
                                type="number" 
                                value={quantity} 
                                onChange={e => setQuantity(e.target.value)}
                                className="w-full h-14 bg-slate-950 border-2 border-slate-800 rounded-2xl px-6 text-white font-mono text-2xl focus:border-teal-500 outline-none transition-all" 
                                placeholder="0"
                            />
                        </div>
                    </div>
                    <div className="lg:col-span-2 space-y-4">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] ml-1">POZNÁMKA / DÔVOD CHYBY</label>
                            <textarea 
                                value={userNote}
                                onChange={e => setUserNote(e.target.value)}
                                className="w-full h-[132px] bg-slate-950 border-2 border-slate-800 rounded-2xl px-6 py-4 text-white focus:border-teal-500 outline-none transition-all resize-none font-medium placeholder:text-slate-700"
                                placeholder={t('erp_placeholder_note')}
                            />
                        </div>
                    </div>
                    <div className="lg:col-span-3 pt-2">
                        <button 
                            onClick={handleAdd}
                            disabled={isSubmitting}
                            className="w-full h-16 bg-teal-600 hover:bg-teal-500 disabled:bg-slate-800 disabled:text-slate-600 text-white rounded-2xl font-black uppercase tracking-[0.2em] shadow-xl shadow-teal-900/20 transition-all active:scale-[0.98] border-b-4 border-teal-800 hover:border-teal-700 text-lg flex items-center justify-center gap-3"
                        >
                            {isSubmitting ? '...' : t('erp_submit_btn')}
                        </button>
                    </div>
                </div>
            </div>

            {/* LIST SECTION */}
            <div className="space-y-4">
                {loading ? (
                    <div className="h-64 flex items-center justify-center"><div className="w-12 h-12 border-4 border-teal-500 border-t-transparent rounded-full animate-spin"></div></div>
                ) : sortedList.length > 0 ? (
                    sortedList.map((item) => {
                        const isWaiting = item.status === 'waiting';
                        const isResolving = item.status === 'resolving';
                        const isReady = item.status === 'ready';

                        const statusColors = isWaiting 
                            ? "border-red-500/20 bg-slate-900/40" 
                            : isResolving 
                                ? "border-orange-500/30 bg-slate-900/80 shadow-[0_0_40px_rgba(245,158,11,0.1)]" 
                                : "opacity-50 grayscale-[0.5] border-teal-500/10 bg-slate-900/20";

                        const badgeColors = isWaiting 
                            ? "bg-red-500/10 text-red-500 border-red-500/30 animate-pulse" 
                            : isResolving 
                                ? "bg-orange-500 text-white border-orange-400" 
                                : "bg-teal-500/10 text-teal-500 border-teal-500/30";

                        return (
                            <div key={item.id} className={`group relative flex flex-col md:flex-row items-stretch rounded-[2rem] border-2 transition-all duration-300 p-6 gap-6 ${statusColors}`}>
                                {/* Left Side: Part Info */}
                                <div className="md:w-64 flex-shrink-0 flex flex-col justify-center">
                                    <h4 className="text-2xl font-black text-white font-mono tracking-tight break-all leading-tight">{item.partNumber}</h4>
                                    <div className="mt-3 bg-slate-950 rounded-xl p-3 border border-slate-800 flex items-center justify-between">
                                        <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Množstvo:</span>
                                        <span className="text-xl font-black text-teal-400 font-mono">{item.quantity}</span>
                                    </div>
                                </div>

                                {/* Middle: Content */}
                                <div className="flex-grow flex flex-col justify-center space-y-4">
                                    <div className="flex flex-wrap items-center gap-3">
                                        <span className={`px-4 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest border-2 ${badgeColors}`}>
                                            {t(`erp_status_${item.status}` as any)}
                                        </span>
                                        <span className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Nahlásil: <span className="text-slate-300 ml-1">{resolveName(item.createdBy)}</span></span>
                                        <span className="bg-rose-500/10 text-rose-500 border border-rose-500/20 px-3 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest">
                                            {getAgeingText(item.timestamp)}
                                        </span>
                                    </div>
                                    <div className="bg-slate-950/40 p-4 rounded-2xl border-l-4 border-slate-700 italic text-slate-300 text-sm leading-relaxed">
                                        "{item.userNote}"
                                    </div>
                                    {item.adminNote && (
                                        <div className="bg-teal-500/5 p-4 rounded-2xl border border-teal-500/20 text-teal-400 text-sm font-bold flex gap-3 items-start animate-fade-in">
                                            <span className="mt-0.5 text-lg">✅</span>
                                            <p>{item.adminNote}</p>
                                        </div>
                                    )}
                                </div>

                                {/* Right Side: Actions */}
                                <div className="md:w-48 flex-shrink-0 flex md:flex-col items-center justify-center gap-3">
                                    {isAdmin && (
                                        <>
                                            {!isReady && (
                                                <>
                                                    {isWaiting && (
                                                        <button 
                                                            onClick={() => handleResolve(item.id)}
                                                            className="w-full h-14 bg-orange-600 hover:bg-orange-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-orange-800 shadow-lg transition-all active:scale-95"
                                                        >
                                                            {t('erp_btn_resolve')}
                                                        </button>
                                                    )}
                                                    {isResolving && (
                                                        <button 
                                                            onClick={() => openFinishModal(item.id)}
                                                            className="w-full h-14 bg-teal-600 hover:bg-teal-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-teal-800 shadow-lg transition-all active:scale-95"
                                                        >
                                                            {t('erp_btn_finish')}
                                                        </button>
                                                    )}
                                                </>
                                            )}
                                            <button 
                                                onClick={() => handleDelete(item.id)}
                                                className="w-14 h-14 flex items-center justify-center rounded-2xl bg-slate-950 border-2 border-slate-800 text-slate-600 hover:text-red-500 hover:border-red-500/40 transition-all active:scale-95 shadow-lg"
                                            >
                                                <Icons.Trash />
                                            </button>
                                        </>
                                    )}
                                </div>
                            </div>
                        );
                    })
                ) : (
                    <div className="py-32 text-center bg-slate-900/20 rounded-[3rem] border-2 border-dashed border-slate-800">
                        <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-6 opacity-20"><Icons.Check /></div>
                        <p className="text-slate-600 font-black uppercase tracking-[0.3em] text-lg">{t('erp_empty_list')}</p>
                    </div>
                )}
            </div>

            {/* MODALS */}
            {finishModal.isOpen && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in">
                    <div className="bg-slate-900 border-2 border-teal-500/50 rounded-[2.5rem] shadow-[0_0_100px_rgba(20,184,166,0.2)] w-full max-w-lg p-10 relative overflow-hidden" onClick={e => e.stopPropagation()}>
                        <div className="absolute top-0 right-0 w-32 h-32 bg-teal-500/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
                        <h3 className="text-3xl font-black text-white uppercase tracking-tighter mb-4">{t('erp_finish_modal_title')}</h3>
                        <p className="text-slate-500 text-sm font-bold uppercase tracking-widest mb-8 leading-relaxed">{t('erp_finish_modal_desc')}</p>

                        <textarea 
                            value={finishModal.note}
                            onChange={e => setFinishModal(p => ({ ...p, note: e.target.value }))}
                            className="w-full h-40 bg-slate-950 border-2 border-slate-800 rounded-2xl px-6 py-4 text-white focus:border-teal-500 outline-none transition-all resize-none mb-8 font-medium shadow-inner"
                            placeholder="NAPR. CHYBA OPRAVENÁ V EFACS..."
                            autoFocus
                        />

                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => setFinishModal({ isOpen: false, id: null, note: '' })} className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all">ZRUŠIŤ</button>
                            <button onClick={handleConfirmFinish} className="h-14 bg-teal-600 hover:bg-teal-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-teal-800 shadow-xl transition-all active:scale-95">POTVRDIŤ</button>
                        </div>
                    </div>
                </div>,
                document.body
            )}

            {confirmModal.isOpen && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in">
                    <div className="bg-slate-900 border-2 border-slate-800 rounded-[2.5rem] shadow-2xl w-full max-w-md p-10 text-center" onClick={e => e.stopPropagation()}>
                        <div className={`w-20 h-20 rounded-3xl mx-auto mb-8 flex items-center justify-center border-2 ${confirmModal.type === 'danger' ? 'bg-red-500/10 border-red-500/30 text-red-500' : 'bg-orange-500/10 border-orange-500/30 text-orange-500'}`}>
                            <Icons.Warning />
                        </div>
                        <h3 className="text-2xl font-black text-white uppercase tracking-tighter mb-4">{confirmModal.title}</h3>
                        <p className="text-slate-500 text-sm font-bold uppercase tracking-widest mb-10 leading-relaxed">{confirmModal.desc}</p>

                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => setConfirmModal(p => ({ ...p, isOpen: false }))} className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all">ZRUŠIŤ</button>
                            <button onClick={confirmModal.onConfirm} className={`h-14 rounded-2xl font-black uppercase text-xs tracking-widest text-white shadow-xl transition-all active:scale-95 border-b-4 ${confirmModal.type === 'danger' ? 'bg-red-600 border-red-800 hover:bg-red-500' : 'bg-orange-600 border-orange-800 hover:bg-orange-500'}`}>POTVRDIŤ</button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default ERPBlockageTab;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { useLanguage } from '../LanguageContext';
import PartNumberInput from '../PartNumberInput';
import { Task, PriorityLevel } from '../../types/appTypes';

interface ScannedItem {
    id: string;
    location: string;
    partNumber: string;
    batch: string;
    quantity: string;
    timestamp: number;
    worker: string;
}

interface InventoryTabProps {
    currentUser: string;
    tasks: Task[];
    onAddTask: (pn: string, wp: string | null, qty: string | null, unit: string | null, prio: PriorityLevel, isLogistics?: boolean) => void;
    onUpdateTask: (id: string, updates: Partial<Task>) => void;
    onToggleTask: (id: string) => void;
    onDeleteTask: (id: string) => void;
    hasPermission: (perm: string) => boolean;
    parts: string[];
    onRequestPart: (part: string) => Promise<boolean>;
    resolveName: (username?: string | null) => string;
}

declare var XLSX: any;

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
);

const InventoryTab: React.FC<InventoryTabProps> = ({ currentUser, tasks, onAddTask, onUpdateTask, onDeleteTask, parts, onRequestPart, resolveName }) => {
    const { t, language } = useLanguage();

    const locationRef = useRef<HTMLInputElement>(null);
    const partRef = useRef<HTMLInputElement>(null);
    const batchRef = useRef<HTMLInputElement>(null);
    const quantityRef = useRef<HTMLInputElement>(null);

    const [location, setLocation] = useState('');
    const [partNumber, setPartNumber] = useState('');
    const [batch, setBatch] = useState('');
    const [isBatchMissing, setIsBatchMissing] = useState(false);
    const [quantity, setQuantity] = useState('');
    const [lastSaved, setLastSaved] = useState<number | null>(null);
    const [scannedItems, setScannedItems] = useState<ScannedItem[]>([]);

    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: React.ReactNode;
        onConfirm: () => void;
        type: 'danger' | 'warning';
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => {},
        type: 'danger'
    });

    const activeInventoryTask = useMemo(() => {
        return (tasks || []).find(t => 
            t.partNumber === "Počítanie zásob" && 
            !t.isDone && 
            t.inProgressBy === currentUser
        );
    }, [tasks, currentUser]);

    useEffect(() => {
        const saved = localStorage.getItem('inventory_scans');
        if (saved) {
            try {
                const parsed = JSON.parse(saved);
                if (parsed && Array.isArray(parsed)) {
                    setScannedItems(parsed);
                    if (parsed.length > 0) setLastSaved(parsed[0].timestamp);
                }
            } catch (e) {
                console.error("Failed to parse inventory scans", e);
            }
        }
    }, []);

    useEffect(() => {
        if (scannedItems && scannedItems.length > 0) {
            localStorage.setItem('inventory_scans', JSON.stringify(scannedItems));
            setLastSaved(Date.now());
        }
    }, [scannedItems]);

    const handleStartInventory = () => {
        onAddTask("Počítanie zásob", "Inventúra", "0", "pallet", "NORMAL", true);
    };

    const handleAddItem = () => {
        const isLocEmpty = !location.trim();
        const isPartEmpty = !partNumber.trim();
        const isQtyEmpty = !quantity.trim();
        const isBatchRequiredAndEmpty = !isBatchMissing && !batch.trim();

        if (isLocEmpty || isPartEmpty || isQtyEmpty || isBatchRequiredAndEmpty) {
            const missingFields = [];
            if (isLocEmpty) missingFields.push(t('inv_th_loc'));
            if (isPartEmpty) missingFields.push(t('inv_th_part'));
            if (isBatchRequiredAndEmpty) missingFields.push(t('inv_th_batch'));
            if (isQtyEmpty) missingFields.push(t('inv_th_qty'));

            const errorMsg = language === 'sk' 
                ? `Prosím, vyplňte povinné polia: ${missingFields.join(', ')}.` 
                : `Please fill required fields: ${missingFields.join(', ')}.`;

            alert(errorMsg);
            return;
        }

        const newItem: ScannedItem = {
            id: crypto.randomUUID(),
            location,
            partNumber,
            batch: isBatchMissing ? `[${t('inv_missing_label').toUpperCase()}]` : batch,
            quantity,
            timestamp: Date.now(),
            worker: currentUser
        };
        setScannedItems([newItem, ...scannedItems]);

        setLocation(''); 
        setPartNumber(''); 
        setBatch(''); 
        setIsBatchMissing(false);
        setQuantity('');
        setTimeout(() => locationRef.current?.focus(), 10);
    };

    const handleDeleteItem = (id: string) => {
        setConfirmModal({
            isOpen: true,
            title: t('confirm_delete_title'),
            message: t('confirm_delete_msg'),
            type: 'danger',
            onConfirm: () => {
                const updated = scannedItems.filter(item => item.id !== id);
                setScannedItems(updated);
                if (updated.length === 0) {
                    localStorage.removeItem('inventory_scans');
                }
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleClearAll = () => {
        setConfirmModal({
            isOpen: true,
            title: t('confirm_clear_all'),
            message: t('confirm_clear_all_msg'),
            type: 'danger',
            onConfirm: () => {
                setScannedItems([]);
                localStorage.removeItem('inventory_scans');
                setLastSaved(null);
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleCancelInventory = () => {
        setConfirmModal({
            isOpen: true,
            title: language === 'sk' ? "Zrušiť reláciu inventúry?" : "Cancel inventory session?",
            message: (
                <div className="space-y-4">
                    <p className="font-bold text-red-500">
                        {language === 'sk' 
                            ? "Pozor! Táto akcia vymaže všetky naskenované dáta a ukončí inventúru bez uloženia do systému." 
                            : "Warning! This action will delete all scanned data and end the inventory without saving to the system."}
                    </p>
                    <div className="bg-gray-700/50 p-4 rounded-lg border border-gray-600 text-sm">
                        <p className="text-gray-300">
                            {language === 'sk'
                                ? "Ak chcete dáta uložiť a vygenerovať report, použite zelené tlačidlo"
                                : "If you want to save data and generate a report, use the green button"}
                            <span className="text-green-400 font-black ml-1">"{t('inv_finish_btn')}"</span>.
                        </p>
                    </div>
                </div>
            ),
            type: 'danger',
            onConfirm: () => {
                if (activeInventoryTask) {
                    onDeleteTask(activeInventoryTask.id);
                }
                setScannedItems([]);
                localStorage.removeItem('inventory_scans');
                setLastSaved(null);
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleExportAndFinish = () => {
        if (!scannedItems || scannedItems.length === 0) {
            alert(language === 'sk' ? "Zoznam je prázdny." : "List is empty.");
            return;
        }

        handleExport();

        const finalCount = scannedItems.length.toString();

        if (activeInventoryTask) {
            onUpdateTask(activeInventoryTask.id, { 
                isDone: true, 
                status: 'completed', 
                completionTime: new Date().toLocaleTimeString('sk-SK'),
                completedBy: currentUser,
                completedAt: Date.now(),
                isInProgress: false,
                inProgressBy: null,
                quantity: finalCount
            });
        }

        setScannedItems([]);
        localStorage.removeItem('inventory_scans');
        setLastSaved(null);
    };

    const handleExport = () => {
        if (!scannedItems || scannedItems.length === 0) return;
        if (typeof XLSX === 'undefined') { alert("Library Error"); return; }
        const data = scannedItems.map(item => ({
            "Dátum inventúry": new Date(item.timestamp).toLocaleDateString('sk-SK'),
            "Užívateľ": resolveName(item.worker),
            "Lokácia": item.location,
            "Číslo dielu": item.partNumber,
            "Batch": item.batch,
            "Množstvo": item.quantity,
            "Presný čas": new Date(item.timestamp).toLocaleTimeString('sk-SK')
        }));
        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Inventúra");
        XLSX.writeFile(wb, `Inventura_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    const toggleBatchMissing = () => {
        const newState = !isBatchMissing;
        setIsBatchMissing(newState);
        if (newState) {
            setBatch(`[${t('inv_missing_label').toUpperCase()}]`);
            setTimeout(() => quantityRef.current?.focus(), 10);
        } else {
            setBatch('');
            setTimeout(() => batchRef.current?.focus(), 10);
        }
    };

    const inputBaseClass = "w-full h-12 bg-gray-700 border border-gray-600 rounded-lg px-4 text-white text-base placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#4169E1] transition-all font-mono uppercase";
    const dangerButtonClass = "bg-red-900/40 hover:bg-red-800 text-red-100 px-6 py-5 rounded-xl text-base font-black border-2 border-red-800/50 shadow-lg transition-all active:scale-95 uppercase tracking-wider flex items-center justify-center gap-2";

    return (
        <div className="max-w-4xl mx-auto space-y-8 pb-20 animate-fade-in">
            <div className="bg-gray-800 p-6 sm:p-8 rounded-xl shadow-lg border border-gray-700 relative overflow-hidden">
                {!activeInventoryTask ? (
                    <div className="flex flex-col items-center justify-center py-12 space-y-8">
                        <div className="text-center">
                            <h2 className="text-3xl font-bold text-white uppercase tracking-widest">{t('inv_not_started')}</h2>
                            <p className="text-gray-400 text-base mt-3">{t('inv_start_hint')}</p>
                        </div>
                        <button 
                            onClick={handleStartInventory}
                            className="bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-8 px-16 rounded-2xl shadow-[0_0_25px_rgba(65,105,225,0.4)] transition-all active:scale-95 uppercase tracking-[0.25em] text-2xl border-2 border-[#5a81f3]"
                        >
                            📋 {t('inv_start_btn')}
                        </button>
                    </div>
                ) : (
                    <>
                        <div className="flex justify-between items-start sm:items-center mb-10 border-b border-gray-700 pb-6">
                            <div>
                                <h1 className="text-4xl font-extrabold text-[#4169E1] uppercase tracking-widest leading-none">
                                    {t('tab_inventory')}
                                </h1>
                                <div className="flex gap-6 items-center mt-3">
                                    <span className="bg-[#4169E1]/20 text-[#4169E1] text-xs font-black px-3 py-1 rounded-md border border-[#4169E1]/40 animate-pulse uppercase">{t('inv_active_session')}</span>
                                    <p className="text-xs text-gray-500 uppercase font-mono">
                                        {t('inv_items_count')}: <span className="text-white font-bold">{(scannedItems || []).length}</span>
                                    </p>
                                </div>
                            </div>

                            <button 
                                onClick={handleCancelInventory}
                                className={dangerButtonClass.replace('px-6 py-5', 'px-5 py-3 text-xs')}
                            >
                                🛑 {t('inv_cancel_session')}
                            </button>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_loc_label')}</label>
                                <input 
                                    ref={locationRef}
                                    type="text"
                                    value={location}
                                    onChange={(e) => setLocation(e.target.value.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && partRef.current?.focus()}
                                    placeholder="NAPR. MA123"
                                    className={inputBaseClass}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_th_part')}</label>
                                <PartNumberInput 
                                    inputRef={partRef}
                                    parts={parts}
                                    onPartSelect={(p) => setPartNumber(p || '')}
                                    onInputChange={(val) => setPartNumber(val.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && batchRef.current?.focus()}
                                    placeholder={t('part_placeholder')}
                                    value={partNumber}
                                    onRequestPart={onRequestPart}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_batch_label')}</label>
                                <div className="flex gap-3">
                                    <input 
                                        ref={batchRef}
                                        type="text"
                                        inputMode="numeric"
                                        readOnly={isBatchMissing}
                                        value={batch}
                                        onChange={(e) => {
                                            if (!isBatchMissing) {
                                                const val = e.target.value.replace(/[^0-9]/g, '').slice(0, 7);
                                                setBatch(val);
                                            }
                                        }}
                                        maxLength={7}
                                        onKeyDown={(e) => e.key === 'Enter' && quantityRef.current?.focus()}
                                        placeholder={isBatchMissing ? '' : "489523"}
                                        className={`${inputBaseClass.replace('w-full', 'w-1/2')} ${isBatchMissing ? 'text-red-500 border-red-900/50 bg-red-900/10' : ''}`}
                                    />
                                    <button 
                                        type="button"
                                        onClick={toggleBatchMissing}
                                        className={`w-1/2 h-12 rounded-lg border-2 font-black uppercase text-xs text-white transition-all flex items-center justify-center gap-2 ${isBatchMissing ? 'bg-red-600 border-red-500 shadow-lg' : 'bg-[#4169E1]/20 border-[#4169E1] hover:bg-[#4169E1]/40'}`}
                                    >
                                        🏷️ {t('inv_missing_label')}
                                    </button>
                                </div>
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_qty_label')}</label>
                                <input 
                                    ref={quantityRef}
                                    type="text"
                                    inputMode="decimal"
                                    value={quantity}
                                    onChange={(e) => setQuantity(e.target.value.replace(/[^0-9.,]/g, '').slice(0, 7))}
                                    maxLength={7}
                                    onKeyDown={(e) => e.key === 'Enter' && handleAddItem()}
                                    placeholder="0"
                                    className={`${inputBaseClass} font-black text-lg`}
                                />
                            </div>
                        </div>

                        <button 
                            onClick={handleAddItem}
                            className="w-full mt-10 bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-6 rounded-2xl shadow-xl transition-all active:scale-95 uppercase tracking-widest text-xl border-2 border-[#5a81f3]"
                        >
                            {t('inv_add_btn')}
                        </button>
                    </>
                )}
            </div>

            {activeInventoryTask && (
                <div className="bg-gray-800 rounded-xl shadow-lg border border-gray-700 overflow-hidden">
                    <div className="p-5 sm:p-8 border-b border-gray-700 bg-gray-900/50 flex flex-col sm:row justify-between items-center gap-8">
                        <div className="flex items-center gap-6">
                            <h3 className="text-gray-400 font-black uppercase text-base tracking-[0.2em] leading-none">
                                {t('inv_summary_title')}
                            </h3>
                            <span className="bg-[#4169E1]/20 text-white border-2 border-[#4169E1] text-2xl px-5 py-2 rounded-xl font-black font-mono leading-none shadow-lg">
                                {(scannedItems || []).length}
                            </span>
                        </div>
                        <div className="flex flex-wrap w-full sm:w-auto gap-4">
                            <button 
                                onClick={handleClearAll} 
                                className={dangerButtonClass}
                            >
                                {language === 'sk' ? 'Zmazať všetko' : 'Clear all'}
                            </button>
                            <button 
                                onClick={handleExportAndFinish}
                                className="flex-1 sm:flex-none bg-green-700 hover:bg-green-600 text-white px-10 py-5 rounded-xl text-lg font-black shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 border-2 border-green-500 uppercase tracking-widest"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                                </svg>
                                {t('inv_finish_btn')}
                            </button>
                        </div>
                    </div>

                    <div className="overflow-x-auto custom-scrollbar">
                        <table className="w-full text-left text-base border-collapse">
                            <thead className="bg-gray-900/30 text-gray-500 text-xs font-black uppercase tracking-widest border-b border-gray-700">
                                <tr>
                                    <th className="py-5 px-6">{t('inv_th_time')}</th>
                                    <th className="py-5 px-6">{t('inv_th_loc')}</th>
                                    <th className="py-5 px-6">{t('inv_th_part')}</th>
                                    <th className="py-5 px-6">{t('inv_th_batch')}</th>
                                    <th className="py-5 px-6 text-right">{t('inv_th_qty')}</th>
                                    <th className="py-5 px-6 text-center"></th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-700/50">
                                {scannedItems && scannedItems.length > 0 ? (
                                    scannedItems.map(item => (
                                        <tr key={item.id} className="text-gray-300 hover:bg-gray-700/30 transition-colors group">
                                            <td className="py-5 px-6 text-xs text-gray-500 font-mono whitespace-nowrap">{new Date(item.timestamp).toLocaleTimeString('sk-SK')}</td>
                                            <td className="py-5 px-6 font-mono font-bold text-[#4169E1] text-lg">{item.location}</td>
                                            <td className="py-5 px-6 font-mono text-white text-base">{item.partNumber}</td>
                                            <td className={`py-5 px-6 font-mono text-base ${item.batch && item.batch.includes(t('inv_missing_label').toUpperCase()) ? 'text-red-500 font-bold' : 'text-gray-500'}`}>
                                                {item.batch || '-'}
                                            </td>
                                            <td className="py-5 px-6 font-black text-white text-right font-mono text-xl">{item.quantity}</td>
                                            <td className="py-5 px-6 text-center w-24">
                                                <button 
                                                    onClick={() => handleDeleteItem(item.id)} 
                                                    className="w-16 h-16 flex items-center justify-center rounded-lg bg-red-900/30 text-red-500 hover:bg-red-800 hover:text-white border border-red-800/50 transition-all active:scale-90"
                                                >
                                                    <TrashIcon className="w-8 h-8" />
                                                </button>
                                            </td>
                                        </tr>
                                    ))
                                ) : (
                                    <tr><td colSpan={6} className="py-16 text-center text-gray-600 italic font-bold text-lg">{t('inv_empty_list')}</td></tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {confirmModal.isOpen && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setConfirmModal(prev => ({...prev, isOpen: false}))}>
                    <div className="bg-gray-800 border-2 border-slate-700 rounded-2xl shadow-2xl w-full max-w-md p-8 relative" onClick={e => e.stopPropagation()}>
                        <div className="text-center mb-8">
                            <h3 className={`text-2xl font-black mb-3 uppercase tracking-tighter ${confirmModal.type === 'danger' ? 'text-red-500' : 'text-amber-500'}`}>
                                {confirmModal.title}
                            </h3>
                            <div className="text-gray-300 text-base leading-relaxed">
                                {confirmModal.message}
                            </div>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => setConfirmModal(prev => ({...prev, isOpen: false}))} className="flex-1 py-4 bg-gray-700 text-gray-300 rounded-xl hover:bg-gray-600 font-black transition-all uppercase text-xs">
                                {t('btn_cancel')}
                            </button>
                            <button onClick={confirmModal.onConfirm} className={`flex-1 py-4 text-white rounded-xl font-black transition-all shadow-xl uppercase text-xs border-2 ${confirmModal.type === 'danger' ? 'bg-red-600 hover:bg-red-700 border-red-500' : 'bg-amber-600 hover:bg-amber-700 border-amber-500'}`}>
                                {t('btn_confirm')}
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default InventoryTab;

import React, { useState } from 'react';
import { db } from '../../firebase';
import { 
  collection, 
  getDocs, 
  writeBatch,
  doc,
  getDoc,
  updateDoc
} from 'firebase/firestore';
import { useLanguage } from '../LanguageContext';
import { MapSector } from '../../types/appTypes';

declare var XLSX: any;

interface YearlyClosingProps {
  resolveName: (username?: string | null) => string;
  fetchSanons: () => Promise<any[]>;
  mapSectors: MapSector[];
}

const YearlyClosing: React.FC<YearlyClosingProps> = ({ resolveName, fetchSanons, mapSectors }) => {
  const { t, language } = useLanguage();
  const [isExporting, setIsExporting] = useState(false);
  const [isResetting, setIsResetting] = useState(false);
  const [hasExported, setHasExported] = useState(false);
  const [progress, setProgress] = useState('');

  const formatDate = (ts?: number) => {
    if (!ts) return '';
    const d = new Date(ts);
    return d.toLocaleDateString('sk-SK', { day: '2-digit', month: '2-digit', year: 'numeric' });
  };

  const formatTime = (ts?: number) => {
    if (!ts) return '';
    const d = new Date(ts);
    return d.toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' });
  };

  const formatDateTime = (ts?: number) => {
    if (!ts) return '';
    return `${formatDate(ts)} ${formatTime(ts)}`;
  };

  const resolveSectorName = (sectorId?: string) => {
      if (!sectorId) return '';
      const sector = mapSectors.find(s => s.id === sectorId);
      return sector ? sector.name : sectorId;
  };

  const fetchYearlyData = async () => {
    setIsExporting(true);
    setProgress(t('yearly_prep_download'));

    const allTasks: any[] = [];
    const currentYear = new Date().getFullYear();

    try {
      setProgress(t('yearly_fetch_live'));
      const snapTasks = await getDocs(collection(db, 'tasks'));
      snapTasks.forEach(d => allTasks.push({ id: d.id, ...d.data() }));

      setProgress(t('yearly_fetch_draft'));
      const draftSnap = await getDoc(doc(db, 'settings', 'draft'));
      if (draftSnap.exists()) {
          (draftSnap.data().data || []).forEach((t: any) => allTasks.push(t));
      }

      setProgress(t('yearly_fetch_weekly'));
      const sanons = await fetchSanons();

      sanons.forEach(sanon => {
          if (sanon.tasks && Array.isArray(sanon.tasks)) {
              allTasks.push(...sanon.tasks);
          }
      });

      if (allTasks.length === 0) {
        alert(t('yearly_no_data'));
        setIsExporting(false);
        return;
      }

      const excelData = allTasks.map(item => {
        let searchResult = '';
        if (item.searchedBy) {
          if (item.searchExhausted || item.auditResult) {
            searchResult = language === 'sk' ? 'Nie' : 'No';
          } else if (item.isMissing === false) {
            searchResult = language === 'sk' ? 'Áno' : 'Yes';
          } else {
            searchResult = language === 'sk' ? 'Prebieha' : 'In progress';
          }
        }

        let statusText = language === 'sk' ? 'Otvorené' : 'Open';
        if (item.status === 'incorrectly_entered') {
            statusText = language === 'sk' ? 'Chybne zadané' : 'Incorrectly entered';
        } else if (item.auditResult) {
            statusText = language === 'sk' ? 'Auditované' : 'Audited';
        } else if (item.isDone) {
            statusText = language === 'sk' ? 'Dokončené' : 'Completed';
        }

        let sourceVal = '';
        let targetVal = '';

        if (item.isLogistics) {
            const op = (item.workplace || '').toUpperCase();
            const isUnloading = op.includes('VYKL') || op.includes('UNLOAD') || op.includes('PRÍJEM') || op.includes('INBOUND');
            const isLoading = op.includes('NAKL') || op.includes('LOAD') || op.includes('EXPED') || op.includes('OUTBOUND');

            if (isUnloading) {
                 sourceVal = item.note || (language === 'sk' ? 'EXTERNY ZDROJ' : 'EXTERNAL SOURCE');
                 targetVal = resolveSectorName(item.targetSectorId) || (language === 'sk' ? 'PRÍJEM' : 'RECEIVING');
            } else if (isLoading) {
                 sourceVal = resolveSectorName(item.sourceSectorId) || (language === 'sk' ? 'SKLAD' : 'WAREHOUSE');
                 targetVal = item.note || (language === 'sk' ? 'EXTERNY CIEĽ' : 'EXTERNAL TARGET');
            } else {
                 sourceVal = resolveSectorName(item.sourceSectorId) || '';
                 targetVal = resolveSectorName(item.targetSectorId) || '';
            }
        } else {
            sourceVal = resolveSectorName(item.pickedFromSectorId) || '';
            targetVal = item.workplace || '';
        }

        return {
          [language === 'sk' ? 'Dátum pridania' : 'Added Date']: formatDate(item.createdAt),
          [language === 'sk' ? 'Čas pridania' : 'Added Time']: formatTime(item.createdAt),
          [language === 'sk' ? 'Kto pridal' : 'Created By']: resolveName(item.createdBy),
          [language === 'sk' ? 'Diel / Referencia' : 'Part / Ref']: item.partNumber || '',
          [language === 'sk' ? 'Pracovisko / Operácia' : 'Workplace / Op']: item.workplace || '',
          [language === 'sk' ? 'SPZ / Prepravca' : 'Plate / Carrier']: item.isLogistics ? (item.note || '') : '',
          [language === 'sk' ? 'Počet' : 'Quantity']: item.quantity || '',
          [language === 'sk' ? 'Jednotka' : 'Unit']: item.quantityUnit || '',
          [language === 'sk' ? 'Poznámka' : 'Note']: !item.isLogistics ? (item.note || '') : '',
          [language === 'sk' ? 'Skladník' : 'Picker']: resolveName(item.completedBy),
          [language === 'sk' ? 'Dátum dokončenia' : 'Done Date']: formatDate(item.completedAt),
          [language === 'sk' ? 'Čas dokončenia' : 'Done Time']: formatTime(item.completedAt),
          'Status': statusText,
          [language === 'sk' ? 'Nahlásil chýbajúce' : 'Reported Missing By']: resolveName(item.missingReportedBy),
          [language === 'sk' ? 'Dôvod chýbania' : 'Missing Reason']: item.missingReason || '',
          [language === 'sk' ? 'Čas nahlásenia chyby' : 'Report Time']: item.missingReportedBy ? formatTime(item.completedAt || item.createdAt) : '',
          [language === 'sk' ? 'Kto hľadal' : 'Searched By']: item.searchedBy || '',
          [language === 'sk' ? 'Výsledok hľadania' : 'Search Result']: searchResult,
          [language === 'sk' ? 'Audit (Výsledok)' : 'Audit Result']: item.auditResult || '',
          [language === 'sk' ? 'Poznámka k auditu' : 'Audit Note']: item.auditNote || '',
          [language === 'sk' ? 'Audit vykonal' : 'Audited By']: resolveName(item.auditedBy) || item.auditBy || '',
          [language === 'sk' ? 'Dátum a čas auditu' : 'Audit Datetime']: formatDateTime(item.auditedAt ?? undefined),
          [language === 'sk' ? 'Odkiaľ (Zdroj)' : 'From (Source)']: sourceVal,
          [language === 'sk' ? 'Kam (Cieľ)' : 'To (Target)']: targetVal
        };
      });

      const ws = XLSX.utils.json_to_sheet(excelData);
      const wscols = Array(24).fill({wch: 20});
      ws['!cols'] = wscols;

      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, "YEARLY_CLOSING");
      XLSX.writeFile(wb, `COMPLETE_ARCHIVE_${currentYear}_${new Date().getTime()}.xlsx`);

      setHasExported(true);
      setProgress(t('yearly_export_success'));
    } catch (error) {
      console.error(error);
      alert('Error during export.');
    } finally {
      setIsExporting(false);
    }
  };

  const handleReset = async () => {
    if (!hasExported) return;

    if (!window.confirm(t('yearly_reset_warning_1'))) return;
    if (!window.confirm(t('yearly_reset_warning_2'))) return;

    setIsResetting(true);
    setProgress(t('yearly_cleaning_db'));

    try {
      await updateDoc(doc(db, 'settings', 'draft'), { data: [] });

      const sanonsToDelete = await fetchSanons();
      if (sanonsToDelete.length > 0) {
          const batch = writeBatch(db);
          let opCount = 0;
          for (const sanon of sanonsToDelete) {
              batch.delete(doc(db, 'sanony', sanon.id));
              opCount++;
              if (opCount >= 498) { await batch.commit(); }
          }
          if (opCount > 0) await batch.commit();
      }

      const snapTasks = await getDocs(collection(db, 'tasks'));
      let batchTasks = writeBatch(db);
      let count = 0;
      for (const d of snapTasks.docs) {
        batchTasks.delete(d.ref);
        count++;
        if (count === 500) { await batchTasks.commit(); batchTasks = writeBatch(db); count = 0; }
      }
      if (count > 0) await batchTasks.commit();

      alert(t('yearly_reset_success'));
      window.location.reload();
    } catch (error) {
      console.error(error);
      alert('Error during data cleanup.');
    } finally {
      setIsResetting(false);
    }
  };

  return (
    <div className="bg-gray-800/40 border border-slate-700/50 rounded-2xl p-8 shadow-2xl backdrop-blur-sm animate-fade-in">
      <div className="flex items-center gap-4 mb-8">
        <div className="p-3 bg-rose-500/20 rounded-xl">
          <svg className="w-8 h-8 text-rose-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
        </div>
        <div>
          <h3 className="text-2xl font-black text-white uppercase tracking-tighter">{t('yearly_closing_title')}</h3>
          <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">{t('yearly_closing_subtitle')}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-slate-950/40 p-6 rounded-2xl border border-white/5 space-y-4">
          <h4 className="text-sm font-black text-teal-400 uppercase tracking-widest">{t('yearly_step1')}</h4>
          <p className="text-xs text-slate-400 leading-relaxed">
            {t('yearly_step1_desc')}
          </p>
          <button 
            onClick={fetchYearlyData}
            disabled={isExporting || isResetting}
            className={`w-full py-4 rounded-xl font-black uppercase text-xs tracking-widest transition-all border-2 shadow-lg flex items-center justify-center gap-3 ${
              isExporting ? 'bg-gray-700 border-gray-600 text-gray-400 animate-pulse' : 'bg-teal-600 hover:bg-teal-500 text-white border-teal-500'
            }`}
          >
            {isExporting ? '...' : (
              <>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                {t('yearly_download_btn')}
              </>
            )}
          </button>
        </div>

        <div className="bg-slate-950/40 p-6 rounded-2xl border border-white/5 space-y-4">
          <h4 className="text-sm font-black text-rose-400 uppercase tracking-widest">{t('yearly_step2')}</h4>
          <p className="text-xs text-slate-400 leading-relaxed">
            {t('yearly_step2_desc')}
          </p>
          <button 
            onClick={handleReset}
            disabled={!hasExported || isResetting || isExporting}
            className={`w-full py-4 rounded-xl font-black uppercase text-xs tracking-widest transition-all border-2 shadow-lg flex items-center justify-center gap-3 ${
              !hasExported ? 'bg-gray-800 border-gray-700 text-gray-600 cursor-not-allowed' : 'bg-rose-600 hover:bg-rose-500 text-white border-rose-500'
            }`}
          >
            {isResetting ? '...' : (
              <>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                {t('yearly_reset_btn')}
              </>
            )}
          </button>
        </div>
      </div>

      {progress && (
        <div className="mt-8 text-center animate-fade-in">
          <p className="text-xs font-mono font-bold text-amber-500 bg-amber-500/5 py-2 px-4 rounded-full inline-block border border-amber-500/20 uppercase tracking-widest">
            {progress}
          </p>
        </div>
      )}
    </div>
  );
};

export default YearlyClosing;

import React, { useState, useMemo } from 'react';
import { Task, UserData, MapSector, DBItem, SystemConfig, MapObstacle } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';
import { COLOR_MAP } from '../../constants/uiConstants';
import { findAStarPath, GRID_SIZE } from '../../utils/pathfinding';

interface MapVisualizationTabProps {
  tasks: Task[];
  draftTasks: Task[];
  fetchSanons: () => Promise<any[]>;
  users: UserData[];
  mapSectors: MapSector[];
  workplaces: DBItem[];
  logisticsOperations: DBItem[];
  mapObstacles: MapObstacle[];
  systemConfig: SystemConfig;
  resolveName: (username?: string | null) => string;
}

interface Point { x: number; y: number; label: string; type: 'wp' | 'sector' | 'log'; id: string; color?: string }
interface RouteSegment { path: {x: number, y: number}[]; worker: string; isTransit: boolean; taskType: 'prod' | 'log' }

interface HeatNode { x: number; y: number; freq: number; intensity: number }

interface MapData {
    segments: RouteSegment[];
    nodes: Point[];
    obstacles: MapObstacle[];
    viewBox: string;
    bottlenecks: { x: number, y: number, freq: number }[];
    heatNodes: HeatNode[];
}

const MapVisualizationTab: React.FC<MapVisualizationTabProps> = ({
  tasks, draftTasks, fetchSanons, users, mapSectors, workplaces, logisticsOperations, mapObstacles = [], systemConfig, resolveName
}) => {
  const { t, language } = useLanguage();

  const [dateFrom, setDateFrom] = useState(new Date().toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);
  const [selectedWorkers, setSelectedWorkers] = useState<string[]>([]);
  const [allData, setAllData] = useState<Task[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const handleLoadMap = async () => {
    setIsLoading(true);
    try {
        const sanons = await fetchSanons();
        const combined: Task[] = [...tasks, ...draftTasks];
        sanons.forEach(s => { if (s.tasks) combined.push(...s.tasks); });
        const startTs = new Date(dateFrom).setHours(0,0,0,0);
        const endTs = new Date(dateTo).setHours(23,59,59,999);
        const filtered = combined.filter(t => {
            const ts = t.completedAt || t.createdAt || 0;
            return ts >= startTs && ts <= endTs && t.isDone;
        });
        const uniqueMap = new Map();
        filtered.forEach(t => uniqueMap.set(t.id, t));
        setAllData(Array.from(uniqueMap.values()));
    } catch (e) { console.error(e); }
    finally { setIsLoading(false); }
  };

  const { segments, nodes, obstacles, viewBox, bottlenecks, heatNodes } = useMemo((): MapData => {
    const pointsMap = new Map<string, Point>();
    workplaces.forEach(w => pointsMap.set(`wp_${w.value}`, { x: w.coordX || 0, y: w.coordY || 0, label: w.value, type: 'wp', id: w.id }));
    logisticsOperations.forEach(l => pointsMap.set(`log_${l.value}`, { x: l.coordX || 0, y: l.coordY || 0, label: l.value, type: 'log', id: l.id }));
    mapSectors.forEach(s => pointsMap.set(`sector_${s.id}`, { x: s.coordX || 0, y: s.coordY || 0, label: s.name, type: 'sector', id: s.id, color: s.color }));

    const allNodes = Array.from(pointsMap.values());
    if (allNodes.length === 0 && mapObstacles.length === 0) {
        return { segments: [], nodes: [], obstacles: [], viewBox: "0 0 1000 1000", bottlenecks: [], heatNodes: [] };
    }

    const nodeXs = allNodes.length > 0 ? allNodes.map(p => p.x) : [0, 1000];
    const nodeYs = allNodes.length > 0 ? allNodes.map(p => p.y) : [0, 1000];
    const minX = Math.min(...nodeXs, ...mapObstacles.flatMap(o => [o.x, o.x + o.w])) - 100;
    const minY = Math.min(...nodeYs, ...mapObstacles.flatMap(o => [o.y, o.y + o.h])) - 100;
    const maxX = Math.max(...nodeXs, ...mapObstacles.flatMap(o => [o.x, o.x + o.w])) + 100;
    const maxY = Math.max(...nodeYs, ...mapObstacles.flatMap(o => [o.y, o.y + o.h])) + 100;

    const workerSegments: RouteSegment[] = [];
    const heatmap: Record<string, number> = {};

    const filteredByWorker = selectedWorkers.length > 0 ? allData.filter(t => selectedWorkers.includes(t.completedBy || '')) : allData;
    const grouped = new Map<string, Task[]>();
    filteredByWorker.forEach(t => {
        const worker = t.completedBy || 'Unknown';
        if (!grouped.has(worker)) grouped.set(worker, []);
        grouped.get(worker)!.push(t);
    });

    grouped.forEach((workerTasks, worker) => {
        const sorted = [...workerTasks].sort((a,b) => (a.completedAt || 0) - (b.completedAt || 0));
        let prevEnd: Point | null = null;
        sorted.forEach(task => {
            let startPoint: Point | null = null;
            let endPoint: Point | null = null;
            if (task.isLogistics) {
                const op = pointsMap.get(`log_${task.workplace}`);
                startPoint = pointsMap.get(`sector_${task.sourceSectorId}`) || op || null;
                endPoint = pointsMap.get(`sector_${task.targetSectorId}`) || op || null;
            } else {
                startPoint = pointsMap.get(`sector_${task.pickedFromSectorId}`) || null;
                endPoint = pointsMap.get(`wp_${task.workplace}`) || null;
            }
            if (startPoint && endPoint) {
                if (prevEnd) {
                    const transitPath = findAStarPath(prevEnd, startPoint, mapObstacles);
                    if (transitPath.length > 0) {
                        workerSegments.push({ path: transitPath, worker, isTransit: true, taskType: task.isLogistics ? 'log' : 'prod' });
                        transitPath.forEach(pt => {
                            const key = `${Math.round(pt.x/GRID_SIZE)*GRID_SIZE},${Math.round(pt.y/GRID_SIZE)*GRID_SIZE}`;
                            heatmap[key] = (heatmap[key] || 0) + 1;
                        });
                    }
                }
                const workPath = findAStarPath(startPoint, endPoint, mapObstacles);
                if (workPath.length > 0) {
                    workerSegments.push({ path: workPath, worker, isTransit: false, taskType: task.isLogistics ? 'log' : 'prod' });
                    workPath.forEach(pt => {
                        const key = `${Math.round(pt.x/GRID_SIZE)*GRID_SIZE},${Math.round(pt.y/GRID_SIZE)*GRID_SIZE}`;
                        heatmap[key] = (heatmap[key] || 0) + 1;
                    });
                }
                prevEnd = endPoint;
            }
        });
    });

    let maxFreq = 0;
    Object.values(heatmap).forEach(f => { if(f > maxFreq) maxFreq = f; });

    const finalHeatNodes: HeatNode[] = [];
    const finalBottlenecks: { x: number, y: number, freq: number }[] = [];

    Object.entries(heatmap).forEach(([key, freq]) => {
        const [x, y] = key.split(',').map(Number);
        const intensity = freq / maxFreq;
        if (intensity > 0.1) { finalHeatNodes.push({ x, y, freq, intensity }); }
        if (intensity > 0.8) { finalBottlenecks.push({ x, y, freq }); }
    });

    return { 
        segments: workerSegments, 
        nodes: allNodes, 
        obstacles: mapObstacles, 
        viewBox: `${minX} ${minY} ${maxX - minX} ${maxY - minY}`, 
        bottlenecks: finalBottlenecks,
        heatNodes: finalHeatNodes
    };
  }, [allData, selectedWorkers, workplaces, logisticsOperations, mapSectors, mapObstacles]);

  const generatePathData = (path: {x: number, y: number}[]) => {
      if (path.length === 0) return "";
      const simplified = [path[0]];
      for (let i = 1; i < path.length - 1; i++) {
          const prev = path[i-1], curr = path[i], next = path[i+1];
          if (!((prev.x === curr.x && curr.x === next.x) || (prev.y === curr.y && curr.y === next.y))) simplified.push(curr);
      }
      if (path.length > 1) simplified.push(path[path.length - 1]);
      return `M ${simplified[0].x} ${simplified[0].y} ` + simplified.slice(1).map(p => `L ${p.x} ${p.y}`).join(' ');
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6 pb-20 animate-fade-in px-2 md:px-0">
        <div className="bg-slate-900 border border-slate-700 rounded-2xl p-5 shadow-xl">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <div className="md:col-span-1 space-y-4">
                    <h3 className="text-sm font-black text-amber-500 uppercase tracking-widest border-b border-amber-900/30 pb-2">{t('map_period_title')}</h3>
                    <div className="grid grid-cols-2 gap-2">
                        <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className="bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-emerald-500 transition-all" />
                        <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} className="bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-white text-xs outline-none focus:border-emerald-500 transition-all" />
                    </div>
                    <button onClick={handleLoadMap} disabled={isLoading} className="w-full h-12 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-xl uppercase text-xs tracking-widest shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 border-2 border-emerald-400 disabled:opacity-50">
                        {isLoading ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : '🔄 ' + t('map_load_btn')}
                    </button>
                </div>
                <div className="md:col-span-2 space-y-4 border-l border-slate-800 pl-6">
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest border-b border-slate-800 pb-2">{t('map_filter_workers')}</h3>
                    <div className="flex flex-wrap gap-2 max-h-24 overflow-y-auto custom-scrollbar">
                        {users.map(u => (
                            <button key={u.username} onClick={() => setSelectedWorkers(prev => prev.includes(u.username) ? prev.filter(w => w !== u.username) : [...prev, u.username])} className={`px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${selectedWorkers.includes(u.username) ? 'bg-teal-500 border-teal-400 text-white shadow-lg' : 'bg-slate-800 border-slate-700 text-slate-500 hover:text-slate-300'}`}>{u.nickname || u.username}</button>
                        ))}
                    </div>
                </div>
                <div className="md:col-span-1 space-y-4 border-l border-slate-800 pl-6">
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest border-b border-slate-800 pb-2">{t('map_legend_title')}</h3>
                    <div className="flex flex-col gap-2 items-start text-[10px] font-black uppercase tracking-widest text-slate-500">
                        <div className="flex items-center gap-2"><div className="w-3 h-1 bg-teal-500 rounded"></div> {t('map_legend_prod')}</div>
                        <div className="flex items-center gap-2"><div className="w-3 h-1 bg-sky-500 rounded"></div> {t('map_legend_log')}</div>
                        <div className="flex items-center gap-2"><div className="w-3 h-3 bg-red-600/20 border border-red-500 rounded-full"></div> {t('map_bottleneck_label')}</div>
                    </div>
                </div>
            </div>
        </div>

        <div className="bg-slate-900 border-2 border-slate-800 rounded-3xl shadow-2xl overflow-hidden relative min-h-[650px] flex flex-col group">
            {isLoading && (
                <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm z-50 flex flex-col items-center justify-center gap-4">
                    <div className="w-16 h-16 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-emerald-500 font-black animate-pulse uppercase tracking-[0.4em] text-lg">{t('map_loading')}</p>
                </div>
            )}
            <div className="flex-grow relative overflow-hidden bg-slate-950">
                <svg viewBox={viewBox} className="w-full h-full min-h-[650px]" xmlns="http://www.w3.org/2000/svg">
                    <defs>
                        <pattern id="grid5m" width="50" height="50" patternUnits="userSpaceOnUse"><path d="M 50 0 L 0 0 0 50" fill="none" stroke="white" strokeWidth="1" strokeOpacity="0.05" /></pattern>
                        <pattern id="grid1m" width="10" height="10" patternUnits="userSpaceOnUse"><path d="M 10 0 L 0 0 0 10" fill="none" stroke="white" strokeWidth="0.5" strokeOpacity="0.02" /></pattern>
                        <pattern id="hatch" patternUnits="userSpaceOnUse" width="10" height="10"><path d="M-1,1 l2,-2 M0,10 l10,-10 M9,11 l2,-2" stroke="white" strokeWidth="1" strokeOpacity="0.1" /></pattern>
                        <filter id="blurHeat" x="-50%" y="-50%" width="200%" height="200%"><feGaussianBlur in="SourceGraphic" stdDeviation="6" /></filter>
                    </defs>

                    <rect width="10000" height="10000" x="-5000" y="-5000" fill="url(#grid1m)" />
                    <rect width="10000" height="10000" x="-5000" y="-5000" fill="url(#grid5m)" />

                    {obstacles.map((o, idx) => (
                        <g key={o.id || idx}>
                            <rect x={o.x} y={o.y} width={o.w} height={o.h} fill="#1e293b" stroke="#334155" strokeWidth="2" rx="4" />
                            <rect x={o.x} y={o.y} width={o.w} height={o.h} fill="url(#hatch)" rx="4" />
                            {o.w > 40 && <text x={o.x + o.w/2} y={o.y + o.h/2} textAnchor="middle" dominantBaseline="middle" className="fill-slate-600 text-[10px] font-black uppercase tracking-widest pointer-events-none">{o.name}</text>}
                        </g>
                    ))}

                    <g filter="url(#blurHeat)">
                        {heatNodes.map((hn, i) => (
                            <circle key={`heat-${i}`} cx={hn.x} cy={hn.y} r={18} fill={hn.intensity > 0.7 ? '#ef4444' : hn.intensity > 0.4 ? '#f59e0b' : '#10b981'} opacity={hn.intensity * 0.35} />
                        ))}
                    </g>

                    {segments.map((s, i) => (
                        <path key={`${s.isTransit ? 'tr' : 'ride'}-${i}`} d={generatePathData(s.path)} fill="none" stroke={s.isTransit ? '#475569' : (s.taskType === 'prod' ? '#14b8a6' : '#0ea5e9')} strokeWidth={s.isTransit ? 1 : 2.5} strokeDasharray={s.isTransit ? '4 4' : 'none'} strokeOpacity={s.isTransit ? 0.3 : 0.6} strokeLinecap="round" strokeLinejoin="round" />
                    ))}

                    {bottlenecks.map((bn, i) => (
                        <g key={`bn-${i}`} transform={`translate(${bn.x}, ${bn.y})`}>
                            <circle r="30" fill="none" stroke="#ef4444" strokeWidth="1" strokeDasharray="4 2" className="animate-spin" style={{ animationDuration: '4s' }} />
