import React, { useMemo } from 'react';
import { createPortal } from 'react-dom';
import { Task, SystemBreak, MapSector, DBItem, SystemConfig } from '../../../types/appTypes';
import { useLanguage } from '../../LanguageContext';

interface WorkerDetailModalProps {
  name: string;
  tasks: Task[];
  periodLabel: string;
  systemBreaks: SystemBreak[];
  onClose: () => void;
  mapSectors: MapSector[];
  workplaces: DBItem[];
  systemConfig: SystemConfig;
  logisticsOperations: DBItem[];
}

const WorkerDetailModal: React.FC<WorkerDetailModalProps> = ({ name, tasks, periodLabel, systemBreaks, onClose, mapSectors, workplaces, systemConfig, logisticsOperations }) => {
  const { t, language } = useLanguage();
  const VZV_SPEED_MPS = (systemConfig.vzvSpeed || 8) / 3.6;

  const calculateBlockedTime = (history: any[] | undefined, startTime: number, endTime: number): number => {
    let totalBlocked = 0;
    if (history && history.length > 0) {
      history.forEach(session => {
        const overlapStart = Math.max(startTime, session.start);
        const overlapEnd = Math.min(endTime, session.end || endTime);
        if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
      });
    }
    systemBreaks.forEach(br => {
      const overlapStart = Math.max(startTime, br.start);
      const overlapEnd = Math.min(endTime, br.end || endTime);
      if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
    });
    return totalBlocked;
  };

  const stats = useMemo(() => {
    let totalLoad = 0;
    let palCount = 0;
    let pcsTasks = 0;
    let missingReported = 0;
    let realErrors = 0;
    let totalExecMs = 0;
    let totalStandardMin = 0;
    let totalReactionMs = 0;
    let reactionCount = 0;
    let durations: number[] = [];
    let sumPerformance = 0;
    let countPerformanceTasks = 0;
    let totalFullDist = 0;
    let totalEmptyDist = 0;
    let totalTransitBetweenTasksDist = 0;

    const workplacesMap: Record<string, number> = {};
    const partsMap: Record<string, number> = {};
    const uniqueDaysWorked = new Set<string>();

    const sortedTasks = [...tasks].sort((a,b) => (a.completedAt || 0) - (b.completedAt || 0));
    let lastWorkplaceCoords: { x: number, y: number } | null = null;

    sortedTasks.forEach(task => {
      if (task.completedAt) {
        const dateKey = new Date(task.completedAt).toLocaleDateString('sk-SK');
        uniqueDaysWorked.add(dateKey);
      }

      const qtyVal = parseFloat((task.quantity || '1').replace(',', '.'));
      const loadMultiplier = (task.quantityUnit === 'pallet') ? qtyVal : 1;
      totalLoad += loadMultiplier;

      if (task.quantityUnit === 'pallet') palCount += qtyVal;
      else pcsTasks++;

      if (task.isDone && task.completedBy) {
          let validatedTrips = 0;
          let oneWayD = 0;

          if (lastWorkplaceCoords && !task.isLogistics && task.pickedFromSectorId) {
              const sector = mapSectors.find(s => s.id === task.pickedFromSectorId);
              if (sector) {
                  const transitD = (Math.abs(sector.coordX - lastWorkplaceCoords.x) + Math.abs(sector.coordY - lastWorkplaceCoords.y)) / 10;
                  totalTransitBetweenTasksDist += transitD;
              }
          }

          if (task.isLogistics) {
              const logOp = logisticsOperations.find(o => o.value === task.workplace);
              if (logOp && logOp.distancePx) {
                  oneWayD = logOp.distancePx;
                  const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
                  const possibleTrips = Math.round(( (durationMs / 1000) * VZV_SPEED_MPS ) / (2 * oneWayD));
                  validatedTrips = Math.min(Math.max(1, Math.floor(loadMultiplier)), Math.max(1, possibleTrips));
              }
          } else if (task.pickedFromSectorId && task.workplace) {
              const sector = mapSectors.find(s => s.id === task.pickedFromSectorId);
              const wp = workplaces.find(w => w.value === task.workplace);
              if (sector && wp) {
                  const dx = (wp.coordX || 0) - (sector.coordX || 0);
                  const dy = (wp.coordY || 0) - (sector.coordY || 0);
                  oneWayD = (Math.abs(dx) + Math.abs(dy)) / 10;
                  const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
                  const possibleTrips = Math.round(( (durationMs / 1000) * VZV_SPEED_MPS ) / (2 * oneWayD));
                  validatedTrips = Math.min(Math.max(1, Math.floor(loadMultiplier)), Math.max(1, possibleTrips));
                  lastWorkplaceCoords = { x: wp.coordX || 0, y: wp.coordY || 0 };
              }
          }

          if (validatedTrips > 0) {
              totalFullDist += validatedTrips * oneWayD;
              totalEmptyDist += (validatedTrips > 1 ? (validatedTrips - 1) * oneWayD : 0);
          }
      }

      if (task.startedAt && task.completedAt) {
        const rawDurationMs = task.completedAt - task.startedAt;
        const blockedMs = calculateBlockedTime(task.inventoryHistory, task.startedAt, task.completedAt);
        const realDurationMs = Math.max(rawDurationMs - blockedMs, 0);

        totalExecMs += realDurationMs;
        durations.push(realDurationMs);

        const standardTime = task.isLogistics 
            ? (logisticsOperations.find(o => o.value === task.workplace)?.standardTime || 0)
            : (workplaces.find(w => w.value === task.workplace)?.standardTime || 0);

        const targetMin = standardTime * loadMultiplier;
        const durationMin = realDurationMs / 60000;

        let adjustedMin;
        if (durationMin < 0.5) { adjustedMin = (targetMin * 2) || 2; } 
        else if (durationMin < 1) { adjustedMin = 1; } 
        else { adjustedMin = durationMin; }

        if (targetMin > 0) {
            const taskPerf = (targetMin / adjustedMin) * 100;
            const cappedPerf = Math.min(taskPerf, 200);
            sumPerformance += cappedPerf;
            countPerformanceTasks++;
            totalStandardMin += targetMin;
        }
      }

      if (task.createdAt && task.startedAt && task.startedAt > task.createdAt) {
        const react = task.startedAt - task.createdAt;
        totalReactionMs += react; reactionCount++;
      }

      const isProd = (task.isProduction === true) || (!task.isLogistics && !!task.workplace);
      if (isProd && task.workplace) workplacesMap[task.workplace] = (workplacesMap[task.workplace] || 0) + 1;
      if (task.partNumber) partsMap[task.partNumber] = (partsMap[task.partNumber] || 0) + 1;

      if (task.isMissing) {
        missingReported++;
        if (task.auditResult === 'NOK') realErrors++;
      }
    });

    const numDays = Math.max(uniqueDaysWorked.size, 1);
    const SHIFT_MINUTES = 450;
    const totalAvailableMinutes = numDays * SHIFT_MINUTES;
    const pureWorkMinutes = totalExecMs / 60000;

    const performanceRatio = countPerformanceTasks > 0 ? (sumPerformance / countPerformanceTasks) : 0;
    const avgReactionSeconds = reactionCount > 0 ? (totalReactionMs / reactionCount) / 1000 : 0;
    const confidenceRating = missingReported > 0 ? ((missingReported - realErrors) / missingReported) * 100 : 100;
    const grandTotalEmptyDist = totalEmptyDist + totalTransitBetweenTasksDist;
    const logEfficiency = (totalFullDist + grandTotalEmptyDist) > 0 ? (totalFullDist / (totalFullDist + grandTotalEmptyDist)) * 100 : 50;

    const utilizationPercent = (pureWorkMinutes * 1.15 / totalAvailableMinutes) * 100;

    const scoreQuality = (confidenceRating / 100) * 3.0;
    const scoreUtilization = (Math.min(utilizationPercent, 100) / 100) * 2.5;
    const scoreStandards = performanceRatio > 0 ? (Math.min(performanceRatio, 200) / 200) * 2.0 : 1.0; 
    const scoreReaction = avgReactionSeconds > 0 ? (avgReactionSeconds < 60 ? 1.0 : avgReactionSeconds < 180 ? 0.5 : 0) : 0.5;
    const scoreLogistics = (logEfficiency / 100) * 1.0;

    const workerIndex = parseFloat((scoreQuality + scoreUtilization + scoreStandards + scoreReaction + scoreLogistics).toFixed(1));

    return {
      totalLoad, palCount, pcsTasks, 
      confidenceRating, realErrors, missingReported,
      totalExecMs, 
      avgMsPerPoint: durations.length > 0 ? totalExecMs / totalLoad : 0,
      topWorkplaces: Object.entries(workplacesMap).sort(([,a],[,b]) => b-a).slice(0, 3).map(([name, count]) => ({ name, count })),
      topParts: Object.entries(partsMap).sort(([,a],[,b]) => b-a).slice(0, 3).map(([name, count]) => ({ name, count })),
      utilizationPercent, pureWorkMinutes, workerIndex, performanceRatio, avgReactionSeconds,
      totalFullDist, totalEmptyDist: grandTotalEmptyDist, transitOnlyDist: totalTransitBetweenTasksDist,
      logEfficiency, totalStandardMin
    };
  }, [tasks, systemBreaks, mapSectors, workplaces, systemConfig, VZV_SPEED_MPS, logisticsOperations]);

  const formatDuration = (ms: number) => {
    if (ms <= 0) return '-';
    const minutes = Math.round(ms / 60000);
    if (minutes < 1) return language === 'sk' ? '< 1 min' : '< 1 min';
    if (minutes >= 60) return `${Math.floor(minutes / 60)}h ${minutes % 60}m`;
    return `${minutes} min`;
  };

  const formatMinutes = (totalMin: number) => {
    const h = Math.floor(totalMin / 60);
    const m = Math.round(totalMin % 60);
    return h > 0 ? `${h}h ${m}m` : `${m} min`;
  };

  return createPortal(
    <div className="fixed inset-0 z-[10000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in" onClick={onClose}>
      <div className="bg-slate-900 border-2 border-slate-800 rounded-[2.5rem] shadow-[0_0_100px_rgba(0,0,0,0.8)] w-full max-w-6xl p-8 relative overflow-hidden flex flex-col max-h-[95vh]" onClick={e => e.stopPropagation()}>

        <div className="absolute top-0 right-0 w-96 h-96 bg-teal-500/5 rounded-full -mr-48 -mt-48 blur-[100px]"></div>
        <div className="absolute bottom-0 left-0 w-96 h-96 bg-purple-500/5 rounded-full -ml-48 -mb-48 blur-[100px]"></div>

        <div className="flex justify-between items-start mb-10 relative z-10 border-b border-white/5 pb-8">
          <div>
            <div className="flex items-center gap-4 mb-2">
              <div className="w-14 h-14 rounded-2xl bg-teal-500/10 border border-teal-500/20 flex items-center justify-center text-teal-400 text-2xl font-black">
                {name.charAt(0).toUpperCase()}
              </div>
              <div>
                <h2 className="text-4xl font-black text-white tracking-tighter uppercase">{name}</h2>
                <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mt-1">
                  {t('detail_period')}: <span className="text-teal-500">{periodLabel}</span>
                </p>
              </div>
            </div>
          </div>
          <div className="text-right">
            <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.25em] mb-1">WORKER INDEX</p>
            <p className="text-6xl font-black text-white tracking-tighter tabular-nums leading-none">
              {stats.workerIndex}<span className="text-xl text-slate-600">/10</span>
            </p>
          </div>
        </div>

        <div className="flex-grow overflow-y-auto custom-scrollbar pr-4 space-y-10 relative z-10">

          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <div className="bg-slate-800/40 p-6 rounded-3xl border border-white/5">
                <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest">{t('detail_total_load')}</p>
                <p className="text-3xl font-black text-white mt-1">{stats.totalLoad.toFixed(1)} <span className="text-sm font-normal text-slate-600">{t('points')}</span></p>
            </div>
            <div className="bg-slate-800/40 p-6 rounded-3xl border border-white/5">
                <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest">{language === 'sk' ? 'Naložené paliet' : 'Pallets handled'}</p>
                <p className="text-3xl font-black text-sky-400 mt-1">{stats.palCount} <span className="text-sm font-normal text-slate-600">{t('unit_pallet_short')}</span></p>
            </div>
            <div className="bg-slate-800/40 p-6 rounded-3xl border border-white/5">
                <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest">{t('detail_utilization')}</p>
                <p className={`text-3xl font-black mt-1 ${stats.utilizationPercent > 80 ? 'text-green-400' : stats.utilizationPercent > 50 ? 'text-amber-400' : 'text-slate-400'}`}>
                  {stats.utilizationPercent.toFixed(1)}%
                </p>
            </div>
            <div className="bg-slate-800/40 p-6 rounded-3xl border border-white/5">
                <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest">{t('detail_avg_reaction')}</p>
                <p className="text-3xl font-black text-purple-400 mt-1">
                  {stats.avgReactionSeconds > 60 ? `${(stats.avgReactionSeconds/60).toFixed(1)}m` : `${Math.round(stats.avgReactionSeconds)}s`}
                </p>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="bg-slate-950/40 border border-slate-800 p-8 rounded-3xl space-y-8">
              <h3 className="text-xs font-black text-slate-400 uppercase tracking-[0.25em] border-b border-white/5 pb-4">{t('detail_log_section')}</h3>
              <div className="space-y-6">
                <div>
                  <div className="flex justify-between items-end mb-2">
                    <p className="text-[10px] font-black text-slate-500 uppercase">{t('detail_efficiency')}</p>
                    <p className="text-lg font-black text-white">{stats.logEfficiency.toFixed(1)}%</p>
                  </div>
                  <div className="w-full bg-slate-800 h-2 rounded-full overflow-hidden">
                    <div style={{ width: `${stats.logEfficiency}%` }} className={`h-full transition-all duration-700 ${stats.logEfficiency > 75 ? 'bg-green-500' : 'bg-amber-500'}`}></div>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-8 pt-4">
                  <div>
                    <p className="text-slate-500 text-[9px] font-black uppercase">{t('detail_dist_full')}</p>
                    <p className="text-xl font-black text-sky-500 mt-1">{(stats.totalFullDist / 1000).toFixed(3)} km</p>
                  </div>
                  <div>
                    <p className="text-slate-500 text-[9px] font-black uppercase">{t('detail_dist_empty')}</p>
                    <p className="text-xl font-black text-rose-500 mt-1">{(stats.totalEmptyDist / 1000).toFixed(3)} km</p>
                  </div>
                </div>
                <div className="bg-slate-900/50 p-4 rounded-2xl border border-white/5">
                  <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-1">{t('detail_shadow_log')}</p>
                  <p className="text-sm font-bold text-slate-300">
                    {t('detail_shadow_desc', { m: stats.transitOnlyDist.toFixed(0) })}
                  </p>
                </div>
              </div>
            </div>

            <div className="bg-slate-950/40 border border-slate-800 p-8 rounded-3xl space-y-8">
              <h3 className="text-xs font-black text-slate-400 uppercase tracking-[0.25em] border-b border-white/5 pb-4">{t('detail_quality_section')}</h3>
              <div className="flex items-center gap-8">
                <div className="relative w-24 h-24 flex-shrink-0">
                  <svg className="w-full h-full transform -rotate-90">
                    <circle cx="48" cy="48" r="42" stroke="currentColor" strokeWidth="8" fill="transparent" className="text-slate-800" />
                    <circle cx="48" cy="48" r="42" stroke="currentColor" strokeWidth="8" fill="transparent" 
                      strokeDasharray={264} 
                      strokeDashoffset={264 - (264 * stats.confidenceRating) / 100} 
                      className={`${stats.confidenceRating > 90 ? 'text-teal-500' : 'text-amber-500'} transition-all duration-1000`} 
                    />
                  </svg>
                  <div className="absolute inset-0 flex flex-col items-center justify-center">
                    <span className="text-xl font-black text-white leading-none">{Math.round(stats.confidenceRating)}</span>
                    <span className="text-[8px] text-slate-500 uppercase font-black">Score</span>
                  </div>
                </div>
                <div className="space-y-4">
                  <p className="text-sm text-slate-300 leading-relaxed">
                    {language === 'sk' 
                      ? `Skladník nahlásil ${stats.missingReported}x chýbajúci tovar, z čoho ${stats.realErrors} boli reálne chyby.`
                      : `Worker reported ${stats.missingReported}x missing items, ${stats.realErrors} were real errors.`
                    }
                  </p>
                  <div className="px-3 py-1 bg-teal-500/10 border border-teal-500/20 rounded-lg w-fit">
                      <p className="text-[8px] font-black text-teal-500 uppercase">{t('detail_trust')}</p>
                      <p className="text-sm font-black text-teal-400">{stats.confidenceRating > 80 ? t('detail_trust_high') : t('detail_trust_mod')}</p>
                  </div>
                </div>
              </div>
              {stats.topParts.length > 0 && (
                <div className="pt-4 border-t border-white/5">
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">{t('chart_parts_label')}</p>
                  <div className="flex flex-wrap gap-2">
                    {stats.topParts.map(p => (
                      <span key={p.name} className="bg-slate-900 px-3 py-1.5 rounded-xl border border-white/5 text-[10px] font-mono font-bold text-slate-400">
                        {p.name} <span className="text-white ml-2">({p.count}x)</span>
                      </span>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>

          <div className="bg-slate-950/40 border border-slate-800 p-8 rounded-3xl">
             <h3 className="text-xs font-black text-slate-400 uppercase tracking-[0.25em] border-b border-white/5 pb-4 mb-8">{t('detail_perf_section')}</h3>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-12">
                <div className="space-y-2">
                  <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest">{t('detail_net_work')}</p>
                  <p className="text-3xl font-black text-white">{formatMinutes(stats.pureWorkMinutes)}</p>
                  <p className="text-[10px] text-slate-600 font-bold uppercase italic">{t('detail_net_desc')}</p>
                </div>
                <div className="space-y-2">
                  <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest">{t('detail_std_perf')}</p>
                  <p className={`text-3xl font-black ${stats.performanceRatio > 100 ? 'text-green-400' : 'text-slate-300'}`}>
                    {stats.performanceRatio.toFixed(1)}%
                  </p>
                  <p className="text-[10px] text-slate-600 font-bold uppercase">{t('detail_std_sum')}: {stats.totalStandardMin.toFixed(0)} min</p>
                </div>
                <div className="space-y-2">
                  <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest">{t('detail_tempo')}</p>
                  <p className="text-3xl font-black text-amber-500">{formatDuration(stats.avgMsPerPoint)} <span className="text-sm font-normal text-slate-600">/ {t('load')}</span></p>
                  <p className="text-[10px] text-slate-600 font-bold uppercase italic">{t('detail_tempo_desc')}</p>
                </div>
             </div>
          </div>

        </div>

        <div className="mt-8 pt-6 border-t border-white/5 flex justify-between items-center relative z-10">
          <p className="text-[10px] font-bold text-slate-600 uppercase tracking-widest">
            {t('detail_audit_tag')}
          </p>
          <button 
            onClick={onClose}
            className="px-10 py-4 bg-white text-slate-900 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-slate-200 transition-all active:scale-95 shadow-xl"
          >
            {t('map_close_detail')}
          </button>
        </div>

      </div>
    </div>,
    document.body
  );
};

export default WorkerDetailModal;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { useLanguage } from '../LanguageContext';
import PartNumberInput from '../PartNumberInput';
import { Task, PriorityLevel } from '../../types/appTypes';

interface ScannedItem {
    id: string;
    location: string;
    partNumber: string;
    batch: string;
    quantity: string;
    timestamp: number;
    worker: string;
}

interface InventoryTabProps {
    currentUser: string;
    tasks: Task[];
    onAddTask: (pn: string, wp: string | null, qty: string | null, unit: string | null, prio: PriorityLevel, isLogistics?: boolean) => void;
    onUpdateTask: (id: string, updates: Partial<Task>) => void;
    onToggleTask: (id: string) => void;
    onDeleteTask: (id: string) => void;
    hasPermission: (perm: string) => boolean;
    parts: string[];
    onRequestPart: (part: string) => Promise<boolean>;
    resolveName: (username?: string | null) => string;
}

declare var XLSX: any;

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
);

const InventoryTab: React.FC<InventoryTabProps> = ({ currentUser, tasks, onAddTask, onUpdateTask, onDeleteTask, parts, onRequestPart, resolveName }) => {
    const { t, language } = useLanguage();

    const locationRef = useRef<HTMLInputElement>(null);
    const partRef = useRef<HTMLInputElement>(null);
    const batchRef = useRef<HTMLInputElement>(null);
    const quantityRef = useRef<HTMLInputElement>(null);

    const [location, setLocation] = useState('');
    const [partNumber, setPartNumber] = useState('');
    const [batch, setBatch] = useState('');
    const [isBatchMissing, setIsBatchMissing] = useState(false);
    const [quantity, setQuantity] = useState('');
    const [scannedItems, setScannedItems] = useState<ScannedItem[]>([]);

    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: React.ReactNode;
        onConfirm: () => void;
        type: 'danger' | 'warning';
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => {},
        type: 'danger'
    });

    const activeInventoryTask = useMemo(() => {
        return (tasks || []).find(t => 
            t.partNumber === "Počítanie zásob" && 
            !t.isDone && 
            t.inProgressBy === currentUser
        );
    }, [tasks, currentUser]);

    // Načítanie dát viazané na konkrétne ID úlohy
    useEffect(() => {
        if (!activeInventoryTask) {
            setScannedItems([]);
            return;
        }

        const storageKey = `inventory_scans_${activeInventoryTask.id}`;
        const saved = localStorage.getItem(storageKey);

        if (saved) {
            try {
                const parsed = JSON.parse(saved);
                if (Array.isArray(parsed)) {
                    setScannedItems(parsed);
                }
            } catch (e) {
                console.error("Failed to parse inventory scans", e);
            }
        } else {
            // Ak neexistujú dáta pre túto úlohu, skúsime starý kľúč (migrácia)
            const legacySaved = localStorage.getItem('inventory_scans');
            if (legacySaved) {
                try {
                    const parsed = JSON.parse(legacySaved);
                    setScannedItems(parsed);
                    localStorage.setItem(storageKey, legacySaved);
                    localStorage.removeItem('inventory_scans');
                } catch(e) {}
            } else {
                setScannedItems([]);
            }
        }
    }, [activeInventoryTask?.id]);

    // Ukladanie dát pri zmene zoznamu
    useEffect(() => {
        if (activeInventoryTask && scannedItems.length >= 0) {
            const storageKey = `inventory_scans_${activeInventoryTask.id}`;
            localStorage.setItem(storageKey, JSON.stringify(scannedItems));
        }
    }, [scannedItems, activeInventoryTask?.id]);

    const handleStartInventory = () => {
        onAddTask("Počítanie zásob", "Inventúra", "0", "pallet", "NORMAL", true);
    };

    const handleAddItem = () => {
        const normalizedQty = quantity.replace(',', '.').trim();
        const isLocEmpty = !location.trim();
        const isPartEmpty = !partNumber.trim();
        const isQtyEmpty = !normalizedQty || isNaN(Number(normalizedQty));
        const isBatchRequiredAndEmpty = !isBatchMissing && !batch.trim();

        if (isLocEmpty || isPartEmpty || isQtyEmpty || isBatchRequiredAndEmpty) {
            const missingFields = [];
            if (isLocEmpty) missingFields.push(t('inv_th_loc'));
            if (isPartEmpty) missingFields.push(t('inv_th_part'));
            if (isBatchRequiredAndEmpty) missingFields.push(t('inv_th_batch'));
            if (isQtyEmpty) missingFields.push(t('inv_th_qty'));

            const errorMsg = language === 'sk' 
                ? `Chyba: Vyplňte ${missingFields.join(', ')}.` 
                : `Error: Fill ${missingFields.join(', ')}.`;

            alert(errorMsg);
            return;
        }

        const newItem: ScannedItem = {
            id: crypto.randomUUID(),
            location: location.trim().toUpperCase(),
            partNumber: partNumber.trim().toUpperCase(),
            batch: isBatchMissing ? `[${t('inv_missing_label').toUpperCase()}]` : batch.trim(),
            quantity: normalizedQty,
            timestamp: Date.now(),
            worker: currentUser
        };

        setScannedItems(prev => [newItem, ...prev]);

        // Reset polí okrem lokácie (pre efektívne skenovanie regálu)
        setPartNumber(''); 
        setBatch(''); 
        setIsBatchMissing(false);
        setQuantity('');

        // Vrátenie focusu na diel
        setTimeout(() => partRef.current?.focus(), 50);
    };

    const handleDeleteItem = (id: string) => {
        setScannedItems(prev => prev.filter(item => item.id !== id));
    };

    const handleClearAll = () => {
        setConfirmModal({
            isOpen: true,
            title: t('confirm_clear_all'),
            message: t('confirm_clear_all_msg'),
            type: 'danger',
            onConfirm: () => {
                setScannedItems([]);
                if (activeInventoryTask) {
                    localStorage.removeItem(`inventory_scans_${activeInventoryTask.id}`);
                }
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleCancelInventory = () => {
        setConfirmModal({
            isOpen: true,
            title: language === 'sk' ? "Zrušiť reláciu inventúry?" : "Cancel inventory session?",
            message: language === 'sk' 
                ? "Dáta tejto relácie budú natrvalo odstránené z pamäte tabletu." 
                : "Data for this session will be permanently removed from tablet storage.",
            type: 'danger',
            onConfirm: () => {
                if (activeInventoryTask) {
                    localStorage.removeItem(`inventory_scans_${activeInventoryTask.id}`);
                    onDeleteTask(activeInventoryTask.id);
                }
                setScannedItems([]);
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleExportAndFinish = () => {
        if (scannedItems.length === 0) {
            alert(language === 'sk' ? "Nemožno ukončiť prázdnu inventúru." : "Cannot finish empty inventory.");
            return;
        }

        handleExport();

        if (activeInventoryTask) {
            onUpdateTask(activeInventoryTask.id, { 
                isDone: true, 
                status: 'completed', 
                completedBy: currentUser,
                completedAt: Date.now(),
                isInProgress: false,
                inProgressBy: null,
                quantity: scannedItems.length.toString()
            });
            localStorage.removeItem(`inventory_scans_${activeInventoryTask.id}`);
        }
        setScannedItems([]);
    };

    const handleExport = () => {
        if (scannedItems.length === 0 || typeof XLSX === 'undefined') return;

        const data = scannedItems.map(item => ({
            "Dátum": new Date(item.timestamp).toLocaleDateString('sk-SK'),
            "Skladník": resolveName(item.worker),
            "Lokácia": item.location,
            "Číslo dielu": item.partNumber,
            "Batch": item.batch,
            "Množstvo": item.quantity.replace('.', ','),
            "Čas": new Date(item.timestamp).toLocaleTimeString('sk-SK')
        }));

        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Inventúra");
        XLSX.writeFile(wb, `Inventura_${activeInventoryTask?.id || 'export'}_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    const toggleBatchMissing = () => {
        const newState = !isBatchMissing;
        setIsBatchMissing(newState);
        if (newState) {
            setBatch(`[${t('inv_missing_label').toUpperCase()}]`);
            setTimeout(() => quantityRef.current?.focus(), 50);
        } else {
            setBatch('');
            setTimeout(() => batchRef.current?.focus(), 50);
        }
    };

    const inputBaseClass = "w-full h-12 bg-gray-700 border border-gray-600 rounded-lg px-4 text-white text-base placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#4169E1] transition-all font-mono uppercase";
    const dangerButtonClass = "bg-red-900/40 hover:bg-red-800 text-red-100 px-6 py-5 rounded-xl text-base font-black border-2 border-red-800/50 shadow-lg transition-all active:scale-95 uppercase tracking-wider flex items-center justify-center gap-2";

    return (
        <div className="max-w-4xl mx-auto space-y-8 pb-20 animate-fade-in">
            <div className="bg-gray-800 p-6 sm:p-8 rounded-xl shadow-lg border border-gray-700">
                {!activeInventoryTask ? (
                    <div className="flex flex-col items-center justify-center py-12 space-y-8">
                        <div className="text-center">
                            <h2 className="text-3xl font-bold text-white uppercase tracking-widest">{t('inv_not_started')}</h2>
                            <p className="text-gray-400 text-base mt-3">{t('inv_start_hint')}</p>
                        </div>
                        <button 
                            onClick={handleStartInventory}
                            className="bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-8 px-16 rounded-2xl shadow-[0_0_25px_rgba(65,105,225,0.4)] transition-all active:scale-95 uppercase tracking-[0.25em] text-2xl border-2 border-[#5a81f3]"
                        >
                            📋 {t('inv_start_btn')}
                        </button>
                    </div>
                ) : (
                    <>
                        <div className="flex justify-between items-start sm:items-center mb-10 border-b border-gray-700 pb-6">
                            <div>
                                <h1 className="text-4xl font-extrabold text-[#4169E1] uppercase tracking-widest leading-none">
                                    {t('tab_inventory')}
                                </h1>
                                <div className="flex gap-6 items-center mt-3">
                                    <span className="bg-[#4169E1]/20 text-[#4169E1] text-xs font-black px-3 py-1 rounded-md border border-[#4169E1]/40 animate-pulse uppercase">{t('inv_active_session')}</span>
                                    <p className="text-xs text-gray-500 uppercase font-mono">
                                        {t('inv_items_count')}: <span className="text-white font-bold">{scannedItems.length}</span>
                                    </p>
                                </div>
                            </div>

                            <button 
                                onClick={handleCancelInventory}
                                className={dangerButtonClass.replace('px-6 py-5', 'px-5 py-3 text-xs')}
                            >
                                🛑 {t('inv_cancel_session')}
                            </button>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_loc_label')}</label>
                                <input 
                                    ref={locationRef}
                                    type="text"
                                    value={location}
                                    onChange={(e) => setLocation(e.target.value.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && partRef.current?.focus()}
                                    placeholder="NAPR. MA123"
                                    className={inputBaseClass}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_th_part')}</label>
                                <PartNumberInput 
                                    inputRef={partRef}
                                    parts={parts}
                                    onPartSelect={(p) => { if(p) { setPartNumber(p); setTimeout(() => batchRef.current?.focus(), 50); } }}
                                    onInputChange={(val) => setPartNumber(val.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && batchRef.current?.focus()}
                                    placeholder={t('part_placeholder')}
                                    value={partNumber}
                                    onRequestPart={onRequestPart}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_batch_label')}</label>
                                <div className="flex gap-3">
                                    <input 
                                        ref={batchRef}
                                        type="text"
                                        inputMode="numeric"
                                        readOnly={isBatchMissing}
                                        value={batch}
                                        onChange={(e) => {
                                            if (!isBatchMissing) {
                                                const val = e.target.value.replace(/[^0-9]/g, '').slice(0, 10);
                                                setBatch(val);
                                            }
                                        }}
                                        onKeyDown={(e) => e.key === 'Enter' && quantityRef.current?.focus()}
                                        placeholder={isBatchMissing ? '' : "BATCH / LOT"}
                                        className={`${inputBaseClass.replace('w-full', 'w-1/2')} ${isBatchMissing ? 'text-red-500 border-red-900/50 bg-red-900/10' : ''}`}
                                    />
                                    <button 
                                        type="button"
                                        onClick={toggleBatchMissing}
                                        className={`w-1/2 h-12 rounded-lg border-2 font-black uppercase text-xs text-white transition-all flex items-center justify-center gap-2 ${isBatchMissing ? 'bg-red-600 border-red-500 shadow-lg' : 'bg-[#4169E1]/20 border-[#4169E1] hover:bg-[#4169E1]/40'}`}
                                    >
                                        🏷️ {t('inv_missing_label')}
                                    </button>
                                </div>
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_qty_label')}</label>
                                <input 
                                    ref={quantityRef}
                                    type="text"
                                    inputMode="decimal"
                                    value={quantity}
                                    onChange={(e) => setQuantity(e.target.value.replace(/[^0-9.,]/g, '').slice(0, 10))}
                                    onKeyDown={(e) => e.key === 'Enter' && handleAddItem()}
                                    placeholder="0"
                                    className={`${inputBaseClass} font-black text-lg`}
                                />
                            </div>
                        </div>

                        <button 
                            onClick={handleAddItem}
                            className="w-full mt-10 bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-6 rounded-2xl shadow-xl transition-all active:scale-95 uppercase tracking-widest text-xl border-2 border-[#5a81f3]"
                        >
                            {t('inv_add_btn')}
                        </button>
                    </>
                )}
            </div>

            {activeInventoryTask && (
                <div className="bg-gray-800 rounded-xl shadow-lg border border-gray-700 overflow-hidden">
                    <div className="p-5 sm:p-8 border-b border-gray-700 bg-gray-900/50 flex flex-col sm:flex-row justify-between items-center gap-8">
                        <div className="flex items-center gap-6">
                            <h3 className="text-gray-400 font-black uppercase text-base tracking-[0.2em] leading-none">
                                {t('inv_summary_title')}
                            </h3>
                            <span className="bg-[#4169E1]/20 text-white border-2 border-[#4169E1] text-2xl px-5 py-2 rounded-xl font-black font-mono leading-none shadow-lg">
                                {scannedItems.length}
                            </span>
                        </div>
                        <div className="flex flex-wrap w-full sm:w-auto gap-4">
                            <button 
                                onClick={handleClearAll} 
                                className={dangerButtonClass}
                            >
                                {language === 'sk' ? 'Zmazať všetko' : 'Clear all'}
                            </button>
                            <button 
                                onClick={handleExportAndFinish}
                                className="flex-1 sm:flex-none bg-green-700 hover:bg-green-600 text-white px-10 py-5 rounded-xl text-lg font-black shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 border-2 border-green-500 uppercase tracking-widest"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                                </svg>
                                {t('inv_finish_btn')}
                            </button>
                        </div>
                    </div>

                    <div className="overflow-x-auto custom-scrollbar">
                        <table className="w-full text-left text-base border-collapse">
                            <thead className="bg-gray-900/30 text-gray-500 text-xs font-black uppercase tracking-widest border-b border-gray-700">
                                <tr>
                                    <th className="py-5 px-6">{t('inv_th_time')}</th>
                                    <th className="py-5 px-6">{t('inv_th_loc')}</th>
                                    <th className="py-5 px-6">{t('inv_th_part')}</th>
                                    <th className="py-5 px-6">{t('inv_th_batch')}</th>
                                    <th className="py-5 px-6 text-right">{t('inv_th_qty')}</th>
                                    <th className="py-5 px-6 text-center"></th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-700/50">
                                {scannedItems.length > 0 ? (
                                    scannedItems.map(item => (
                                        <tr key={item.id} className="text-gray-300 hover:bg-gray-700/30 transition-colors group">
                                            <td className="py-5 px-6 text-xs text-gray-500 font-mono whitespace-nowrap">{new Date(item.timestamp).toLocaleTimeString('sk-SK')}</td>
                                            <td className="py-5 px-6 font-mono font-bold text-[#4169E1] text-lg">{item.location}</td>
                                            <td className="py-5 px-6 font-mono text-white text-base">{item.partNumber}</td>
                                            <td className={`py-5 px-6 font-mono text-base ${item.batch.includes('[') ? 'text-red-500 font-bold' : 'text-gray-500'}`}>
                                                {item.batch}
                                            </td>
                                            <td className="py-5 px-6 font-black text-white text-right font-mono text-xl">{item.quantity}</td>
                                            <td className="py-5 px-6 text-center w-24">
                                                <button 
                                                    onClick={() => handleDeleteItem(item.id)} 
                                                    className="w-16 h-16 flex items-center justify-center rounded-lg bg-red-900/30 text-red-500 hover:bg-red-800 hover:text-white border border-red-800/50 transition-all active:scale-90"
                                                >
                                                    <TrashIcon className="w-8 h-8" />
                                                </button>
                                            </td>
                                        </tr>
                                    ))
                                ) : (
                                    <tr><td colSpan={6} className="py-16 text-center text-gray-600 italic font-bold text-lg">{t('inv_empty_list')}</td></tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {confirmModal.isOpen && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setConfirmModal(prev => ({...prev, isOpen: false}))}>
                    <div className="bg-gray-800 border-2 border-slate-700 rounded-2xl shadow-2xl w-full max-w-md p-8 relative" onClick={e => e.stopPropagation()}>
                        <div className="text-center mb-8">
                            <h3 className={`text-2xl font-black mb-3 uppercase tracking-tighter ${confirmModal.type === 'danger' ? 'text-red-500' : 'text-amber-500'}`}>
                                {confirmModal.title}
                            </h3>
                            <div className="text-gray-300 text-base leading-relaxed">
                                {confirmModal.message}
                            </div>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => setConfirmModal(prev => ({...prev, isOpen: false}))} className="flex-1 py-4 bg-gray-700 text-gray-300 rounded-xl hover:bg-gray-600 font-black transition-all uppercase text-xs">
                                {t('btn_cancel')}
                            </button>
                            <button onClick={confirmModal.onConfirm} className={`flex-1 py-4 text-white rounded-xl font-black transition-all shadow-xl uppercase text-xs border-2 ${confirmModal.type === 'danger' ? 'bg-red-600 hover:bg-red-700 border-red-500' : 'bg-amber-600 hover:bg-amber-700 border-amber-500'}`}>
                                {t('btn_confirm')}
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default InventoryTab;

import { useState, useEffect, useRef, useCallback } from 'react';
import { db } from '../../firebase';
import { collection, onSnapshot, query, where, limit, doc, getDocs } from 'firebase/firestore';
import { Task, PriorityLevel, Notification } from '../../types/appTypes';
import { PRIORITY_ORDER } from '../../constants/uiConstants';
import { taskService } from '../../services/taskService';

export const useTaskData = (
    isAuthenticated: boolean, 
    checkPermission: (perm: string) => boolean,
    onAddNotification: (n: Partial<Notification>) => void
) => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [draftTasks, setDraftTasks] = useState<Task[]>([]);
  const isFirstLoad = useRef(true);
  const checkPermissionRef = useRef(checkPermission);

  useEffect(() => { checkPermissionRef.current = checkPermission; }, [checkPermission]);

  // 1. LISTENER PRE ŽIVÉ ÚLOHY
  useEffect(() => {
    if (!isAuthenticated) return;
    const threshold = Date.now() - (3 * 24 * 60 * 60 * 1000);
    const q = query(collection(db, 'tasks'), where('createdAt', '>=', threshold), limit(300)); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));

      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added' && checkPermissionRef.current('perm_play_sound')) {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3').play().catch(() => {});
                  }
              }
          });
      }
      isFirstLoad.current = false;

      setTasks(newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) return (b.completedAt || 0) - (a.completedAt || 0);
        if (a.isManualBlocked !== b.isManualBlocked) return (a.isManualBlocked ? 1 : 0) - (b.isManualBlocked ? 1 : 0);
        const pA = PRIORITY_ORDER[a.priority || 'NORMAL'], pB = PRIORITY_ORDER[b.priority || 'NORMAL'];
        return pA !== pB ? pA - pB : (a.createdAt || 0) - (b.createdAt || 0);
      }));
    });
  }, [isAuthenticated]);

  // 2. LISTENER PRE DRAFT
  useEffect(() => {
    return onSnapshot(doc(db, 'settings', 'draft'), (s) => {
      setDraftTasks(s.exists() ? (s.data().data || []) : []);
    });
  }, []);

  // 3. WRAPPERS PRE SERVICE
  const onAddTask = useCallback(async (pn: string, wp: string | null, qty: string, unit: string, prio: PriorityLevel, isLog?: boolean, note?: string, isProd?: boolean, src?: string | null, tgt?: string | null) => {
    const user = localStorage.getItem('app_user') || 'Unknown';

    const taskData: any = {
        partNumber: pn || '',
        text: pn || '',
        workplace: wp || '',
        quantity: qty || '0',
        quantityUnit: unit || 'pcs',
        priority: prio || 'NORMAL',
        isLogistics: !!isLog,
        isProduction: !!isProd,
        createdBy: user,
        note: note || '',
        plate: isLog ? (note || '') : '',
        sourceSectorId: src || null,
        targetSectorId: tgt || null
    };

    // FIX: Ak ide o inventúru, automaticky nastaviť riešiteľa pre odomknutie UI
    if (pn === "Počítanie zásob") {
        taskData.isInProgress = true;
        taskData.inProgressBy = user;
        taskData.startedAt = Date.now();
    }

    return taskService.addTask(taskData);
  }, []);

  const onUpdateTask = useCallback((id: string, up: Partial<Task>) => taskService.updateTask(id, up), []);
  const onDeleteTask = useCallback((id: string) => taskService.deleteTask(id), []);

  const onToggleTask = useCallback(async (id: string, sectorId?: string) => {
      const task = tasks.find(t => t.id === id);
      if (!task) return;
      const user = localStorage.getItem('app_user') || 'Unknown';
      const updates: any = { isDone: !task.isDone, completedAt: !task.isDone ? Date.now() : null, completedBy: !task.isDone ? user : null, status: !task.isDone ? 'completed' : 'open' };
      if (!task.isDone && sectorId) updates.pickedFromSectorId = sectorId;
      return taskService.updateTask(id, updates);
  }, [tasks]);

  const onToggleMissing = useCallback(async (id: string, reason?: string) => {
      const task = tasks.find(t => t.id === id);
      if (!task) return;
      const user = localStorage.getItem('app_user') || 'Unknown';
      const isMarking = !task.isMissing;
      const updates: any = { isMissing: isMarking, missingReason: isMarking ? (reason || 'Unknown') : null, missingReportedBy: isMarking ? user : null, isInProgress: false, inProgressBy: null };
      if (isMarking && task.createdBy) {
          onAddNotification({ partNumber: task.partNumber, reason: `CHÝBA: ${reason}`, reportedBy: user, targetUser: task.createdBy });
      }
      return taskService.updateTask(id, updates);
  }, [tasks, onAddNotification]);

  const onSetInProgress = useCallback(async (id: string) => {
      const task = tasks.find(t => t.id === id);
      if (!task) return;
      const user = localStorage.getItem('app_user') || 'Unknown';
      return taskService.updateTask(id, task.isInProgress ? { isInProgress: false, inProgressBy: null } : { isInProgress: true, inProgressBy: user, startedAt: Date.now() });
  }, [tasks]);

  const onToggleBlock = useCallback(async (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    const user = localStorage.getItem('app_user') || 'Unknown';
    const isCurrentlyBlocked = !!task.isBlocked;
    return taskService.updateTask(id, {
        isBlocked: !isCurrentlyBlocked,
        blockedBy: !isCurrentlyBlocked ? user : null
    });
  }, [tasks]);

  const onExhaustSearch = useCallback(async (id: string) => {
    const user = localStorage.getItem('app_user') || 'Unknown';
    return taskService.updateTask(id, {
        searchExhausted: true,
        searchedBy: user
    });
  }, []);

  const onAddNote = useCallback(async (id: string, note: string) => {
    return taskService.updateTask(id, { note });
  }, []);

  const onMarkAsIncorrect = useCallback(async (id: string) => {
    const user = localStorage.getItem('app_user') || 'Unknown';
    return taskService.updateTask(id, {
        isDone: true,
        status: 'incorrectly_entered',
        completedAt: Date.now(),
        completedBy: user,
        isInProgress: false,
        inProgressBy: null
    });
  }, []);

  const onStartAudit = useCallback((id: string) => taskService.updateTask(id, { isAuditInProgress: true, auditBy: localStorage.getItem('app_user'), isInProgress: false, inProgressBy: null }), []);
  const onFinishAudit = useCallback((id: string, res: 'found' | 'missing', note: string) => {
      const task = tasks.find(t => t.id === id);
      if (task) taskService.finishAudit(task, res, note, localStorage.getItem('app_user') || 'Unknown', onAddNotification);
  }, [tasks, onAddNotification]);

  return {
    tasks, draftTasks, onAddTask, onUpdateTask, onDeleteTask, onToggleTask, onToggleMissing, onSetInProgress, onStartAudit, onFinishAudit, onToggleBlock, onExhaustSearch, onAddNote, onMarkAsIncorrect,
    onToggleManualBlock: (id: string) => { const t = tasks.find(x => x.id === id); if(t) taskService.toggleManualBlock(t); },
    onDailyClosing: taskService.dailyClosing, onWeeklyClosing: taskService.weeklyClosing,
    fetchSanons: async () => (await getDocs(collection(db, 'sanony'))).docs.map(d => d.data())
  };
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { useLanguage } from '../LanguageContext';
import PartNumberInput from '../PartNumberInput';
import { Task, PriorityLevel } from '../../types/appTypes';

interface ScannedItem {
    id: string;
    location: string;
    partNumber: string;
    batch: string;
    quantity: string;
    timestamp: number;
    worker: string;
}

interface InventoryTabProps {
    currentUser: string;
    tasks: Task[];
    onAddTask: (pn: string, wp: string | null, qty: string | null, unit: string | null, prio: PriorityLevel, isLogistics?: boolean) => void;
    onUpdateTask: (id: string, updates: Partial<Task>) => void;
    onToggleTask: (id: string) => void;
    onDeleteTask: (id: string) => void;
    hasPermission: (perm: string) => boolean;
    parts: string[];
    onRequestPart: (part: string) => Promise<boolean>;
    resolveName: (username?: string | null) => string;
}

declare var XLSX: any;

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
);

const InventoryTab: React.FC<InventoryTabProps> = ({ currentUser, tasks, onAddTask, onUpdateTask, onDeleteTask, parts, onRequestPart, resolveName }) => {
    const { t, language } = useLanguage();

    const locationRef = useRef<HTMLInputElement>(null);
    const partRef = useRef<HTMLInputElement>(null);
    const batchRef = useRef<HTMLInputElement>(null);
    const quantityRef = useRef<HTMLInputElement>(null);

    const [location, setLocation] = useState('');
    const [partNumber, setPartNumber] = useState('');
    const [batch, setBatch] = useState('');
    const [isBatchMissing, setIsBatchMissing] = useState(false);
    const [quantity, setQuantity] = useState('');
    const [scannedItems, setScannedItems] = useState<ScannedItem[]>([]);

    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: React.ReactNode;
        onConfirm: () => void;
        type: 'danger' | 'warning';
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => {},
        type: 'danger'
    });

    const activeInventoryTask = useMemo(() => {
        // FIX: Hľadáme úlohu, ktorú tento user BUĎ vytvoril, ALEBO ju má v riešení
        return (tasks || []).find(t => 
            t.partNumber === "Počítanie zásob" && 
            !t.isDone && 
            (t.inProgressBy === currentUser || t.createdBy === currentUser)
        );
    }, [tasks, currentUser]);

    // Načítanie dát viazané na konkrétne ID úlohy
    useEffect(() => {
        if (!activeInventoryTask) {
            setScannedItems([]);
            return;
        }

        const storageKey = `inventory_scans_${activeInventoryTask.id}`;
        const saved = localStorage.getItem(storageKey);

        if (saved) {
            try {
                const parsed = JSON.parse(saved);
                if (Array.isArray(parsed)) {
                    setScannedItems(parsed);
                }
            } catch (e) {
                console.error("Failed to parse inventory scans", e);
            }
        } else {
            // Ak neexistujú dáta pre túto úlohu, skúsime starý kľúč (migrácia)
            const legacySaved = localStorage.getItem('inventory_scans');
            if (legacySaved) {
                try {
                    const parsed = JSON.parse(legacySaved);
                    setScannedItems(parsed);
                    localStorage.setItem(storageKey, legacySaved);
                    localStorage.removeItem('inventory_scans');
                } catch(e) {}
            } else {
                setScannedItems([]);
            }
        }
    }, [activeInventoryTask?.id]);

    // Ukladanie dát pri zmene zoznamu
    useEffect(() => {
        if (activeInventoryTask && scannedItems.length >= 0) {
            const storageKey = `inventory_scans_${activeInventoryTask.id}`;
            localStorage.setItem(storageKey, JSON.stringify(scannedItems));
        }
    }, [scannedItems, activeInventoryTask?.id]);

    const handleStartInventory = () => {
        onAddTask("Počítanie zásob", "Inventúra", "0", "pallet", "NORMAL", true);
    };

    const handleAddItem = () => {
        const normalizedQty = quantity.replace(',', '.').trim();
        const isLocEmpty = !location.trim();
        const isPartEmpty = !partNumber.trim();
        const isQtyEmpty = !normalizedQty || isNaN(Number(normalizedQty));
        const isBatchRequiredAndEmpty = !isBatchMissing && !batch.trim();

        if (isLocEmpty || isPartEmpty || isQtyEmpty || isBatchRequiredAndEmpty) {
            const missingFields = [];
            if (isLocEmpty) missingFields.push(t('inv_th_loc'));
            if (isPartEmpty) missingFields.push(t('inv_th_part'));
            if (isBatchRequiredAndEmpty) missingFields.push(t('inv_th_batch'));
            if (isQtyEmpty) missingFields.push(t('inv_th_qty'));

            const errorMsg = language === 'sk' 
                ? `Chyba: Vyplňte ${missingFields.join(', ')}.` 
                : `Error: Fill ${missingFields.join(', ')}.`;

            alert(errorMsg);
            return;
        }

        const newItem: ScannedItem = {
            id: crypto.randomUUID(),
            location: location.trim().toUpperCase(),
            partNumber: partNumber.trim().toUpperCase(),
            batch: isBatchMissing ? `[${t('inv_missing_label').toUpperCase()}]` : batch.trim(),
            quantity: normalizedQty,
            timestamp: Date.now(),
            worker: currentUser
        };

        setScannedItems(prev => [newItem, ...prev]);

        // Reset polí okrem lokácie (pre efektívne skenovanie regálu)
        setPartNumber(''); 
        setBatch(''); 
        setIsBatchMissing(false);
        setQuantity('');

        // Vrátenie focusu na diel
        setTimeout(() => partRef.current?.focus(), 50);
    };

    const handleDeleteItem = (id: string) => {
        setScannedItems(prev => prev.filter(item => item.id !== id));
    };

    const handleClearAll = () => {
        setConfirmModal({
            isOpen: true,
            title: t('confirm_clear_all'),
            message: t('confirm_clear_all_msg'),
            type: 'danger',
            onConfirm: () => {
                setScannedItems([]);
                if (activeInventoryTask) {
                    localStorage.removeItem(`inventory_scans_${activeInventoryTask.id}`);
                }
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleCancelInventory = () => {
        setConfirmModal({
            isOpen: true,
            title: language === 'sk' ? "Zrušiť reláciu inventúry?" : "Cancel inventory session?",
            message: language === 'sk' 
                ? "Dáta tejto relácie budú natrvalo odstránené z pamäte tabletu." 
                : "Data for this session will be permanently removed from tablet storage.",
            type: 'danger',
            onConfirm: () => {
                if (activeInventoryTask) {
                    localStorage.removeItem(`inventory_scans_${activeInventoryTask.id}`);
                    onDeleteTask(activeInventoryTask.id);
                }
                setScannedItems([]);
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleExportAndFinish = () => {
        if (scannedItems.length === 0) {
            alert(language === 'sk' ? "Nemožno ukončiť prázdnu inventúru." : "Cannot finish empty inventory.");
            return;
        }

        handleExport();

        if (activeInventoryTask) {
            onUpdateTask(activeInventoryTask.id, { 
                isDone: true, 
                status: 'completed', 
                completedBy: currentUser,
                completedAt: Date.now(),
                isInProgress: false,
                inProgressBy: null,
                quantity: scannedItems.length.toString()
            });
            localStorage.removeItem(`inventory_scans_${activeInventoryTask.id}`);
        }
        setScannedItems([]);
    };

    const handleExport = () => {
        if (scannedItems.length === 0 || typeof XLSX === 'undefined') return;

        const data = scannedItems.map(item => ({
            "Dátum": new Date(item.timestamp).toLocaleDateString('sk-SK'),
            "Skladník": resolveName(item.worker),
            "Lokácia": item.location,
            "Číslo dielu": item.partNumber,
            "Batch": item.batch,
            "Množstvo": item.quantity.replace('.', ','),
            "Čas": new Date(item.timestamp).toLocaleTimeString('sk-SK')
        }));

        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Inventúra");
        XLSX.writeFile(wb, `Inventura_${activeInventoryTask?.id || 'export'}_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    const toggleBatchMissing = () => {
        const newState = !isBatchMissing;
        setIsBatchMissing(newState);
        if (newState) {
            setBatch(`[${t('inv_missing_label').toUpperCase()}]`);
            setTimeout(() => quantityRef.current?.focus(), 50);
        } else {
            setBatch('');
            setTimeout(() => batchRef.current?.focus(), 50);
        }
    };

    const inputBaseClass = "w-full h-12 bg-gray-700 border border-gray-600 rounded-lg px-4 text-white text-base placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#4169E1] transition-all font-mono uppercase text-base";
    const dangerButtonClass = "bg-red-900/40 hover:bg-red-800 text-red-100 px-6 py-5 rounded-xl text-base font-black border-2 border-red-800/50 shadow-lg transition-all active:scale-95 uppercase tracking-wider flex items-center justify-center gap-2";

    return (
        <div className="max-w-4xl mx-auto space-y-8 pb-20 animate-fade-in">
            <div className="bg-gray-800 p-6 sm:p-8 rounded-xl shadow-lg border border-gray-700">
                {!activeInventoryTask ? (
                    <div className="flex flex-col items-center justify-center py-12 space-y-8">
                        <div className="text-center">
                            <h2 className="text-3xl font-bold text-white uppercase tracking-widest">{t('inv_not_started')}</h2>
                            <p className="text-gray-400 text-base mt-3">{t('inv_start_hint')}</p>
                        </div>
                        <button 
                            onClick={handleStartInventory}
                            className="bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-8 px-16 rounded-2xl shadow-[0_0_25px_rgba(65,105,225,0.4)] transition-all active:scale-95 uppercase tracking-[0.25em] text-2xl border-2 border-[#5a81f3]"
                        >
                            📋 {t('inv_start_btn')}
                        </button>
                    </div>
                ) : (
                    <>
                        <div className="flex justify-between items-start sm:items-center mb-10 border-b border-gray-700 pb-6">
                            <div>
                                <h1 className="text-4xl font-extrabold text-[#4169E1] uppercase tracking-widest leading-none">
                                    {t('tab_inventory')}
                                </h1>
                                <div className="flex gap-6 items-center mt-3">
                                    <span className="bg-[#4169E1]/20 text-[#4169E1] text-xs font-black px-3 py-1 rounded-md border border-[#4169E1]/40 animate-pulse uppercase">{t('inv_active_session')}</span>
                                    <p className="text-xs text-gray-500 uppercase font-mono">
                                        {t('inv_items_count')}: <span className="text-white font-bold">{scannedItems.length}</span>
                                    </p>
                                </div>
                            </div>

                            <button 
                                onClick={handleCancelInventory}
                                className={dangerButtonClass.replace('px-6 py-5', 'px-5 py-3 text-xs')}
                            >
                                🛑 {t('inv_cancel_session')}
                            </button>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_loc_label')}</label>
                                <input 
                                    ref={locationRef}
                                    type="text"
                                    value={location}
                                    onChange={(e) => setLocation(e.target.value.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && partRef.current?.focus()}
                                    placeholder="NAPR. MA123"
                                    className={inputBaseClass}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_th_part')}</label>
                                <PartNumberInput 
                                    inputRef={partRef}
                                    parts={parts}
                                    onPartSelect={(p) => { if(p) { setPartNumber(p); setTimeout(() => batchRef.current?.focus(), 50); } }}
                                    onInputChange={(val) => setPartNumber(val.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && batchRef.current?.focus()}
                                    placeholder={t('part_placeholder')}
                                    value={partNumber}
                                    onRequestPart={onRequestPart}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_batch_label')}</label>
                                <div className="flex gap-3">
                                    <input 
                                        ref={batchRef}
                                        type="text"
                                        inputMode="numeric"
                                        readOnly={isBatchMissing}
                                        value={batch}
                                        onChange={(e) => {
                                            if (!isBatchMissing) {
                                                const val = e.target.value.replace(/[^0-9]/g, '').slice(0, 10);
                                                setBatch(val);
                                            }
                                        }}
                                        onKeyDown={(e) => e.key === 'Enter' && quantityRef.current?.focus()}
                                        placeholder={isBatchMissing ? '' : "BATCH / LOT"}
                                        className={`${inputBaseClass.replace('w-full', 'w-1/2')} ${isBatchMissing ? 'text-red-500 border-red-900/50 bg-red-900/10' : ''}`}
                                    />
                                    <button 
                                        type="button"
                                        onClick={toggleBatchMissing}
                                        className={`w-1/2 h-12 rounded-lg border-2 font-black uppercase text-xs text-white transition-all flex items-center justify-center gap-2 ${isBatchMissing ? 'bg-red-600 border-red-500 shadow-lg' : 'bg-[#4169E1]/20 border-[#4169E1] hover:bg-[#4169E1]/40'}`}
                                    >
                                        🏷️ {t('inv_missing_label')}
                                    </button>
                                </div>
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_qty_label')}</label>
                                <input 
                                    ref={quantityRef}
                                    type="text"
                                    inputMode="decimal"
                                    value={quantity}
                                    onChange={(e) => setQuantity(e.target.value.replace(/[^0-9.,]/g, '').slice(0, 10))}
                                    onKeyDown={(e) => e.key === 'Enter' && handleAddItem()}
                                    placeholder="0"
                                    className={`${inputBaseClass} font-black text-lg`}
                                />
                            </div>
                        </div>

                        <button 
                            onClick={handleAddItem}
                            className="w-full mt-10 bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-6 rounded-2xl shadow-xl transition-all active:scale-95 uppercase tracking-widest text-xl border-2 border-[#5a81f3]"
                        >
                            {t('inv_add_btn')}
                        </button>
                    </>
                )}
            </div>

            {activeInventoryTask && (
                <div className="bg-gray-800 rounded-xl shadow-lg border border-gray-700 overflow-hidden">
                    <div className="p-5 sm:p-8 border-b border-gray-700 bg-gray-900/50 flex flex-col sm:flex-row justify-between items-center gap-8">
                        <div className="flex items-center gap-6">
                            <h3 className="text-gray-400 font-black uppercase text-base tracking-[0.2em] leading-none">
                                {t('inv_summary_title')}
                            </h3>
                            <span className="bg-[#4169E1]/20 text-white border-2 border-[#4169E1] text-2xl px-5 py-2 rounded-xl font-black font-mono leading-none shadow-lg">
                                {scannedItems.length}
                            </span>
                        </div>
                        <div className="flex flex-wrap w-full sm:w-auto gap-4">
                            <button 
                                onClick={handleClearAll} 
                                className={dangerButtonClass}
                            >
                                {language === 'sk' ? 'Zmazať všetko' : 'Clear all'}
                            </button>
                            <button 
                                onClick={handleExportAndFinish}
                                className="flex-1 sm:flex-none bg-green-700 hover:bg-green-600 text-white px-10 py-5 rounded-xl text-lg font-black shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 border-2 border-green-500 uppercase tracking-widest"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                                </svg>
                                {t('inv_finish_btn')}
                            </button>
                        </div>
                    </div>

                    <div className="overflow-x-auto custom-scrollbar">
                        <table className="w-full text-left text-base border-collapse">
                            <thead className="bg-gray-900/30 text-gray-500 text-xs font-black uppercase tracking-widest border-b border-gray-700">
                                <tr>
                                    <th className="py-5 px-6">{t('inv_th_time')}</th>
                                    <th className="py-5 px-6">{t('inv_th_loc')}</th>
                                    <th className="py-5 px-6">{t('inv_th_part')}</th>
                                    <th className="py-5 px-6">{t('inv_th_batch')}</th>
                                    <th className="py-5 px-6 text-right">{t('inv_th_qty')}</th>
                                    <th className="py-5 px-6 text-center"></th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-700/50">
                                {scannedItems.length > 0 ? (
                                    scannedItems.map(item => (
                                        <tr key={item.id} className="text-gray-300 hover:bg-gray-700/30 transition-colors group">
                                            <td className="py-5 px-6 text-xs text-gray-500 font-mono whitespace-nowrap">{new Date(item.timestamp).toLocaleTimeString('sk-SK')}</td>
                                            <td className="py-5 px-6 font-mono font-bold text-[#4169E1] text-lg">{item.location}</td>
                                            <td className="py-5 px-6 font-mono text-white text-base">{item.partNumber}</td>
                                            <td className={`py-5 px-6 font-mono text-base ${item.batch.includes('[') ? 'text-red-500 font-bold' : 'text-gray-500'}`}>
                                                {item.batch}
                                            </td>
                                            <td className="py-5 px-6 font-black text-white text-right font-mono text-xl">{item.quantity}</td>
                                            <td className="py-5 px-6 text-center w-24">
                                                <button 
                                                    onClick={() => handleDeleteItem(item.id)} 
                                                    className="w-16 h-16 flex items-center justify-center rounded-lg bg-red-900/30 text-red-500 hover:bg-red-800 hover:text-white border border-red-800/50 transition-all active:scale-90"
                                                >
                                                    <TrashIcon className="w-8 h-8" />
                                                </button>
                                            </td>
                                        </tr>
                                    ))
                                ) : (
                                    <tr><td colSpan={6} className="py-16 text-center text-gray-600 italic font-bold text-lg">{t('inv_empty_list')}</td></tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {confirmModal.isOpen && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setConfirmModal(prev => ({...prev, isOpen: false}))}>
                    <div className="bg-gray-800 border-2 border-slate-700 rounded-2xl shadow-2xl w-full max-w-md p-8 relative" onClick={e => e.stopPropagation()}>
                        <div className="text-center mb-8">
                            <h3 className={`text-2xl font-black mb-3 uppercase tracking-tighter ${confirmModal.type === 'danger' ? 'text-red-500' : 'text-amber-500'}`}>
                                {confirmModal.title}
                            </h3>
                            <div className="text-gray-300 text-base leading-relaxed">
                                {confirmModal.message}
                            </div>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => setConfirmModal(prev => ({...prev, isOpen: false}))} className="flex-1 py-4 bg-gray-700 text-gray-300 rounded-xl hover:bg-gray-600 font-black transition-all uppercase text-xs">
                                {t('btn_cancel')}
                            </button>
                            <button onClick={confirmModal.onConfirm} className={`flex-1 py-4 text-white rounded-xl font-black transition-all shadow-xl uppercase text-xs border-2 ${confirmModal.type === 'danger' ? 'bg-red-600 hover:bg-red-700 border-red-500' : 'bg-amber-600 hover:bg-amber-700 border-amber-500'}`}>
                                {t('btn_confirm')}
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default InventoryTab;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { useLanguage } from '../LanguageContext';
import PartNumberInput from '../PartNumberInput';
import { Task, PriorityLevel } from '../../types/appTypes';

interface ScannedItem {
    id: string;
    location: string;
    partNumber: string;
    batch: string;
    quantity: string;
    timestamp: number;
    worker: string;
}

interface InventoryTabProps {
    currentUser: string;
    tasks: Task[];
    onAddTask: (pn: string, wp: string | null, qty: string | null, unit: string | null, prio: PriorityLevel, isLogistics?: boolean) => void;
    onUpdateTask: (id: string, updates: Partial<Task>) => void;
    onToggleTask: (id: string) => void;
    onDeleteTask: (id: string) => void;
    hasPermission: (perm: string) => boolean;
    parts: string[];
    onRequestPart: (part: string) => Promise<boolean>;
    resolveName: (username?: string | null) => string;
}

declare var XLSX: any;

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
);

const InventoryTab: React.FC<InventoryTabProps> = ({ currentUser, tasks, onAddTask, onUpdateTask, onDeleteTask, parts, onRequestPart, resolveName }) => {
    const { t, language } = useLanguage();

    const locationRef = useRef<HTMLInputElement>(null);
    const partRef = useRef<HTMLInputElement>(null);
    const batchRef = useRef<HTMLInputElement>(null);
    const quantityRef = useRef<HTMLInputElement>(null);

    const [location, setLocation] = useState('');
    const [partNumber, setPartNumber] = useState('');
    const [batch, setBatch] = useState('');
    const [isBatchMissing, setIsBatchMissing] = useState(false);
    const [quantity, setQuantity] = useState('');
    const [scannedItems, setScannedItems] = useState<ScannedItem[]>([]);

    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: React.ReactNode;
        onConfirm: () => void;
        type: 'danger' | 'warning';
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => {},
        type: 'danger'
    });

    const activeInventoryTask = useMemo(() => {
        return (tasks || []).find(t => 
            t.partNumber === "Počítanie zásob" && 
            !t.isDone && 
            (t.inProgressBy === currentUser || t.createdBy === currentUser)
        );
    }, [tasks, currentUser]);

    // Focus na lokáciu pri spustení novej relácie
    useEffect(() => {
        if (activeInventoryTask) {
            setTimeout(() => locationRef.current?.focus(), 100);
        }
    }, [activeInventoryTask?.id]);

    // Načítanie dát viazané na konkrétne ID úlohy
    useEffect(() => {
        if (!activeInventoryTask) {
            setScannedItems([]);
            return;
        }

        const storageKey = `inventory_scans_${activeInventoryTask.id}`;
        const saved = localStorage.getItem(storageKey);

        if (saved) {
            try {
                const parsed = JSON.parse(saved);
                if (Array.isArray(parsed)) {
                    setScannedItems(parsed);
                }
            } catch (e) {
                console.error("Failed to parse inventory scans", e);
            }
        } else {
            const legacySaved = localStorage.getItem('inventory_scans');
            if (legacySaved) {
                try {
                    const parsed = JSON.parse(legacySaved);
                    setScannedItems(parsed);
                    localStorage.setItem(storageKey, legacySaved);
                    localStorage.removeItem('inventory_scans');
                } catch(e) {}
            } else {
                setScannedItems([]);
            }
        }
    }, [activeInventoryTask?.id]);

    // Ukladanie dát pri zmene zoznamu
    useEffect(() => {
        if (activeInventoryTask && scannedItems.length >= 0) {
            const storageKey = `inventory_scans_${activeInventoryTask.id}`;
            localStorage.setItem(storageKey, JSON.stringify(scannedItems));
        }
    }, [scannedItems, activeInventoryTask?.id]);

    const handleStartInventory = () => {
        onAddTask("Počítanie zásob", "Inventúra", "0", "pallet", "NORMAL", true);
    };

    const handleAddItem = () => {
        const normalizedQty = quantity.replace(',', '.').trim();
        const isLocEmpty = !location.trim();
        const isPartEmpty = !partNumber.trim();
        const isQtyEmpty = !normalizedQty || isNaN(Number(normalizedQty));
        const isBatchRequiredAndEmpty = !isBatchMissing && !batch.trim();

        if (isLocEmpty || isPartEmpty || isQtyEmpty || isBatchRequiredAndEmpty) {
            const missingFields = [];
            if (isLocEmpty) missingFields.push(t('inv_th_loc'));
            if (isPartEmpty) missingFields.push(t('inv_th_part'));
            if (isBatchRequiredAndEmpty) missingFields.push(t('inv_th_batch'));
            if (isQtyEmpty) missingFields.push(t('inv_th_qty'));

            const errorMsg = language === 'sk' 
                ? `Chyba: Vyplňte ${missingFields.join(', ')}.` 
                : `Error: Fill ${missingFields.join(', ')}.`;

            alert(errorMsg);
            return;
        }

        const newItem: ScannedItem = {
            id: crypto.randomUUID(),
            location: location.trim().toUpperCase(),
            partNumber: partNumber.trim().toUpperCase(),
            batch: isBatchMissing ? `[${t('inv_missing_label').toUpperCase()}]` : batch.trim(),
            quantity: normalizedQty,
            timestamp: Date.now(),
            worker: currentUser
        };

        setScannedItems(prev => [newItem, ...prev]);

        // Reset všetkých polí pre novú položku (vrátene lokácie)
        setLocation('');
        setPartNumber(''); 
        setBatch(''); 
        setIsBatchMissing(false);
        setQuantity('');

        // Vrátenie focusu na Lokáciu pre ďalší sken
        setTimeout(() => locationRef.current?.focus(), 50);
    };

    const handleDeleteItem = (id: string) => {
        setScannedItems(prev => prev.filter(item => item.id !== id));
    };

    const handleClearAll = () => {
        setConfirmModal({
            isOpen: true,
            title: t('confirm_clear_all'),
            message: t('confirm_clear_all_msg'),
            type: 'danger',
            onConfirm: () => {
                setScannedItems([]);
                if (activeInventoryTask) {
                    localStorage.removeItem(`inventory_scans_${activeInventoryTask.id}`);
                }
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleCancelInventory = () => {
        setConfirmModal({
            isOpen: true,
            title: language === 'sk' ? "Zrušiť reláciu inventúry?" : "Cancel inventory session?",
            message: language === 'sk' 
                ? "Dáta tejto relácie budú natrvalo odstránené z pamäte tabletu." 
                : "Data for this session will be permanently removed from tablet storage.",
            type: 'danger',
            onConfirm: () => {
                if (activeInventoryTask) {
                    localStorage.removeItem(`inventory_scans_${activeInventoryTask.id}`);
                    onDeleteTask(activeInventoryTask.id);
                }
                setScannedItems([]);
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleExportAndFinish = () => {
        if (scannedItems.length === 0) {
            alert(language === 'sk' ? "Nemožno ukončiť prázdnu inventúru." : "Cannot finish empty inventory.");
            return;
        }

        handleExport();

        if (activeInventoryTask) {
            onUpdateTask(activeInventoryTask.id, { 
                isDone: true, 
                status: 'completed', 
                completedBy: currentUser,
                completedAt: Date.now(),
                isInProgress: false,
                inProgressBy: null,
                quantity: scannedItems.length.toString()
            });
            localStorage.removeItem(`inventory_scans_${activeInventoryTask.id}`);
        }
        setScannedItems([]);
    };

    const handleExport = () => {
        if (scannedItems.length === 0 || typeof XLSX === 'undefined') return;

        const data = scannedItems.map(item => ({
            "Dátum": new Date(item.timestamp).toLocaleDateString('sk-SK'),
            "Skladník": resolveName(item.worker),
            "Lokácia": item.location,
            "Číslo dielu": item.partNumber,
            "Batch": item.batch,
            "Množstvo": item.quantity.replace('.', ','),
            "Čas": new Date(item.timestamp).toLocaleTimeString('sk-SK')
        }));

        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Inventúra");
        XLSX.writeFile(wb, `Inventura_${activeInventoryTask?.id || 'export'}_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    const toggleBatchMissing = () => {
        const newState = !isBatchMissing;
        setIsBatchMissing(newState);
        if (newState) {
            setBatch(`[${t('inv_missing_label').toUpperCase()}]`);
            setTimeout(() => quantityRef.current?.focus(), 50);
        } else {
            setBatch('');
            setTimeout(() => batchRef.current?.focus(), 50);
        }
    };

    const inputBaseClass = "w-full h-12 bg-gray-700 border border-gray-600 rounded-lg px-4 text-white text-base placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#4169E1] transition-all font-mono uppercase text-base";
    const dangerButtonClass = "bg-red-900/40 hover:bg-red-800 text-red-100 px-6 py-5 rounded-xl text-base font-black border-2 border-red-800/50 shadow-lg transition-all active:scale-95 uppercase tracking-wider flex items-center justify-center gap-2";

    return (
        <div className="max-w-4xl mx-auto space-y-8 pb-20 animate-fade-in">
            <div className="bg-gray-800 p-6 sm:p-8 rounded-xl shadow-lg border border-gray-700">
                {!activeInventoryTask ? (
                    <div className="flex flex-col items-center justify-center py-12 space-y-8">
                        <div className="text-center">
                            <h2 className="text-3xl font-bold text-white uppercase tracking-widest">{t('inv_not_started')}</h2>
                            <p className="text-gray-400 text-base mt-3">{t('inv_start_hint')}</p>
                        </div>
                        <button 
                            onClick={handleStartInventory}
                            className="bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-8 px-16 rounded-2xl shadow-[0_0_25px_rgba(65,105,225,0.4)] transition-all active:scale-95 uppercase tracking-[0.25em] text-2xl border-2 border-[#5a81f3]"
                        >
                            📋 {t('inv_start_btn')}
                        </button>
                    </div>
                ) : (
                    <>
                        <div className="flex justify-between items-start sm:items-center mb-10 border-b border-gray-700 pb-6">
                            <div>
                                <h1 className="text-4xl font-extrabold text-[#4169E1] uppercase tracking-widest leading-none">
                                    {t('tab_inventory')}
                                </h1>
                                <div className="flex gap-6 items-center mt-3">
                                    <span className="bg-[#4169E1]/20 text-[#4169E1] text-xs font-black px-3 py-1 rounded-md border border-[#4169E1]/40 animate-pulse uppercase">{t('inv_active_session')}</span>
                                    <p className="text-xs text-gray-500 uppercase font-mono">
                                        {t('inv_items_count')}: <span className="text-white font-bold">{scannedItems.length}</span>
                                    </p>
                                </div>
                            </div>

                            <button 
                                onClick={handleCancelInventory}
                                className={dangerButtonClass.replace('px-6 py-5', 'px-5 py-3 text-xs')}
                            >
                                🛑 {t('inv_cancel_session')}
                            </button>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_loc_label')}</label>
                                <input 
                                    ref={locationRef}
                                    type="text"
                                    value={location}
                                    onChange={(e) => setLocation(e.target.value.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && partRef.current?.focus()}
                                    placeholder="NAPR. MA123"
                                    className={inputBaseClass}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_th_part')}</label>
                                <PartNumberInput 
                                    inputRef={partRef}
                                    parts={parts}
                                    onPartSelect={(p) => { if(p) { setPartNumber(p); setTimeout(() => batchRef.current?.focus(), 50); } }}
                                    onInputChange={(val) => setPartNumber(val.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && batchRef.current?.focus()}
                                    placeholder={t('part_placeholder')}
                                    value={partNumber}
                                    onRequestPart={onRequestPart}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_batch_label')}</label>
                                <div className="flex gap-3">
                                    <input 
                                        ref={batchRef}
                                        type="text"
                                        inputMode="numeric"
                                        readOnly={isBatchMissing}
                                        value={batch}
                                        onChange={(e) => {
                                            if (!isBatchMissing) {
                                                const val = e.target.value.replace(/[^0-9]/g, '').slice(0, 10);
                                                setBatch(val);
                                            }
                                        }}
                                        onKeyDown={(e) => e.key === 'Enter' && quantityRef.current?.focus()}
                                        placeholder={isBatchMissing ? '' : "BATCH / LOT"}
                                        className={`${inputBaseClass.replace('w-full', 'w-1/2')} ${isBatchMissing ? 'text-red-500 border-red-900/50 bg-red-900/10' : ''}`}
                                    />
                                    <button 
                                        type="button"
                                        onClick={toggleBatchMissing}
                                        className={`w-1/2 h-12 rounded-lg border-2 font-black uppercase text-xs text-white transition-all flex items-center justify-center gap-2 ${isBatchMissing ? 'bg-red-600 border-red-500 shadow-lg' : 'bg-[#4169E1]/20 border-[#4169E1] hover:bg-[#4169E1]/40'}`}
                                    >
                                        🏷️ {t('inv_missing_label')}
                                    </button>
                                </div>
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_qty_label')}</label>
                                <input 
                                    ref={quantityRef}
                                    type="text"
                                    inputMode="decimal"
                                    value={quantity}
                                    onChange={(e) => setQuantity(e.target.value.replace(/[^0-9.,]/g, '').slice(0, 10))}
                                    onKeyDown={(e) => e.key === 'Enter' && handleAddItem()}
                                    placeholder="0"
                                    className={`${inputBaseClass} font-black text-lg`}
                                />
                            </div>
                        </div>

                        <button 
                            onClick={handleAddItem}
                            className="w-full mt-10 bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-6 rounded-2xl shadow-xl transition-all active:scale-95 uppercase tracking-widest text-xl border-2 border-[#5a81f3]"
                        >
                            {t('inv_add_btn')}
                        </button>
                    </>
                )}
            </div>

            {activeInventoryTask && (
                <div className="bg-gray-800 rounded-xl shadow-lg border border-gray-700 overflow-hidden">
                    <div className="p-5 sm:p-8 border-b border-gray-700 bg-gray-900/50 flex flex-col sm:flex-row justify-between items-center gap-8">
                        <div className="flex items-center gap-6">
                            <h3 className="text-gray-400 font-black uppercase text-base tracking-[0.2em] leading-none">
                                {t('inv_summary_title')}
                            </h3>
                            <span className="bg-[#4169E1]/20 text-white border-2 border-[#4169E1] text-2xl px-5 py-2 rounded-xl font-black font-mono leading-none shadow-lg">
                                {scannedItems.length}
                            </span>
                        </div>
                        <div className="flex flex-wrap w-full sm:w-auto gap-4">
                            <button 
                                onClick={handleClearAll} 
                                className={dangerButtonClass}
                            >
                                {language === 'sk' ? 'Zmazať všetko' : 'Clear all'}
                            </button>
                            <button 
                                onClick={handleExportAndFinish}
                                className="flex-1 sm:flex-none bg-green-700 hover:bg-green-600 text-white px-10 py-5 rounded-xl text-lg font-black shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 border-2 border-green-500 uppercase tracking-widest"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                                </svg>
                                {t('inv_finish_btn')}
                            </button>
                        </div>
                    </div>

                    <div className="overflow-x-auto custom-scrollbar">
                        <table className="w-full text-left text-base border-collapse">
                            <thead className="bg-gray-900/30 text-gray-500 text-xs font-black uppercase tracking-widest border-b border-gray-700">
                                <tr>
                                    <th className="py-5 px-6">{t('inv_th_time')}</th>
                                    <th className="py-5 px-6">{t('inv_th_loc')}</th>
                                    <th className="py-5 px-6">{t('inv_th_part')}</th>
                                    <th className="py-5 px-6">{t('inv_th_batch')}</th>
                                    <th className="py-5 px-6 text-right">{t('inv_th_qty')}</th>
                                    <th className="py-5 px-6 text-center"></th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-700/50">
                                {scannedItems.length > 0 ? (
                                    scannedItems.map(item => (
                                        <tr key={item.id} className="text-gray-300 hover:bg-gray-700/30 transition-colors group">
                                            <td className="py-5 px-6 text-xs text-gray-500 font-mono whitespace-nowrap">{new Date(item.timestamp).toLocaleTimeString('sk-SK')}</td>
                                            <td className="py-5 px-6 font-mono font-bold text-[#4169E1] text-lg">{item.location}</td>
                                            <td className="py-5 px-6 font-mono text-white text-base">{item.partNumber}</td>
                                            <td className={`py-5 px-6 font-mono text-base ${item.batch.includes('[') ? 'text-red-500 font-bold' : 'text-gray-500'}`}>
                                                {item.batch}
                                            </td>
                                            <td className="py-5 px-6 font-black text-white text-right font-mono text-xl">{item.quantity}</td>
                                            <td className="py-5 px-6 text-center w-24">
                                                <button 
                                                    onClick={() => handleDeleteItem(item.id)} 
                                                    className="w-16 h-16 flex items-center justify-center rounded-lg bg-red-900/30 text-red-500 hover:bg-red-800 hover:text-white border border-red-800/50 transition-all active:scale-90"
                                                >
                                                    <TrashIcon className="w-8 h-8" />
                                                </button>
                                            </td>
                                        </tr>
                                    ))
                                ) : (
                                    <tr><td colSpan={6} className="py-16 text-center text-gray-600 italic font-bold text-lg">{t('inv_empty_list')}</td></tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {confirmModal.isOpen && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setConfirmModal(prev => ({...prev, isOpen: false}))}>
                    <div className="bg-gray-800 border-2 border-slate-700 rounded-2xl shadow-2xl w-full max-w-md p-8 relative" onClick={e => e.stopPropagation()}>
                        <div className="text-center mb-8">
                            <h3 className={`text-2xl font-black mb-3 uppercase tracking-tighter ${confirmModal.type === 'danger' ? 'text-red-500' : 'text-amber-500'}`}>
                                {confirmModal.title}
                            </h3>
                            <div className="text-gray-300 text-base leading-relaxed">
                                {confirmModal.message}
                            </div>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => setConfirmModal(prev => ({...prev, isOpen: false}))} className="flex-1 py-4 bg-gray-700 text-gray-300 rounded-xl hover:bg-gray-600 font-black transition-all uppercase text-xs">
                                {t('btn_cancel')}
                            </button>
                            <button onClick={confirmModal.onConfirm} className={`flex-1 py-4 text-white rounded-xl font-black transition-all shadow-xl uppercase text-xs border-2 ${confirmModal.type === 'danger' ? 'bg-red-600 hover:bg-red-700 border-red-500' : 'bg-amber-600 hover:bg-amber-700 border-amber-500'}`}>
                                {t('btn_confirm')}
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default InventoryTab;

import React, { useState, useEffect, useRef, useMemo, memo } from 'react';
import { useLanguage } from './LanguageContext';
import { db } from '../firebase';
import { doc, getDoc } from 'firebase/firestore';

interface PartNumberInputProps {
  parts: string[];
  onPartSelect: (part: string | null) => void;
  onInputChange?: (value: string) => void;
  placeholder?: string;
  value: string | null;
  onRequestPart?: (part: string) => Promise<boolean>;
  inputRef?: React.RefObject<HTMLInputElement>;
  onKeyDown?: React.KeyboardEventHandler<HTMLInputElement>;
}

const SearchIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
    </svg>
);

