  onToggleAdminLock: (val: boolean) => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
}

const Icons = {
  Trash: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
  Megaphone: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5.882V19.24a1.76 1.76 0 01-3.417.592l-2.147-6.15M18 13a3 3 0 100-6M5.436 13.683A4.001 4.001 0 017 6h1.832c4.1 0 7.625-1.234 9.168-3v14c-1.543-1.766-5.067-3-9.168-3H7a3.988 3.988 0 01-1.564-.317z" /></svg>,
  UserGroup: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>,
  ArrowUp: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 15l7-7 7 7" /></svg>,
  ArrowDown: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 9l-7 7-7-7" /></svg>,
  Layout: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6zM4 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2v-2zM14 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2v-2z" /></svg>
};

const SystemSection: React.FC<SystemSectionProps> = ({ 
  missingReasons, breakSchedules, onAddMissingReason, onDeleteMissingReason, onAddBreakSchedule, onDeleteBreakSchedule, onUpdateAdminKey,
  isAdminLockEnabled, onToggleAdminLock, systemConfig, onUpdateSystemConfig
}) => {
  const { t, language } = useLanguage();
  const { onBroadcastNotification, users } = useData();

  const [newMissingReason, setNewMissingReason] = useState('');
  const [newBreakStart, setNewBreakStart] = useState('');
  const [newBreakEnd, setNewBreakEnd] = useState('');

  const [oldKey, setOldKey] = useState('');
  const [newKey, setNewKey] = useState('');
  const [confirmKey, setConfirmKey] = useState('');
  const [isUpdating, setIsUpdating] = useState(false);

  // Broadcast State
  const [broadcastMsg, setBroadcastMsg] = useState('');
  const [isBroadcasting, setIsBroadcasting] = useState(false);
  const [selectedRecipients, setSelectedRecipients] = useState<string[]>([]);
  const [selectAll, setSelectAll] = useState(true);

  // Tab Order State
  const [localTabOrder, setLocalTabOrder] = useState<string[]>([]);
  const [hasOrderChanged, setHasOrderChanged] = useState(false);

  useEffect(() => {
    setLocalTabOrder(systemConfig.tabOrder || DEFAULT_TAB_ORDER);
  }, [systemConfig.tabOrder]);

  const moveTab = (index: number, direction: 'up' | 'down') => {
    const newOrder = [...localTabOrder];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newOrder.length) return;

    const temp = newOrder[index];
    newOrder[index] = newOrder[targetIndex];
    newOrder[targetIndex] = temp;

    setLocalTabOrder(newOrder);
    setHasOrderChanged(true);
  };

  const handleSaveTabOrder = async () => {
    await onUpdateSystemConfig({ tabOrder: localTabOrder });
    setHasOrderChanged(false);
    alert(language === 'sk' ? 'Usporiadanie menu bolo uložené.' : 'Tab order saved.');
  };

  const resetToDefaultOrder = () => {
    setLocalTabOrder(DEFAULT_TAB_ORDER);
    setHasOrderChanged(true);
  };

  const toggleRecipient = (username: string) => {
    setSelectAll(false);
    setSelectedRecipients(prev => 
      prev.includes(username) ? prev.filter(u => u !== username) : [...prev, username]
    );
  };

  const handleToggleAll = () => {
    const newState = !selectAll;
    setSelectAll(newState);
    if (newState) setSelectedRecipients([]);
  };

  const handleUpdateKey = async () => {
    if (!isAdminLockEnabled) return;
    if (!oldKey || !newKey || !confirmKey) {
        alert(language === 'sk' ? 'Prosím, vyplňte všetky polia.' : 'Please fill all fields.');
        return;
    }
    if (newKey !== confirmKey) {
        alert(language === 'sk' ? 'Nové kľúče sa nezhodujú.' : 'New keys do not match.');
        return;
    }

    setIsUpdating(true);
    try {
        await onUpdateAdminKey(oldKey, newKey);
        setOldKey('');
        setNewKey('');
        setConfirmKey('');
    } catch (e) {
        // Error handled in hook
    } finally {
        setIsUpdating(false);
    }
  };

  const handleBroadcast = async () => {
    if (!broadcastMsg.trim()) return;

    const recipientCount = selectAll ? users.length : selectedRecipients.length;
    if (recipientCount === 0) {
        alert(language === 'sk' ? 'Vyberte aspoň jedného príjemcu.' : 'Select at least one recipient.');
        return;
    }

    if (!window.confirm(language === 'sk' ? `Odoslať túto správu ${recipientCount} užívateľom?` : `Send this message to ${recipientCount} users?`)) return;

    setIsBroadcasting(true);
    const author = localStorage.getItem('app_user') || 'ADMIN';

    // Ak je selectAll true, posielame undefined (v hooku ošetríme ako všetkých)
    await onBroadcastNotification(broadcastMsg, author, selectAll ? undefined : selectedRecipients);

    setBroadcastMsg('');
    setIsBroadcasting(false);
    alert(language === 'sk' ? 'Správa bola rozoslaná.' : 'Message broadcasted.');
  };

  const cardClass = "bg-gray-800/40 border border-slate-700/50 rounded-2xl p-6 shadow-2xl backdrop-blur-sm";
  const inputClass = "w-full h-12 bg-slate-800/80 border border-slate-700 rounded-xl px-4 text-white text-base focus:outline-none focus:ring-2 focus:ring-teal-500/50 transition-all font-mono placeholder-gray-500 uppercase";
  const labelClass = "block text-xs font-black text-slate-500 uppercase tracking-[0.2em] mb-3";

  return (
    <div className="space-y-8 animate-fade-in">

      {/* BROADCAST SECTION */}
      <div className="bg-indigo-900/10 border-2 border-indigo-500/30 rounded-3xl p-6 shadow-xl ring-1 ring-indigo-500/20">
          <div className="flex items-center gap-3 mb-6">
              <div className="p-3 bg-indigo-500/20 rounded-xl text-indigo-400">
                  <Icons.Megaphone />
              </div>
              <div>
                  <h3 className="text-xl font-black text-white uppercase tracking-tighter">HROMADNÁ SPRÁVA</h3>
                  <p className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mt-1">Odoslať notifikáciu vybraným užívateľom</p>
              </div>
          </div>

          <div className="space-y-6">
              {/* Recipient Selector UI */}
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-indigo-500/20">
                  <div className="flex items-center justify-between mb-4 px-2">
                      <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest">
                          <Icons.UserGroup />
                          PRÍJEMCOVIA
                      </div>
                      <button 
                        onClick={handleToggleAll}
                        className={`text-[10px] font-black px-3 py-1 rounded-full border transition-all ${selectAll ? 'bg-indigo-500 text-white border-indigo-400 shadow-md' : 'bg-slate-800 text-slate-500 border-slate-700'}`}
                      >
                        VŠETCI PRIHLÁSENÍ
                      </button>
                  </div>

                  {!selectAll && (
                      <div className="flex flex-wrap gap-2 max-h-32 overflow-y-auto custom-scrollbar p-1 animate-fade-in">
                          {users.map(u => (
                              <button
                                  key={u.username}
                                  onClick={() => toggleRecipient(u.username)}
                                  className={`px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wide border transition-all ${selectedRecipients.includes(u.username) ? 'bg-teal-600/20 border-teal-500 text-teal-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-700'}`}
                              >
                                  {u.nickname || u.username}
                              </button>
                          ))}
                      </div>
                  )}
              </div>

              <div className="flex gap-3">
                  <textarea 
                      value={broadcastMsg}
                      onChange={(e) => setBroadcastMsg(e.target.value)}
                      placeholder="ZADAJTE TEXT SPRÁVY..."
                      className="w-full bg-slate-950 border border-indigo-500/30 rounded-2xl px-5 py-4 text-white text-sm focus:outline-none focus:border-indigo-500 transition-all font-medium placeholder-slate-700 resize-none h-24"
                  />
                  <button 
                      onClick={handleBroadcast}
                      disabled={isBroadcasting || !broadcastMsg.trim() || (!selectAll && selectedRecipients.length === 0)}
                      className="w-32 bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 disabled:text-slate-600 text-white rounded-2xl font-black shadow-lg transition-all active:scale-95 border-2 border-indigo-500 uppercase tracking-widest text-[10px]"
                  >
                      {isBroadcasting ? '...' : 'ODOSLAŤ'}
                  </button>
              </div>
          </div>
      </div>

      {/* TAB ORDER MANAGEMENT SECTION */}
      <div className={cardClass}>
        <div className="flex justify-between items-center mb-6">
            <div className="flex items-center gap-3">
                <div className="p-3 bg-teal-500/10 rounded-xl text-teal-400 border border-teal-500/20">
                    <Icons.Layout />
                </div>
                <div>
                    <h3 className="text-xl font-black text-white uppercase tracking-tighter">USPORIADANIE NAVIGÁCIE</h3>
                    <p className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mt-1">Zmeňte poradie kariet v hlavnom menu</p>
                </div>
            </div>
            <div className="flex gap-2">
                <button 
                    onClick={resetToDefaultOrder}
                    className="h-10 px-4 rounded-lg bg-slate-800 text-slate-400 border border-slate-700 text-[9px] font-black uppercase tracking-widest hover:text-white transition-all"
                >
                    RESET
                </button>
                {hasOrderChanged && (
                    <button 
                        onClick={handleSaveTabOrder}
                        className="h-10 px-6 rounded-lg bg-teal-600 text-white border-2 border-teal-500 text-[10px] font-black uppercase tracking-widest shadow-lg animate-pulse"
                    >
                        ULOŽIŤ ZMENY
                    </button>
                )}
            </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
            {localTabOrder.map((tabId, idx) => {
                const config = TAB_CONFIG.find(c => c.id === tabId);
                if (!config) return null;
                return (
                    <div key={tabId} className="bg-slate-950/40 p-4 rounded-xl border border-white/5 flex items-center justify-between group">
                        <div className="flex items-center gap-4">
                            <span className="text-[10px] font-black text-slate-700 font-mono w-4">{idx + 1}.</span>
                            <span className="text-xs font-black text-slate-300 uppercase tracking-wider">{t(config.labelKey)}</span>
                        </div>
                        <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button 
                                onClick={() => moveTab(idx, 'up')} 
                                disabled={idx === 0}
                                className="p-2 rounded bg-slate-800 text-slate-500 hover:text-teal-400 disabled:opacity-10"
                            >
                                <Icons.ArrowUp />
                            </button>
                            <button 
                                onClick={() => moveTab(idx, 'down')} 
                                disabled={idx === localTabOrder.length - 1}
                                className="p-2 rounded bg-slate-800 text-slate-500 hover:text-teal-400 disabled:opacity-10"
                            >
                                <Icons.ArrowDown />
                            </button>
                        </div>
                    </div>
                );
            })}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* REASONS */}
        <div className={cardClass}>
          <h3 className="text-xl font-black text-white mb-6 uppercase tracking-tighter">DÔVODY CHÝBANIA</h3>
          <div className="space-y-4 max-h-60 overflow-y-auto custom-scrollbar pr-2 mb-6">
            {missingReasons.map(r => (
              <div key={r.id} className="flex justify-between items-center bg-slate-950/30 p-3 rounded-xl border border-white/5 group">
                <span className="text-sm font-bold text-slate-300 uppercase">{r.value}</span>
                <button onClick={() => onDeleteMissingReason(r.id)} className="text-slate-600 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"><Icons.Trash /></button>
              </div>
            ))}
          </div>
          <div className="flex gap-2">
            <input value={newMissingReason} onChange={e=>setNewMissingReason(e.target.value)} placeholder="NOVÝ DÔVOD" className={inputClass} />
            <button onClick={()=>{if(newMissingReason){onAddMissingReason(newMissingReason); setNewMissingReason('');}}} className="bg-teal-600 hover:bg-teal-500 text-white px-6 rounded-xl font-black text-xs uppercase tracking-widest border-2 border-teal-500 shadow-lg">PRIDAŤ</button>
          </div>
        </div>

        {/* BREAKS */}
        <div className={cardClass}>
          <h3 className="text-xl font-black text-white mb-6 uppercase tracking-tighter">PLÁNOVANÉ PRESTÁVKY</h3>
          <div className="space-y-4 max-h-60 overflow-y-auto custom-scrollbar pr-2 mb-6">
            {breakSchedules.map(b => (
              <div key={b.id} className="flex justify-between items-center bg-slate-950/30 p-3 rounded-xl border border-white/5 group">
                <span className="text-sm font-bold text-amber-500 font-mono">{b.startTime} - {b.endTime}</span>
                <button onClick={() => onDeleteBreakSchedule(b.id)} className="text-slate-600 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"><Icons.Trash /></button>
              </div>
            ))}
          </div>
          <div className="grid grid-cols-3 gap-2">
            <input type="time" value={newBreakStart} onChange={e=>setNewBreakStart(e.target.value)} className={inputClass} />
            <input type="time" value={newBreakEnd} onChange={e=>setNewBreakEnd(e.target.value)} className={inputClass} />
            <button onClick={()=>{if(newBreakStart && newBreakEnd){onAddBreakSchedule(newBreakStart, newBreakEnd); setNewBreakStart(''); setNewBreakEnd('');}}} className="bg-amber-600 hover:bg-amber-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest border-2 border-amber-500 shadow-lg">PRIDAŤ</button>
          </div>
        </div>
      </div>

      {/* ADMIN LOCK SETTINGS */}
      <div className={cardClass}>
        <div className="flex justify-between items-center mb-8 border-b border-slate-800 pb-6">
            <h3 className="text-xl font-black text-white uppercase tracking-tighter">ZABEZPEČENIE ADMIN KONZOLY</h3>
            <button 
                onClick={() => onToggleAdminLock(!isAdminLockEnabled)}
                className={`px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-widest border-2 transition-all ${isAdminLockEnabled ? 'bg-amber-500/10 border-amber-500 text-amber-500 shadow-lg' : 'bg-slate-800 border-slate-700 text-slate-500'}`}
            >
                {isAdminLockEnabled ? 'ZÁMOK AKTÍVNY' : 'ZÁMOK VYPNUTÝ'}
            </button>
        </div>

        {isAdminLockEnabled && (
            <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 items-end animate-fade-in">
                <div>
                    <label className={labelClass}>AKTUÁLNY KĽÚČ</label>
                    <input type="password" value={oldKey} onChange={e=>setOldKey(e.target.value)} className={inputClass} placeholder="••••" />
                </div>
                <div>
                    <label className={labelClass}>NOVÝ KĽÚČ</label>
                    <input type="password" value={newKey} onChange={e=>setNewKey(e.target.value)} className={inputClass} placeholder="••••" />
                </div>
                <div>
                    <label className={labelClass}>POTVRDIŤ NOVÝ</label>
                    <input type="password" value={confirmKey} onChange={e=>setConfirmKey(e.target.value)} className={inputClass} placeholder="••••" />
                </div>
                <button 
                    onClick={handleUpdateKey}
                    disabled={isUpdating}
                    className="h-12 bg-amber-600 hover:bg-amber-500 text-white rounded-xl font-black uppercase tracking-widest text-[10px] transition-all border-2 border-amber-500 shadow-xl disabled:opacity-50"
                >
                    {isUpdating ? 'AKTUALIZUJEM...' : 'ZMENIŤ KĽÚČ'}
                </button>
            </div>
        )}
      </div>
    </div>
  );
};

export default SystemSection;

export const PRIORITY_ORDER: Record<string, number> = { 
  'URGENT': 0, 
  'NORMAL': 1, 
  'LOW': 2 
};

export const COLOR_MAP = {
  blue: 'bg-blue-600',
  green: 'bg-green-600',
  orange: 'bg-orange-600',
  teal: 'bg-teal-600',
  pink: 'bg-pink-600',
  red: 'bg-red-600',
  slate: 'bg-slate-700'
};

export interface TabDefinition {
  id: string;
  labelKey: any; // Zmenené zo string na any pre opravu TS2345 buildu
  permission: string;
  badgeKey?: 'tasks' | 'pendingRequests' | 'erpBlockages';
  color?: string;
  adminOnly?: boolean;
}

export const TAB_CONFIG: TabDefinition[] = [
  { id: 'entry', labelKey: 'tab_entry', permission: 'perm_tab_entry' },
  { id: 'tasks', labelKey: 'tab_tasks', permission: 'perm_tab_tasks', badgeKey: 'tasks' },
  { id: 'bom', labelKey: 'tab_bom', permission: 'perm_tab_bom' },
  { id: 'catalog', labelKey: 'tab_catalog', permission: 'perm_tab_catalog' },
  { id: 'missing', labelKey: 'tab_missing', permission: 'perm_tab_missing' },
  { id: 'inventory', labelKey: 'tab_inventory', permission: 'perm_tab_inventory' },
  { id: 'logistics', labelKey: 'tab_logistics_center', permission: 'perm_tab_logistics_center' },
  { id: 'erp', labelKey: 'tab_erp', permission: 'perm_tab_erp', badgeKey: 'erpBlockages', color: 'border-orange-500 text-orange-400' },
  { id: 'map', labelKey: 'tab_map', permission: 'perm_tab_map', color: 'border-amber-500 text-amber-400' },
  { id: 'logs', labelKey: 'tab_logs', permission: 'perm_tab_logs', color: 'border-cyan-500 text-cyan-400', adminOnly: true },
  { id: 'analytics', labelKey: 'tab_analytics', permission: 'perm_tab_analytics' },
  { id: 'settings', labelKey: 'tab_settings', permission: 'perm_tab_settings', badgeKey: 'pendingRequests' },
  { id: 'permissions', labelKey: 'tab_permissions', permission: 'perm_tab_permissions' }
];

export const DEFAULT_TAB_ORDER = TAB_CONFIG.map(t => t.id);

import React, { useState, useEffect } from 'react';
import { DBItem, BreakSchedule, SystemConfig } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';
import { useData } from '../../context/DataContext';
import { TAB_CONFIG, DEFAULT_TAB_ORDER } from '../../constants/uiConstants';

interface SystemSectionProps {
  missingReasons: DBItem[];
  breakSchedules: BreakSchedule[];
  onAddMissingReason: (val: string) => void;
  onDeleteMissingReason: (id: string) => void;
  onAddBreakSchedule: (start: string, end: string) => void;
  onDeleteBreakSchedule: (id: string) => void;
  onUpdateAdminKey: (oldK: string, newK: string) => Promise<void>;
  isAdminLockEnabled: boolean;
  onToggleAdminLock: (val: boolean) => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
}

const Icons = {
  Trash: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
  Megaphone: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5.882V19.24a1.76 1.76 0 01-3.417.592l-2.147-6.15M18 13a3 3 0 100-6M5.436 13.683A4.001 4.001 0 017 6h1.832c4.1 0 7.625-1.234 9.168-3v14c-1.543-1.766-5.067-3-9.168-3H7a3.988 3.988 0 01-1.564-.317z" /></svg>,
  UserGroup: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>,
  ArrowUp: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 15l7-7 7 7" /></svg>,
  ArrowDown: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 9l-7 7-7-7" /></svg>,
  Layout: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6zM4 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2v-2zM14 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2v-2z" /></svg>
};

const SystemSection: React.FC<SystemSectionProps> = ({ 
  missingReasons, breakSchedules, onAddMissingReason, onDeleteMissingReason, onAddBreakSchedule, onDeleteBreakSchedule, onUpdateAdminKey,
  isAdminLockEnabled, onToggleAdminLock, systemConfig, onUpdateSystemConfig
}) => {
  const { t, language } = useLanguage();
  const { onBroadcastNotification, users } = useData();

  const [newMissingReason, setNewMissingReason] = useState('');
  const [newBreakStart, setNewBreakStart] = useState('');
  const [newBreakEnd, setNewBreakEnd] = useState('');

  const [oldKey, setOldKey] = useState('');
  const [newKey, setNewKey] = useState('');
  const [confirmKey, setConfirmKey] = useState('');
  const [isUpdating, setIsUpdating] = useState(false);

  // Broadcast State
  const [broadcastMsg, setBroadcastMsg] = useState('');
  const [isBroadcasting, setIsBroadcasting] = useState(false);
  const [selectedRecipients, setSelectedRecipients] = useState<string[]>([]);
  const [selectAll, setSelectAll] = useState(true);

  // Tab Order State
  const [localTabOrder, setLocalTabOrder] = useState<string[]>([]);
  const [hasOrderChanged, setHasOrderChanged] = useState(false);

  useEffect(() => {
    setLocalTabOrder(systemConfig.tabOrder || DEFAULT_TAB_ORDER);
  }, [systemConfig.tabOrder]);

  const moveTab = (index: number, direction: 'up' | 'down') => {
    const newOrder = [...localTabOrder];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newOrder.length) return;

    const temp = newOrder[index];
    newOrder[index] = newOrder[targetIndex];
    newOrder[targetIndex] = temp;

    setLocalTabOrder(newOrder);
    setHasOrderChanged(true);
  };

  const handleSaveTabOrder = async () => {
    await onUpdateSystemConfig({ tabOrder: localTabOrder });
    setHasOrderChanged(false);
    alert(language === 'sk' ? 'Usporiadanie menu bolo uložené.' : 'Tab order saved.');
  };

  const resetToDefaultOrder = () => {
    setLocalTabOrder(DEFAULT_TAB_ORDER);
    setHasOrderChanged(true);
  };

  const toggleRecipient = (username: string) => {
    setSelectAll(false);
    setSelectedRecipients(prev => 
      prev.includes(username) ? prev.filter(u => u !== username) : [...prev, username]
    );
  };

  const handleToggleAll = () => {
    const newState = !selectAll;
    setSelectAll(newState);
    if (newState) setSelectedRecipients([]);
  };

  const handleUpdateKey = async () => {
    if (!isAdminLockEnabled) return;
    if (!oldKey || !newKey || !confirmKey) {
        alert(language === 'sk' ? 'Prosím, vyplňte všetky polia.' : 'Please fill all fields.');
        return;
    }
    if (newKey !== confirmKey) {
        alert(language === 'sk' ? 'Nové kľúče sa nezhodujú.' : 'New keys do not match.');
        return;
    }

    setIsUpdating(true);
    try {
        await onUpdateAdminKey(oldKey, newKey);
        setOldKey('');
        setNewKey('');
        setConfirmKey('');
    } catch (e) {
        // Error handled in hook
    } finally {
        setIsUpdating(false);
    }
  };

  const handleBroadcast = async () => {
    if (!broadcastMsg.trim()) return;

    const recipientCount = selectAll ? users.length : selectedRecipients.length;
    if (recipientCount === 0) {
        alert(language === 'sk' ? 'Vyberte aspoň jedného príjemcu.' : 'Select at least one recipient.');
        return;
    }

    if (!window.confirm(language === 'sk' ? `Odoslať túto správu ${recipientCount} užívateľom?` : `Send this message to ${recipientCount} users?`)) return;

    setIsBroadcasting(true);
    const author = localStorage.getItem('app_user') || 'ADMIN';

    // Ak je selectAll true, posielame undefined (v hooku ošetríme ako všetkých)
    await onBroadcastNotification(broadcastMsg, author, selectAll ? undefined : selectedRecipients);

    setBroadcastMsg('');
    setIsBroadcasting(false);
    alert(language === 'sk' ? 'Správa bola rozoslaná.' : 'Message broadcasted.');
  };

  const cardClass = "bg-gray-800/40 border border-slate-700/50 rounded-2xl p-6 shadow-2xl backdrop-blur-sm";
  const inputClass = "w-full h-12 bg-slate-800/80 border border-slate-700 rounded-xl px-4 text-white text-base focus:outline-none focus:ring-2 focus:ring-teal-500/50 transition-all font-mono placeholder-gray-500 uppercase";
  const labelClass = "block text-xs font-black text-slate-500 uppercase tracking-[0.2em] mb-3";

  return (
    <div className="space-y-8 animate-fade-in">

      {/* BROADCAST SECTION */}
      <div className="bg-indigo-900/10 border-2 border-indigo-500/30 rounded-3xl p-6 shadow-xl ring-1 ring-indigo-500/20">
          <div className="flex items-center gap-3 mb-6">
              <div className="p-3 bg-indigo-500/20 rounded-xl text-indigo-400">
                  <Icons.Megaphone />
              </div>
              <div>
                  <h3 className="text-xl font-black text-white uppercase tracking-tighter">HROMADNÁ SPRÁVA</h3>
                  <p className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mt-1">Odoslať notifikáciu vybraným užívateľom</p>
              </div>
          </div>

          <div className="space-y-6">
              {/* Recipient Selector UI */}
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-indigo-500/20">
                  <div className="flex items-center justify-between mb-4 px-2">
                      <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest">
                          <Icons.UserGroup />
                          PRÍJEMCOVIA
                      </div>
                      <button 
                        onClick={handleToggleAll}
                        className={`text-[10px] font-black px-3 py-1 rounded-full border transition-all ${selectAll ? 'bg-indigo-500 text-white border-indigo-400 shadow-md' : 'bg-slate-800 text-slate-500 border-slate-700'}`}
                      >
                        VŠETCI PRIHLÁSENÍ
                      </button>
                  </div>

                  {!selectAll && (
                      <div className="flex flex-wrap gap-2 max-h-32 overflow-y-auto custom-scrollbar p-1 animate-fade-in">
                          {users.map(u => (
                              <button
                                  key={u.username}
                                  onClick={() => toggleRecipient(u.username)}
                                  className={`px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wide border transition-all ${selectedRecipients.includes(u.username) ? 'bg-teal-600/20 border-teal-500 text-teal-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-700'}`}
                              >
                                  {u.nickname || u.username}
                              </button>
                          ))}
                      </div>
                  )}
              </div>

              <div className="flex gap-3">
                  <textarea 
                      value={broadcastMsg}
                      onChange={(e) => setBroadcastMsg(e.target.value)}
                      placeholder="ZADAJTE TEXT SPRÁVY..."
                      className="w-full bg-slate-950 border border-indigo-500/30 rounded-2xl px-5 py-4 text-white text-sm focus:outline-none focus:border-indigo-500 transition-all font-medium placeholder-slate-700 resize-none h-24"
                  />
                  <button 
                      onClick={handleBroadcast}
                      disabled={isBroadcasting || !broadcastMsg.trim() || (!selectAll && selectedRecipients.length === 0)}
                      className="w-32 bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 disabled:text-slate-600 text-white rounded-2xl font-black shadow-lg transition-all active:scale-95 border-2 border-indigo-500 uppercase tracking-widest text-[10px]"
                  >
                      {isBroadcasting ? '...' : 'ODOSLAŤ'}
                  </button>
              </div>
          </div>
      </div>

      {/* TAB ORDER MANAGEMENT SECTION */}
      <div className={cardClass}>
        <div className="flex justify-between items-center mb-6">
            <div className="flex items-center gap-3">
                <div className="p-3 bg-teal-500/10 rounded-xl text-teal-400 border border-teal-500/20">
                    <Icons.Layout />
                </div>
                <div>
                    <h3 className="text-xl font-black text-white uppercase tracking-tighter">USPORIADANIE NAVIGÁCIE</h3>
                    <p className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mt-1">Zmeňte poradie kariet v hlavnom menu</p>
                </div>
            </div>
            <div className="flex gap-2">
                <button 
                    onClick={resetToDefaultOrder}
                    className="h-10 px-4 rounded-lg bg-slate-800 text-slate-400 border border-slate-700 text-[9px] font-black uppercase tracking-widest hover:text-white transition-all"
                >
                    RESET
                </button>
                {hasOrderChanged && (
                    <button 
                        onClick={handleSaveTabOrder}
                        className="h-10 px-6 rounded-lg bg-teal-600 text-white border-2 border-teal-500 text-[10px] font-black uppercase tracking-widest shadow-lg animate-pulse"
                    >
                        ULOŽIŤ ZMENY
                    </button>
                )}
            </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
            {localTabOrder.map((tabId, idx) => {
                const config = TAB_CONFIG.find(c => c.id === tabId);
                if (!config) return null;
                return (
                    <div key={tabId} className="bg-slate-950/40 p-4 rounded-xl border border-white/5 flex items-center justify-between group">
                        <div className="flex items-center gap-4">
                            <span className="text-[10px] font-black text-slate-700 font-mono w-4">{idx + 1}.</span>
                            <span className="text-xs font-black text-slate-300 uppercase tracking-wider">{t(config.labelKey as any)}</span>
                        </div>
                        <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button 
                                onClick={() => moveTab(idx, 'up')} 
                                disabled={idx === 0}
                                className="p-2 rounded bg-slate-800 text-slate-500 hover:text-teal-400 disabled:opacity-10"
                            >
                                <Icons.ArrowUp />
                            </button>
                            <button 
                                onClick={() => moveTab(idx, 'down')} 
                                disabled={idx === localTabOrder.length - 1}
                                className="p-2 rounded bg-slate-800 text-slate-500 hover:text-teal-400 disabled:opacity-10"
                            >
                                <Icons.ArrowDown />
                            </button>
                        </div>
                    </div>
                );
            })}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* REASONS */}
        <div className={cardClass}>
          <h3 className="text-xl font-black text-white mb-6 uppercase tracking-tighter">DÔVODY CHÝBANIA</h3>
          <div className="space-y-4 max-h-60 overflow-y-auto custom-scrollbar pr-2 mb-6">
            {missingReasons.map(r => (
              <div key={r.id} className="flex justify-between items-center bg-slate-950/30 p-3 rounded-xl border border-white/5 group">
                <span className="text-sm font-bold text-slate-300 uppercase">{r.value}</span>
                <button onClick={() => onDeleteMissingReason(r.id)} className="text-slate-600 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"><Icons.Trash /></button>
              </div>
            ))}
          </div>
          <div className="flex gap-2">
            <input value={newMissingReason} onChange={e=>setNewMissingReason(e.target.value)} placeholder="NOVÝ DÔVOD" className={inputClass} />
            <button onClick={()=>{if(newMissingReason){onAddMissingReason(newMissingReason); setNewMissingReason('');}}} className="bg-teal-600 hover:bg-teal-500 text-white px-6 rounded-xl font-black text-xs uppercase tracking-widest border-2 border-teal-500 shadow-lg">PRIDAŤ</button>
          </div>
        </div>

        {/* BREAKS */}
        <div className={cardClass}>
          <h3 className="text-xl font-black text-white mb-6 uppercase tracking-tighter">PLÁNOVANÉ PRESTÁVKY</h3>
          <div className="space-y-4 max-h-60 overflow-y-auto custom-scrollbar pr-2 mb-6">
            {breakSchedules.map(b => (
              <div key={b.id} className="flex justify-between items-center bg-slate-950/30 p-3 rounded-xl border border-white/5 group">
                <span className="text-sm font-bold text-amber-500 font-mono">{b.startTime} - {b.endTime}</span>
                <button onClick={() => onDeleteBreakSchedule(b.id)} className="text-slate-600 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"><Icons.Trash /></button>
              </div>
            ))}
          </div>
          <div className="grid grid-cols-3 gap-2">
            <input type="time" value={newBreakStart} onChange={e=>setNewBreakStart(e.target.value)} className={inputClass} />
            <input type="time" value={newBreakEnd} onChange={e=>setNewBreakEnd(e.target.value)} className={inputClass} />
            <button onClick={()=>{if(newBreakStart && newBreakEnd){onAddBreakSchedule(newBreakStart, newBreakEnd); setNewBreakStart(''); setNewBreakEnd('');}}} className="bg-amber-600 hover:bg-amber-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest border-2 border-amber-500 shadow-lg">PRIDAŤ</button>
          </div>
        </div>
      </div>

      {/* ADMIN LOCK SETTINGS */}
      <div className={cardClass}>
        <div className="flex justify-between items-center mb-8 border-b border-slate-800 pb-6">
            <h3 className="text-xl font-black text-white uppercase tracking-tighter">ZABEZPEČENIE ADMIN KONZOLY</h3>
            <button 
                onClick={() => onToggleAdminLock(!isAdminLockEnabled)}
                className={`px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-widest border-2 transition-all ${isAdminLockEnabled ? 'bg-amber-500/10 border-amber-500 text-amber-500 shadow-lg' : 'bg-slate-800 border-slate-700 text-slate-500'}`}
            >
                {isAdminLockEnabled ? 'ZÁMOK AKTÍVNY' : 'ZÁMOK VYPNUTÝ'}
            </button>
        </div>

        {isAdminLockEnabled && (
            <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 items-end animate-fade-in">
                <div>
                    <label className={labelClass}>AKTUÁLNY KĽÚČ</label>
                    <input type="password" value={oldKey} onChange={e=>setOldKey(e.target.value)} className={inputClass} placeholder="••••" />
                </div>
                <div>
                    <label className={labelClass}>NOVÝ KĽÚČ</label>
                    <input type="password" value={newKey} onChange={e=>setNewKey(e.target.value)} className={inputClass} placeholder="••••" />
                </div>
                <div>
                    <label className={labelClass}>POTVRDIŤ NOVÝ</label>
                    <input type="password" value={confirmKey} onChange={e=>setConfirmKey(e.target.value)} className={inputClass} placeholder="••••" />
                </div>
                <button 
                    onClick={handleUpdateKey}
                    disabled={isUpdating}
                    className="h-12 bg-amber-600 hover:bg-amber-500 text-white rounded-xl font-black uppercase tracking-widest text-[10px] transition-all border-2 border-amber-500 shadow-xl disabled:opacity-50"
                >
                    {isUpdating ? 'AKTUALIZUJEM...' : 'ZMENIŤ KĽÚČ'}
                </button>
            </div>
        )}
      </div>
    </div>
  );
};

export default SystemSection;

import React from 'react';
import { TAB_CONFIG, DEFAULT_TAB_ORDER } from '../constants/uiConstants';
import { SystemConfig } from '../types/appTypes';

interface TabNavigatorProps {
  activeTab: string;
  setActiveTab: (tab: any) => void;
  hasPermission: (perm: string) => boolean;
  t: (key: any) => string;
  counts: {
    tasks: number;
    pendingRequests: number;
    erpBlockages: number;
  };
  currentUserRole?: string;
  systemConfig?: SystemConfig;
}

const TabNavigator: React.FC<TabNavigatorProps> = ({
  activeTab,
  setActiveTab,
  hasPermission,
  t,
  counts,
  currentUserRole,
  systemConfig
}) => {
  const currentOrder = systemConfig?.tabOrder || DEFAULT_TAB_ORDER;

  return (
    <div className="bg-gray-800 border-t border-gray-700 shadow-sm z-10">
      <div className="max-w-7xl mx-auto w-full px-2 sm:px-4 overflow-x-auto custom-scrollbar">
        <div className="flex space-x-4 sm:space-x-6">
          {currentOrder.map(tabId => {
            const config = TAB_CONFIG.find(c => c.id === tabId);
            if (!config) return null;

            // Admin bypass check
            if (config.adminOnly && currentUserRole !== 'ADMIN') return null;

            // Standard permission check
            if (!hasPermission(config.permission)) return null;

            const isActive = activeTab === config.id;
            const badgeValue = config.badgeKey ? counts[config.badgeKey] : 0;
            const hasBadge = badgeValue > 0;

            const activeColorClass = config.color || 'border-teal-500 text-teal-400';
            const badgeColorClass = config.id === 'settings' ? 'bg-red-500' : 'bg-orange-600';

            return (
              <button
                key={config.id}
                onClick={() => setActiveTab(config.id)}
                className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${
                  isActive 
                    ? activeColorClass 
                    : `border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500 ${hasBadge ? 'text-orange-400/80' : ''}`
                }`}
              >
                {t(config.labelKey as any)}
                {hasBadge && (
                  <span className={`ml-1 sm:ml-2 text-white text-xs rounded-full px-1.5 sm:px-2 py-0.5 ${badgeColorClass}`}>
                    {badgeValue}
                  </span>
                )}
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
};

export default TabNavigator;

import React, { useState, useEffect, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { db } from '../../firebase';
import { doc, updateDoc, setDoc } from 'firebase/firestore';
import { ERPBlockage, DBItem } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';
import { useData } from '../../context/DataContext';
import PartNumberInput from '../PartNumberInput';

declare var XLSX: any;

interface ERPBlockageTabProps {
    currentUser: string;
    currentUserRole: string;
    parts: DBItem[];
    blockages: ERPBlockage[];
    resolveName: (username?: string | null) => string;
}

const Icons = {
    Warning: () => <svg className="w-8 h-8 text-orange-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>,
    Check: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" /></svg>,
    Trash: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
    Excel: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
};

const ERPBlockageTab: React.FC<ERPBlockageTabProps> = ({ currentUser, currentUserRole, parts, blockages, resolveName }) => {
    const { t, language } = useLanguage();
    const { onAddNotification } = useData();

    // State
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [timer, setTimer] = useState(Date.now());

    // Form State
    const [partNumber, setPartNumber] = useState('');
    const [quantity, setQuantity] = useState('');
    const [userNote, setUserNote] = useState('');

    // Modal State
    const [finishModal, setFinishModal] = useState<{ isOpen: boolean; id: string | null; note: string }>({ isOpen: false, id: null, note: '' });
    const [confirmModal, setConfirmModal] = useState<{ isOpen: boolean; title: string; desc: string; onConfirm: () => void; type: 'danger' | 'warning' }>({ isOpen: false, title: '', desc: '', onConfirm: () => {}, type: 'danger' });

    useEffect(() => {
        const interval = setInterval(() => setTimer(Date.now()), 60000);
        return () => clearInterval(interval);
    }, []);

    const sortedList = useMemo(() => {
        const score = { waiting: 0, resolving: 1, ready: 2 };
        return [...blockages].sort((a, b) => {
            if (score[a.status] !== score[b.status]) return score[a.status] - score[b.status];
            return b.timestamp - a.timestamp;
        });
    }, [blockages]);

    // HANDLERS
    const handleAdd = async () => {
        if (!partNumber || !quantity || !userNote) {
            alert(t('fill_all_fields'));
            return;
        }
        setIsSubmitting(true);
        try {
            const newItem: ERPBlockage = {
                id: crypto.randomUUID(),
                partNumber,
                quantity,
                userNote,
                status: 'waiting',
                createdBy: currentUser,
                timestamp: Date.now()
            };
            const ref = doc(db, 'settings', 'erp_blockages');
            await setDoc(ref, { items: [newItem, ...blockages] }, { merge: true });

            // Vyčistenie formulára
            setPartNumber(''); setQuantity(''); setUserNote('');
        } catch (e) { console.error(e); }
        finally { setIsSubmitting(false); }
    };

    const updateStatus = async (id: string, updates: Partial<ERPBlockage>) => {
        try {
            const newList = blockages.map(item => item.id === id ? { ...item, ...updates } : item);
            await updateDoc(doc(db, 'settings', 'erp_blockages'), { items: newList });
        } catch (e) { console.error(e); }
    };

    const handleResolve = (id: string) => {
        updateStatus(id, { status: 'resolving', resolvedBy: currentUser });
    };

    const openFinishModal = (id: string) => {
        setFinishModal({ isOpen: true, id, note: '' });
    };

    const handleConfirmFinish = async () => {
        if (!finishModal.id || !finishModal.note.trim()) return;
        const item = blockages.find(b => b.id === finishModal.id);
        if (!item) return;

        const updates: Partial<ERPBlockage> = {
            status: 'ready',
            adminNote: finishModal.note,
            resolvedAt: Date.now(),
            resolvedBy: currentUser
        };

        await updateStatus(finishModal.id, updates);

        onAddNotification({
            partNumber: item.partNumber,
            reason: finishModal.note,
            reportedBy: currentUser,
            targetUser: item.createdBy,
            timestamp: Date.now()
        });

        setFinishModal({ isOpen: false, id: null, note: '' });
    };

    const handleDelete = (id: string) => {
        setConfirmModal({
            isOpen: true,
            title: t('erp_delete_confirm'),
            desc: language === 'sk' ? "Táto akcia je nevratná a záznam bude odstránený zo zoznamu." : "This action is irreversible.",
            type: 'danger',
            onConfirm: async () => {
                const newList = blockages.filter(b => b.id !== id);
                await updateDoc(doc(db, 'settings', 'erp_blockages'), { items: newList });
                setConfirmModal(p => ({ ...p, isOpen: false }));
            }
        });
    };

    const handleClearReady = () => {
        setConfirmModal({
            isOpen: true,
            title: t('erp_clear_confirm'),
            desc: language === 'sk' ? "Všetky záznamy v stave OPRAVENÉ budú natrvalo vymazané." : "All fixed records will be deleted.",
            type: 'danger',
            onConfirm: async () => {
                const newList = blockages.filter(b => b.status !== 'ready');
                await updateDoc(doc(db, 'settings', 'erp_blockages'), { items: newList });
                setConfirmModal(p => ({ ...p, isOpen: false }));
            }
        });
    };

    const handleExport = () => {
        if (typeof XLSX === 'undefined') return;
        const data = sortedList.map(b => ({
            "Dátum": new Date(b.timestamp).toLocaleDateString(),
            "Čas": new Date(b.timestamp).toLocaleTimeString(),
            "Diel": b.partNumber,
            "Množstvo": b.quantity,
            "Nahlásil": resolveName(b.createdBy),
            "Dôvod (User)": b.userNote,
            "Stav": b.status.toUpperCase(),
            "Riešiteľ": resolveName(b.resolvedBy),
            "Spätná väzba (Admin)": b.adminNote || ""
        }));
        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Chyby_Odvodu");
        XLSX.writeFile(wb, `Chyby_Odvodu_${new Date().toISOString().split('T')[0]}.xlsx`);
    };

    const getAgeingText = (ts: number) => {
        const diff = Math.floor((timer - ts) / 60000);
        return diff < 1 ? t('erp_ageing_now') : t('erp_ageing_min', { n: diff });
    };

    const isAdmin = currentUserRole === 'ADMIN';

    return (
        <div className="max-w-7xl mx-auto space-y-8 pb-24 animate-fade-in text-slate-200">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div className="flex items-center gap-5">
                    <div className="p-4 bg-orange-500/20 rounded-2xl border border-orange-500/30">
                        <Icons.Warning />
                    </div>
                    <div>
                        <h2 className="text-3xl font-black text-white uppercase tracking-tighter leading-none">{t('erp_report_title')}</h2>
                        <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-2">{t('erp_report_subtitle')}</p>
                    </div>
                </div>
                <div className="flex gap-3 w-full md:w-auto">
                    <button onClick={handleExport} className="flex-1 md:flex-none h-12 px-6 bg-teal-600/10 hover:bg-teal-600/20 text-teal-500 border border-teal-500/30 rounded-xl font-black uppercase text-[10px] tracking-widest transition-all flex items-center justify-center gap-2">
                        <Icons.Excel /> {t('erp_btn_excel')}
                    </button>
                    {isAdmin && (
                        <button onClick={handleClearReady} className="flex-1 md:flex-none h-12 px-6 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-500/30 rounded-xl font-black uppercase text-[10px] tracking-widest transition-all flex items-center justify-center gap-2">
                            <Icons.Trash /> {t('erp_btn_clear')}
                        </button>
                    )}
                </div>
            </div>

            <div className="bg-slate-900/60 border-2 border-slate-800 rounded-[2rem] p-8 shadow-2xl backdrop-blur-md relative overflow-hidden group">
                <div className="absolute top-0 right-0 w-64 h-64 bg-orange-500/5 rounded-full -mr-32 -mt-32 blur-[100px] pointer-events-none"></div>
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-end relative z-10">
                    <div className="space-y-4">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] ml-1">{t('part_number')}</label>
                            <PartNumberInput 
                                parts={parts.map(p => p.value)} 
                                value={partNumber} 
                                onPartSelect={(v) => setPartNumber(v || '')}
                                onInputChange={(v) => setPartNumber(v.toUpperCase())}
                                placeholder="33..."
                            />
                        </div>
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] ml-1">{t('quantity')}</label>
                            <input 
                                type="number" 
                                value={quantity} 
                                onChange={e => setQuantity(e.target.value)}
                                className="w-full h-14 bg-slate-950 border-2 border-slate-800 rounded-2xl px-6 text-white font-mono text-2xl focus:border-teal-500 outline-none transition-all" 
                                placeholder="0"
                            />
                        </div>
                    </div>
                    <div className="lg:col-span-2 space-y-4">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] ml-1">{t('erp_label_note')}</label>
                            <textarea 
                                value={userNote}
                                onChange={e => setUserNote(e.target.value)}
                                className="w-full h-[132px] bg-slate-950 border-2 border-slate-800 rounded-2xl px-6 py-4 text-white focus:border-teal-500 outline-none transition-all resize-none font-medium placeholder:text-slate-700"
                                placeholder={t('erp_placeholder_note')}
                            />
                        </div>
                    </div>
                    <div className="lg:col-span-3 pt-2">
                        <button 
                            onClick={handleAdd}
                            disabled={isSubmitting}
                            className="w-full h-16 bg-teal-600 hover:bg-teal-500 disabled:bg-slate-800 disabled:text-slate-600 text-white rounded-2xl font-black uppercase tracking-[0.2em] shadow-xl shadow-teal-900/20 transition-all active:scale-[0.98] border-b-4 border-teal-800 hover:border-teal-700 text-lg flex items-center justify-center gap-3"
                        >
                            {isSubmitting ? '...' : t('erp_submit_btn')}
                        </button>
                    </div>
                </div>
            </div>

            <div className="space-y-4">
                {sortedList.length > 0 ? (
                    sortedList.map((item) => {
                        const isWaiting = item.status === 'waiting';
                        const isResolving = item.status === 'resolving';
                        const isReady = item.status === 'ready';

                        const statusColors = isWaiting 
                            ? "border-red-500/20 bg-slate-900/40" 
                            : isResolving 
                                ? "border-orange-500/30 bg-slate-900/80 shadow-[0_0_40px_rgba(245,158,11,0.1)]" 
                                : "opacity-50 grayscale-[0.5] border-teal-500/10 bg-slate-900/20";

                        const badgeColors = isWaiting 
                            ? "bg-red-500/10 text-red-500 border-red-500/30 animate-pulse" 
                            : isResolving 
                                ? "bg-orange-500 text-white border-orange-400" 
                                : "bg-teal-500/10 text-teal-500 border-teal-500/30";

                        return (
                            <div key={item.id} className={`group relative flex flex-col md:flex-row items-stretch rounded-[2rem] border-2 transition-all duration-300 p-6 gap-6 ${statusColors}`}>
                                <div className="md:w-64 flex-shrink-0 flex flex-col justify-center">
                                    <h4 className="text-2xl font-black text-white font-mono tracking-tight break-all leading-tight">{item.partNumber}</h4>
                                    <div className="mt-3 bg-slate-950 rounded-xl p-3 border border-slate-800 flex items-center justify-between">
                                        <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Množstvo:</span>
                                        <span className="text-xl font-black text-teal-400 font-mono">{item.quantity}</span>
                                    </div>
                                </div>

                                <div className="flex-grow flex flex-col justify-center space-y-4">
                                    <div className="flex flex-wrap items-center gap-3">
                                        <span className={`px-4 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest border-2 ${badgeColors}`}>
                                            {t(`erp_status_${item.status}` as any)}
                                        </span>
                                        <span className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Nahlásil: <span className="text-slate-300 ml-1">{resolveName(item.createdBy)}</span></span>
                                        <span className="bg-rose-500/10 text-rose-500 border border-rose-500/20 px-3 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest">
                                            {getAgeingText(item.timestamp)}
                                        </span>
                                    </div>
                                    <div className="bg-slate-950/40 p-4 rounded-2xl border-l-4 border-slate-700 italic text-slate-300 text-sm leading-relaxed">
                                        "{item.userNote}"
                                    </div>
                                    {item.adminNote && (
                                        <div className="bg-teal-500/5 p-4 rounded-2xl border border-teal-500/20 text-teal-400 text-sm font-bold flex gap-3 items-start animate-fade-in">
                                            <span className="mt-0.5 text-lg">✅</span>
                                            <p>{item.adminNote}</p>
                                        </div>
                                    )}
                                </div>

                                <div className="md:w-48 flex-shrink-0 flex md:flex-col items-center justify-center gap-3">
                                    {isAdmin && (
                                        <>
                                            {!isReady && (
                                                <>
                                                    {isWaiting && (
                                                        <button 
                                                            onClick={() => handleResolve(item.id)}
                                                            className="w-full h-14 bg-orange-600 hover:bg-orange-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-orange-800 shadow-lg transition-all active:scale-95"
                                                        >
                                                            {t('erp_btn_resolve')}
                                                        </button>
                                                    )}
                                                    {isResolving && (
                                                        <button 
                                                            onClick={() => openFinishModal(item.id)}
                                                            className="w-full h-14 bg-teal-600 hover:bg-teal-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-teal-800 shadow-lg transition-all active:scale-95"
                                                        >
                                                            {t('erp_btn_finish')}
                                                        </button>
                                                    )}
                                                </>
                                            )}
                                            <button 
                                                onClick={() => handleDelete(item.id)}
                                                className="w-14 h-14 flex items-center justify-center rounded-2xl bg-slate-950 border-2 border-slate-800 text-slate-600 hover:text-red-500 hover:border-red-500/40 transition-all active:scale-95 shadow-lg"
                                            >
                                                <Icons.Trash />
                                            </button>
                                        </>
                                    )}
                                </div>
                            </div>
                        );
                    })
                ) : (
                    <div className="py-32 text-center bg-slate-900/20 rounded-[3rem] border-2 border-dashed border-slate-800">
                        <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-6 opacity-20"><Icons.Check /></div>
                        <p className="text-slate-600 font-black uppercase tracking-[0.3em] text-lg">{t('erp_empty_list')}</p>
                    </div>
                )}
            </div>

            {finishModal.isOpen && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in">
                    <div className="bg-slate-900 border-2 border-teal-500/50 rounded-[2.5rem] shadow-[0_0_100px_rgba(20,184,166,0.2)] w-full max-w-lg p-10 relative overflow-hidden" onClick={e => e.stopPropagation()}>
                        <div className="absolute top-0 right-0 w-32 h-32 bg-teal-500/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
                        <h3 className="text-3xl font-black text-white uppercase tracking-tighter mb-4">{t('erp_finish_modal_title')}</h3>
                        <p className="text-slate-500 text-sm font-bold uppercase tracking-widest mb-8 leading-relaxed">{t('erp_finish_modal_desc')}</p>

                        <textarea 
                            value={finishModal.note}
                            onChange={e => setFinishModal(p => ({ ...p, note: e.target.value }))}
                            className="w-full h-40 bg-slate-950 border-2 border-slate-800 rounded-2xl px-6 py-4 text-white focus:border-teal-500 outline-none transition-all resize-none mb-8 font-medium shadow-inner"
                            placeholder="NAPR. CHYBA OPRAVENÁ V EFACS..."
                            autoFocus
                        />

                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => setFinishModal({ isOpen: false, id: null, note: '' })} className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all">ZRUŠIŤ</button>
                            <button onClick={handleConfirmFinish} className="h-14 bg-teal-600 hover:bg-teal-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-teal-800 shadow-xl transition-all active:scale-95">POTVRDIŤ</button>
                        </div>
                    </div>
                </div>,
                document.body
            )}

            {confirmModal.isOpen && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in">
                    <div className="bg-slate-900 border-2 border-slate-800 rounded-[2.5rem] shadow-2xl w-full max-w-md p-10 text-center" onClick={e => e.stopPropagation()}>
                        <div className={`w-20 h-20 rounded-3xl mx-auto mb-8 flex items-center justify-center border-2 ${confirmModal.type === 'danger' ? 'bg-red-500/10 border-red-500/30 text-red-500' : 'bg-orange-500/10 border-orange-500/30 text-orange-500'}`}>
                            <Icons.Warning />
                        </div>
                        <h3 className="text-2xl font-black text-white uppercase tracking-tighter mb-4">{confirmModal.title}</h3>
                        <p className="text-slate-500 text-sm font-bold uppercase tracking-widest mb-10 leading-relaxed">{confirmModal.desc}</p>

                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => setConfirmModal(p => ({ ...p, isOpen: false }))} className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all">ZRUŠIŤ</button>
                            <button onClick={confirmModal.onConfirm} className={`h-14 rounded-2xl font-black uppercase text-xs tracking-widest text-white shadow-xl transition-all active:scale-95 border-b-4 ${confirmModal.type === 'danger' ? 'bg-red-600 border-red-800 hover:bg-red-500' : 'bg-orange-600 border-orange-800 hover:bg-orange-500'}`}>POTVRDIŤ</button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default ERPBlockageTab;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { useLanguage } from './LanguageContext';
import AppHeader from './AppHeader';
import TabNavigator from './TabNavigator';
import ProductionEntry from './tabs/ProductionEntry';
import TaskList from './tabs/TaskList';
import BOMScreen from './tabs/BOMScreen';
import MissingItemsTab from './tabs/MissingItemsTab';
import InventoryTab from './tabs/InventoryTab';
import LogisticsCenterTab from './tabs/LogisticsCenterTab';
import MapVisualizationTab from './tabs/MapVisualizationTab';
import TransactionLogTab from './tabs/TransactionLogTab';
import ERPBlockageTab from './tabs/ERPBlockageTab';
import AnalyticsTab from './tabs/Analytics/AnalyticsTab';
import SettingsTab from './settings/SettingsTab';
import PermissionsTab from './tabs/PermissionsTab';
import PartCatalogTab from './tabs/PartCatalogTab';
import { Task, PriorityLevel, DBItem, Role, SystemConfig, MapSector, MapObstacle, BOMComponent, PartRequest, BOMRequest, AdminNote, ERPBlockage } from '../types/appTypes';

// --- MAIN DASHBOARD COMPONENT ---
interface PartSearchScreenProps {
    tasks: Task[];
    draftTasks: Task[];
    users: any[];
    roles: Role[];
    workplaces: DBItem[];
    parts: { id: string; value: string; description?: string }[];
    missingReasons: DBItem[];
    logisticsOperations: DBItem[];
    mapSectors: MapSector[];
    mapObstacles: MapObstacle[];
    bomMap: Record<string, BOMComponent[]>;
    partRequests: PartRequest[];
    bomRequests: BOMRequest[];
    adminNotes: AdminNote[];
    erpBlockages: ERPBlockage[];
    systemConfig: SystemConfig;
    isBreakActive: boolean;

    currentUser: string;
    currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
    onLogout: () => void;

    // Task Actions
    onAddTask: (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, isLogistics?: boolean, noteOrPlate?: string, isProduction?: boolean, sourceSectorId?: string | null, targetSectorId?: string | null) => Promise<void>;
    onUpdateTask: (id: string, updates: Partial<Task>) => Promise<void>;
    onDeleteTask: (id: string) => Promise<void>;
    onToggleTask: (id: string, sectorId?: string) => Promise<void>;
    onSetInProgress: (id: string) => Promise<void>;
    onToggleBlock: (id: string) => Promise<void>;
    onToggleManualBlock: (id: string) => Promise<void>;
    onExhaustSearch: (id: string) => Promise<void>;
    onMarkAsIncorrect: (id: string) => Promise<void>;
    onAddNote: (id: string, note: string) => Promise<void>;
    onReleaseTask: (id: string) => Promise<void>;
    onStartAudit: (id: string) => Promise<void>;
    onFinishAudit: (id: string, result: 'found' | 'missing', note: string) => Promise<void>;
    onToggleMissing: (id: string, reason?: string) => Promise<void>;
    onDeleteMissingItem: (id: string) => Promise<void>;

    // User & Permission Management
    onUpdatePermission: (permissionName: string, roleName: string, hasPermission: boolean) => Promise<void>;
    onUpdateUserRole: (username: string, newRole: string) => Promise<void>;
    onAddRole: (name: string, parentId?: string, rank?: number) => Promise<void>;
    onDeleteRole: (id: string) => Promise<void>;

    // System Settings
    onUpdateSystemConfig: (config: Partial<SystemConfig>) => Promise<void>;
    onUpdateAdminKey: (oldKey: string, newKey: string) => Promise<void>;
    onToggleAdminLock: (val: boolean) => void;

    // Database Management
    onAddPart: (value: string, description?: string) => Promise<void>;
    onBatchAddParts: (vals: string[]) => Promise<void>;
    onDeletePart: (val: string) => Promise<void>;
    onDeleteAllParts: () => Promise<void>;

    onAddWorkplace: (val: string, time?: number, x?: number, y?: number) => Promise<void>;
    onUpdateWorkplace: (id: string, updates: Partial<DBItem>) => Promise<void>;
    onBatchAddWorkplaces: (vals: string[]) => Promise<void>;
    onDeleteWorkplace: (id: string) => Promise<void>;
    onDeleteAllWorkplaces: () => Promise<void>;

    onAddLogisticsOperation: (val: string, time?: number, dist?: number, x?: number, y?: number, defaultSource?: string, defaultTarget?: string) => Promise<void>;
    onUpdateLogisticsOperation: (id: string, updates: Partial<DBItem>) => Promise<void>;
    onDeleteLogisticsOperation: (id: string) => Promise<void>;
    onDeleteAllLogisticsOperations: () => Promise<void>;

    onAddMapSector: (name: string, x: number, y: number, color?: string) => Promise<void>;
    onUpdateMapSector: (id: string, updates: Partial<MapSector>) => Promise<void>;
    onDeleteMapSector: (id: string) => Promise<void>;

    onAddMapObstacle: (obs: Omit<MapObstacle, 'id'>) => Promise<void>;
    onDeleteMapObstacle: (id: string) => Promise<void>;

    onAddBOMItem: (parent: string, child: string, qty: number) => Promise<void>;
    onBatchAddBOMItems: (vals: string[]) => Promise<void>;
    onDeleteBOMItem: (parent: string, child: string) => Promise<void>;
    onDeleteAllBOMItems: () => Promise<void>;

    onAddMissingReason: (val: string) => Promise<void>;
    onDeleteMissingReason: (id: string) => Promise<void>;
    onAddBreakSchedule: (start: string, end: string) => Promise<void>;
    onDeleteBreakSchedule: (id: string) => Promise<void>;

    onAddAdminNote: (text: string, author: string) => Promise<void>;
    onDeleteAdminNote: (id: string) => Promise<void>;
    onClearAdminNotes: () => Promise<void>;

    // Maintenance & Data
    onDailyClosing: () => Promise<{ success: boolean; count: number }>;
    onWeeklyClosing: () => Promise<{ success: boolean; count: number; sanon: string }>;
    onPurgeOldTasks: () => Promise<number>;
    onExportTasksJSON: () => Promise<void>;
    onGetDocCount: () => Promise<number>;
    fetchSanons: () => Promise<any[]>;
    onRequestPart: (part: string) => Promise<boolean>;
    onRequestBOM: (parent: string) => Promise<boolean>;
    onVerifyAdminPassword: (password: string) => boolean;

    installPrompt: any;
    onInstallApp: () => void;
}

const PartSearchScreen: React.FC<PartSearchScreenProps> = (props) => {
    const { t, language, setLanguage } = useLanguage();
    const [activeTab, setActiveTab] = useState('entry');
    const [mode, setMode] = useState<'production' | 'logistics'>('production');
    const [isFullscreen, setIsFullscreen] = useState(false);

    // Form states for adding new tasks
    const [selectedPart, setSelectedPart] = useState<string | null>(null);
    const [selectedWorkplace, setSelectedWorkplace] = useState<string | null>(null);
    const [quantity, setQuantity] = useState('');
    const [quantityUnit, setQuantityUnit] = useState<'pcs' | 'boxes' | 'pallet'>('pcs');
    const [priority, setPriority] = useState<PriorityLevel>('NORMAL');
    const [logisticsRef, setLogisticsRef] = useState('');
    const [logisticsPlate, setLogisticsPlate] = useState('');
    const [logisticsOp, setLogisticsOp] = useState('');
    const [sourceSector, setSourceSector] = useState<string | null>(null);
    const [targetSector, setTargetSector] = useState<string | null>(null);

    // Fullscreen handling
    const toggleFullscreen = () => {
        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen().then(() => setIsFullscreen(true)).catch(err => console.error(err));
        } else {
            if (document.exitFullscreen) {
                document.exitFullscreen().then(() => setIsFullscreen(false)).catch(err => console.error(err));
            }
        }
    };

    // Permission check memoized for children
    const hasPermission = useCallback((permName: string) => {
        if (props.currentUserRole === 'ADMIN') return true;
        const roleObj = props.roles.find(r => r.name === props.currentUserRole);
        if (!roleObj) return false;
        return roleObj.permissions ? roleObj.permissions.includes(permName) : false;
    }, [props.roles, props.currentUserRole]);

    // Name resolution memoized for performance
    const resolveName = useCallback((username?: string | null) => {
        if (!username) return '-';
        const u = props.users.find(x => x.username === username);
        return (u?.nickname || username).toUpperCase();
    }, [props.users]);

    const resetEntry = () => {
        setSelectedPart(null);
        setSelectedWorkplace(null);
        setQuantity('');
        setQuantityUnit('pcs');
        setPriority('NORMAL');
        setLogisticsRef('');
        setLogisticsPlate('');
        setLogisticsOp('');
        setSourceSector(null);
        setTargetSector(null);
    };

    const handleAddTask = async () => {
        if (mode === 'production') {
            if (!selectedPart || !selectedWorkplace || !quantity) {
                alert(t('fill_all_fields'));
                return;
            }
            await props.onAddTask(
                selectedPart,
                selectedWorkplace,
                quantity,
                quantityUnit,
                priority,
                false,
                '',
                true
            );
            resetEntry();
        } else {
            if (!logisticsRef || !logisticsOp || !quantity) {
                alert(t('fill_all_fields'));
                return;
            }
            await props.onAddTask(
                logisticsRef,
                logisticsOp,
                quantity,
                'pallet',
                priority,
                true,
                logisticsPlate,
                false,
                sourceSector,
                targetSector
            );
            resetEntry();
        }
    };

    const counts = useMemo(() => ({
        tasks: props.tasks.filter(t => !t.isDone).length,
        pendingRequests: props.partRequests.length + props.bomRequests.length,
        erpBlockages: (props.erpBlockages || []).filter(b => b.status !== 'ready').length
    }), [props.tasks, props.partRequests, props.bomRequests, props.erpBlockages]);

    return (
        <div className="flex flex-col h-screen overflow-hidden bg-gray-900">
            {/* Top UI Bar */}
            <AppHeader 
                currentUser={props.currentUser}
                currentUserRole={props.currentUserRole}
                users={props.users}
                onLogout={props.onLogout}
                language={language as any}
                setLanguage={setLanguage as any}
                t={t}
                isFullscreen={isFullscreen}
                onToggleFullscreen={toggleFullscreen}
                installPrompt={props.installPrompt}
                onInstallApp={props.onInstallApp}
                hasPermission={hasPermission}
                resolveName={resolveName}
                isBreakActive={props.isBreakActive}
            />

            {/* Application Tab Selector */}
            <TabNavigator 
                activeTab={activeTab}
                setActiveTab={setActiveTab}
                hasPermission={hasPermission}
                t={t}
                counts={counts}
                currentUserRole={props.currentUserRole}
                systemConfig={props.systemConfig}
            />

            {/* Main Application Container */}
            <main className="flex-grow overflow-y-auto custom-scrollbar p-4 sm:p-6">
                <div className="max-w-7xl mx-auto h-full">
                    {activeTab === 'entry' && hasPermission('perm_tab_entry') && (
                        <ProductionEntry 
                            mode={mode}
                            setMode={setMode}
                            selectedPart={selectedPart}
                            setSelectedPart={setSelectedPart}
                            selectedWorkplace={selectedWorkplace}
                            setSelectedWorkplace={setSelectedWorkplace}
                            logisticsRef={logisticsRef}
                            setLogisticsRef={setLogisticsRef}
                            logisticsPlate={logisticsPlate}
                            setLogisticsPlate={setLogisticsPlate}
                            logisticsOp={logisticsOp}
                            setLogisticsOp={setLogisticsOp}
                            sourceSector={sourceSector}
                            setSourceSector={setSourceSector}
                            targetSector={targetSector}
                            setTargetSector={setTargetSector}
                            quantity={quantity}
                            setQuantity={setQuantity}
                            quantityUnit={quantityUnit}
                            setQuantityUnit={setQuantityUnit}
                            priority={priority}
                            setPriority={setPriority}
                            parts={props.parts}
                            workplaces={props.workplaces}
                            logisticsOperationsList={props.logisticsOperations}
                            mapSectors={props.mapSectors}
                            t={t}
                            language={language}
                            hasPermission={hasPermission}
                            handleAdd={handleAddTask}
                            onRequestPart={props.onRequestPart}
                        />
                    )}

                    {activeTab === 'tasks' && hasPermission('perm_tab_tasks') && (
                        <TaskList 
